-- Poems batch 46
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7fab1c4b-a86f-402a-bcef-60a1bfee11eb','春秋戰國門 再吟','周曇','唐','唐诗','tang','','[]','曲突徙薪不謂賢，焦頭爛額饗盤筵。',32,'全唐诗/poet.tang.40000.json','["曲突徙薪不謂賢，焦頭爛額饗盤筵。", "時人多是輕先見，不獨田家國亦然。"]'),
('a6aef6ae-4a7f-4ff4-810d-becc4b82e94c','春秋戰國門 田子奇','周曇','唐','唐诗','tang','','[]','少年爲吏慮非循，一騎奔追委使臣。',32,'全唐诗/poet.tang.40000.json','["少年爲吏慮非循，一騎奔追委使臣。", "使者不追何所對，車中緣見白頭人。"]'),
('67892ebe-6081-4b38-bee6-0dfcd6aacbcc','春秋戰國門 百里奚','周曇','唐','唐诗','tang','','[]','船驥由來是股肱，在虞虞滅在秦興。',32,'全唐诗/poet.tang.40000.json','["船驥由來是股肱，在虞虞滅在秦興。", "裁量何異刀將尺，秪繫用之能不能。"]'),
('4c7d52c1-dae4-45eb-8be9-934d44938dcf','春秋戰國門 孫叔敖','周曇','唐','唐诗','tang','','[]','童稚逢蛇歎不祥，慮悲來者爲埋藏。',32,'全唐诗/poet.tang.40000.json','["童稚逢蛇歎不祥，慮悲來者爲埋藏。", "是知陽報由陰施，天爵昭然契日彰。"]'),
('40da12d0-a1cd-44ac-a623-b411fce5ce14','春秋戰國門 魯仲連','周曇','唐','唐诗','tang','','[]','昔迸燒牛發戰機，夜奔驚火走燕師。',32,'全唐诗/poet.tang.40000.json','["昔迸燒牛發戰機，夜奔驚火走燕師。", "今來躍馬懷驕惰，十萬如無一撮時。"]'),
('f5d184fc-ff85-46a1-877d-95bca6ecab45','春秋戰國門 宋子罕','周曇','唐','唐诗','tang','','[]','子憐溫潤欲歸仁，吾貴堅廉是寶身。',32,'全唐诗/poet.tang.40000.json','["子憐溫潤欲歸仁，吾貴堅廉是寶身。", "自有不貪身內寶，玉人徒獻外來珍。"]'),
('8f98123a-ac95-479b-954a-a5e54de00cd8','春秋戰國門 宮之奇','周曇','唐','唐诗','tang','','[]','虞虢相依自保安，謀臣吞度不爲難。',32,'全唐诗/poet.tang.40000.json','["虞虢相依自保安，謀臣吞度不爲難。", "貪憐璧馬迷香餌，肯信之奇諭齒寒。"]'),
('f13ba69c-1ae2-4de7-af08-969eac466071','春秋戰國門 王孫滿','周曇','唐','唐诗','tang','','[]','九牧金鎔物像成，辭昏去亂祚休明。',32,'全唐诗/poet.tang.40000.json','["九牧金鎔物像成，辭昏去亂祚休明。", "興亡在德不在鼎，楚子何勞問重輕。"]'),
('996e3eff-4996-4514-b79e-1bef62c5c6bf','春秋戰國門 顏叔子','周曇','唐','唐诗','tang','','[]','夜雨鄰娃告屋傾，一宵從寄念悲驚。',32,'全唐诗/poet.tang.40000.json','["夜雨鄰娃告屋傾，一宵從寄念悲驚。", "誠知獨處從燒燭，君子行心要自明。"]'),
('6cc8da6d-32b2-4096-a7b1-807ca4933af6','春秋戰國門 張孟譚','周曇','唐','唐诗','tang','','[]','強兵四合國將危，賴有謀臣爲發揮。',32,'全唐诗/poet.tang.40000.json','["強兵四合國將危，賴有謀臣爲發揮。", "城內蒿銅誠自有，無謀誰解見玄機。"]'),
('feb3c844-8f44-437a-b62e-787cae2c9d83','春秋戰國門 公子無忌','周曇','唐','唐诗','tang','','[]','按劍臨籠震咄呼，鷂甘梟戮伏鳩辜。',32,'全唐诗/poet.tang.40000.json','["按劍臨籠震咄呼，鷂甘梟戮伏鳩辜。", "能憐鈍拙誅豪俊，憫弱摧強真丈夫。"]'),
('ceac5da1-4c73-4680-af3b-ab98521efb3d','春秋戰國門 再吟','周曇','唐','唐诗','tang','','[]','趙解重圍魏再昌，信陵賢德日馨芳。',32,'全唐诗/poet.tang.40000.json','["趙解重圍魏再昌，信陵賢德日馨芳。", "昏蒙愚主聽讒說，公子云亡國亦亡。"]'),
('6effc8aa-cf93-4275-b0ff-ed78d0d16e97','春秋戰國門 侯嬴朱亥','周曇','唐','唐诗','tang','','[]','屠肆監門一賤微，信陵交結國人非。',32,'全唐诗/poet.tang.40000.json','["屠肆監門一賤微，信陵交結國人非。", "當時不是二君計，匹馬那能解趙圍。"]'),
('8a764c6c-1b5f-4b5f-b482-82a41e3d54ae','春秋戰國門 再吟','周曇','唐','唐诗','tang','','[]','走敵存亡義有餘，全由雄勇與英謨。',32,'全唐诗/poet.tang.40000.json','["走敵存亡義有餘，全由雄勇與英謨。", "但如公子能交結，朱亥侯嬴何代無。"]'),
('ff5f4b8e-0bf8-4406-822f-aa4290b1865d','秦門 胡亥','周曇','唐','唐诗','tang','','[]','鹿馬何難辨是非，寧勞卜筮問安危。',32,'全唐诗/poet.tang.40000.json','["鹿馬何難辨是非，寧勞卜筮問安危。", "權臣爲亂多如此，亡國時君不自知。"]'),
('d7d0b1fa-40a6-4c47-828f-2b95dc96b390','秦門 再吟','周曇','唐','唐诗','tang','','[]','盜賊縱橫主惡聞，遂爲流矢犯君軒。',32,'全唐诗/poet.tang.40000.json','["盜賊縱橫主惡聞，遂爲流矢犯君軒。", "怪言何不早言者，若使早言還不存。"]'),
('9dff98bb-93f8-4d9e-bbfe-8765940c23ac','秦門 趙高','周曇','唐','唐诗','tang','','[]','趙高胡亥速天誅，率土興兵怨毒痡。',32,'全唐诗/poet.tang.41000.json','["趙高胡亥速天誅，率土興兵怨毒痡。", "豐沛見機羣小吏，功成兒戲亦何殊。"]'),
('2c0ba142-d45c-4582-81fd-ac705de1d568','秦門 陳涉','周曇','唐','唐诗','tang','','[]','秦法煩苛霸業隳，一夫攘臂萬夫隨。',32,'全唐诗/poet.tang.41000.json','["秦法煩苛霸業隳，一夫攘臂萬夫隨。", "王侯無種英雄志，燕雀喧喧安得知。"]'),
('65b8dd73-a4d4-4d99-b0cb-d7bf8631d352','秦門 項籍','周曇','唐','唐诗','tang','','[]','九垓垂定棄謀臣，一陣無功便殺身。',32,'全唐诗/poet.tang.41000.json','["九垓垂定棄謀臣，一陣無功便殺身。", "壯士誠知輕性命，不思辜負八千人。"]'),
('6e07b279-ca07-436d-b182-1ddaca610389','秦門 范增','周曇','唐','唐诗','tang','','[]','智士寧爲暗主謨，范公曾不讀兵書。',32,'全唐诗/poet.tang.41000.json','["智士寧爲暗主謨，范公曾不讀兵書。", "平生心力爲誰盡，一事無成空背疽。"]'),
('ad8b67f8-3a82-4b39-aa21-840e94cacd56','前漢門 高祖','周曇','唐','唐诗','tang','','[]','愛子從烹報主時，安知強啜不含悲。',32,'全唐诗/poet.tang.41000.json','["愛子從烹報主時，安知強啜不含悲。", "太公懸命臨刀几，忍取桮羹欲爲誰。"]'),
('af5af6f9-f7fa-4db7-ab6e-ef2de4b2011f','前漢門 再吟','周曇','唐','唐诗','tang','','[]','北伐匈奴事可悲，當時將相是其誰。',32,'全唐诗/poet.tang.41000.json','["北伐匈奴事可悲，當時將相是其誰。", "君臣束手平城裏，三十萬兵能忍飢。"]'),
('413c12bc-c194-4446-afd3-8c1cb124a62c','前漢門 周苛紀信','周曇','唐','唐诗','tang','','[]','爲主堅能不顧身，赴湯蹈火見忠臣。',32,'全唐诗/poet.tang.41000.json','["爲主堅能不顧身，赴湯蹈火見忠臣。", "後來邦國論心義，誰是君王出熱人。"]'),
('880aba7b-f205-479d-beb2-6f77ba39e551','前漢門 酇侯','周曇','唐','唐诗','tang','','[]','共怪酇侯第一功，咸稱得地合先封。',32,'全唐诗/poet.tang.41000.json','["共怪酇侯第一功，咸稱得地合先封。", "韓生不是蕭君薦，獵犬何人爲指蹤。"]'),
('8c5980e2-1d88-46e6-8148-3d292c6a65bb','前漢門 曲逆侯','周曇','唐','唐诗','tang','','[]','社肉分平未足奇，須觀大用展無私。',32,'全唐诗/poet.tang.41000.json','["社肉分平未足奇，須觀大用展無私。", "一朝如得宰天下，必使還如宰社時。"]'),
('9aaf4a05-ba5b-4148-b32c-737b5b94c82e','前漢門 薛公','周曇','唐','唐诗','tang','','[]','黥布稱兵孰敢當，薛公三計爲斟量。',32,'全唐诗/poet.tang.41000.json','["黥布稱兵孰敢當，薛公三計爲斟量。", "上中良策知非用，南取長沙是死鄉。"]'),
('f825b203-db49-44a7-bd14-bee7de0d4e1c','前漢門 條侯','周曇','唐','唐诗','tang','','[]','上將風戈賞罰明，矛鋋嚴閉亞夫營。',32,'全唐诗/poet.tang.41000.json','["上將風戈賞罰明，矛鋋嚴閉亞夫營。", "人君却稟將軍令，按轡垂鞭爲緩行。"]'),
('a91dade5-1aca-4bb0-98df-8090c45b768f','前漢門 平津侯','周曇','唐','唐诗','tang','','[]','儒素逢時得自媒，忽從徒步列公台。',32,'全唐诗/poet.tang.41000.json','["儒素逢時得自媒，忽從徒步列公台。", "北辰如不延吾輩，東閣何由逐汝開。"]'),
('0164e1ac-ac4f-4512-bb53-4e65eb61564a','前漢門 博陸侯','周曇','唐','唐诗','tang','','[]','棟梁徒自保堅貞，毀穴難防雀鼠爭。',32,'全唐诗/poet.tang.41000.json','["棟梁徒自保堅貞，毀穴難防雀鼠爭。", "不是主人知詐僞，如何柱石免欹傾。"]'),
('15b7d55e-48c1-426a-b2dc-87b1a05d1ac7','前漢門 夏賀良','周曇','唐','唐诗','tang','','[]','漢代中微亦再昌，忠臣憂國冀修禳。',32,'全唐诗/poet.tang.41000.json','["漢代中微亦再昌，忠臣憂國冀修禳。", "赤精符讖誠非妄，枉殺無辜夏賀良。"]'),
('4e231c37-d83f-4669-a9e5-6214a43d4249','前漢門 王莽','周曇','唐','唐诗','tang','','[]','權歸諸呂牝雞鳴，殷鑒昭然詎可輕。',32,'全唐诗/poet.tang.41000.json','["權歸諸呂牝雞鳴，殷鑒昭然詎可輕。", "新室不囚崇外戚，水中安敢寄生營。"]'),
('b7b54c62-7cd0-42a8-8f84-8405fa15b6ed','前漢門 再吟','周曇','唐','唐诗','tang','','[]','重賦嚴刑作禍胎，豈知由此亂離媒。',32,'全唐诗/poet.tang.41000.json','["重賦嚴刑作禍胎，豈知由此亂離媒。", "家傳揖讓亦難濟，況是身從傾篡來。"]'),
('03a46ea5-6492-4dc7-abe9-4c044acf0ac9','前漢門 又吟','周曇','唐','唐诗','tang','','[]','銅馬朱眉滿四方，總緣居攝亂天常。',32,'全唐诗/poet.tang.41000.json','["銅馬朱眉滿四方，總緣居攝亂天常。", "因君多少布衣士，不是公卿即帝王。"]'),
('03a33afc-b292-4524-9619-d95b7b329025','前漢門 毛延壽','周曇','唐','唐诗','tang','','[]','不拔金釵賂漢臣，徒嗟玉豔委胡塵。',32,'全唐诗/poet.tang.41000.json','["不拔金釵賂漢臣，徒嗟玉豔委胡塵。", "能知貨賄移妍醜，豈獨丹青畫美人。"]'),
('72677656-d14f-4d52-a423-fac723136091','前漢門 劉聖公','周曇','唐','唐诗','tang','','[]','不納良謀劉縯言，胡爲銜璧向崇宣。',32,'全唐诗/poet.tang.41000.json','["不納良謀劉縯言，胡爲銜璧向崇宣。", "傷哉亂帝途窮處，何必當時譖福先。"]'),
('0ba83716-169a-472a-a881-02c3d12517a9','前漢門 樊崇徐宣','周曇','唐','唐诗','tang','','[]','庸中佼佼鐵錚錚，百萬長驅入帝京。',32,'全唐诗/poet.tang.41000.json','["庸中佼佼鐵錚錚，百萬長驅入帝京。", "首事縱隳三善在，歸仁何慮不全生。"]'),
('2f6e9cc7-21c7-4504-b6d8-98ae44dcb504','前漢門 僭號公孫述','周曇','唐','唐诗','tang','','[]','劍蜀金湯孰敢爭，子陽才業匪雄英。',32,'全唐诗/poet.tang.41000.json','["劍蜀金湯孰敢爭，子陽才業匪雄英。", "方知在德不在險，危棧何曾阻漢兵。"]'),
('3cc57204-d127-4542-a33c-171f73fc204e','後漢門 光武','周曇','唐','唐诗','tang','','[]','成敗非儒孰可量，儒生何指指蕭王。',32,'全唐诗/poet.tang.41000.json','["成敗非儒孰可量，儒生何指指蕭王。", "蕭王得衆能寬裕，吳漢歸來帝業昌。"]'),
('0b876cb4-6288-483b-b408-272db587fd2f','後漢門 明帝','周曇','唐','唐诗','tang','','[]','朝臣咸佞孰知非，張佚公忠語獨奇。',32,'全唐诗/poet.tang.41000.json','["朝臣咸佞孰知非，張佚公忠語獨奇。", "博士一言除太傅，謚爲明帝信其宜。"]'),
('eb9d95ae-57fe-4902-b671-0b64faf1d0a5','後漢門 桓帝','周曇','唐','唐诗','tang','','[]','能嫌跋扈斬梁王，寧便榮枯信段張。',32,'全唐诗/poet.tang.41000.json','["能嫌跋扈斬梁王，寧便榮枯信段張。", "襄楷忠言誰佞惑，忍教奸禍起蕭牆。"]'),
('0a4c1380-6558-4297-b81e-2e50221ee85a','後漢門 靈帝','周曇','唐','唐诗','tang','','[]','榜懸金價鬻官榮，千萬爲公五百卿。',32,'全唐诗/poet.tang.41000.json','["榜懸金價鬻官榮，千萬爲公五百卿。", "公瑾孔明窮退者，安知高臥遇雄英。"]'),
('9c4e6a5e-2d0a-4ea1-b633-0eb9f57a0b43','後漢門 廢帝','周曇','唐','唐诗','tang','','[]','亂兵如蝟走王師，社稷顛危孰爲持。',32,'全唐诗/poet.tang.41000.json','["亂兵如蝟走王師，社稷顛危孰爲持。", "夜逐螢光尋道路，漢家天子步歸時。"]'),
('e3c84bcb-bc36-4b2e-8430-6e9de0542b09','後漢門 獻帝','周曇','唐','唐诗','tang','','[]','秪爲曹侯數貴人，普天黔首盡黃巾。',32,'全唐诗/poet.tang.41000.json','["秪爲曹侯數貴人，普天黔首盡黃巾。", "漢靈早聽侍中諫，安得獻生稱不辰。"]'),
('51fa9503-9864-4c86-ad32-d94dd24993c9','後漢門 再吟','周曇','唐','唐诗','tang','','[]','咸怨刑科有黨偏，耕夫無不事戎旃。',32,'全唐诗/poet.tang.41000.json','["咸怨刑科有黨偏，耕夫無不事戎旃。", "是時老幼飢號處，一斛黃禾五百千。"]'),
('67d6f5e9-340a-4ae2-b55e-a77bb79ad22a','後漢門 子密','周曇','唐','唐诗','tang','','[]','子密封侯豈所宜，能高德義必無爲。',32,'全唐诗/poet.tang.41000.json','["子密封侯豈所宜，能高德義必無爲。", "當時若縛還彭氏，率土何憂不自歸。"]'),
('04e66dc8-8e11-4f44-936f-e9a39e4eeb4f','後漢門 羊續','周曇','唐','唐诗','tang','','[]','魚懸潔白振清風，祿散親賓歲自窮。',32,'全唐诗/poet.tang.41000.json','["魚懸潔白振清風，祿散親賓歲自窮。", "單席寒廳慙使者，葛衣何以至三公。"]'),
('3d64bde6-c523-4e63-accf-97e6f911fb69','後漢門 楊震','周曇','唐','唐诗','tang','','[]','爲國推賢匪惠私，十金爲報遽相危。',32,'全唐诗/poet.tang.41000.json','["爲國推賢匪惠私，十金爲報遽相危。", "無言暗室何人見，咫尺斯須已四知。"]'),
