('b1a84f73-0d63-44ca-9c67-d6b48772b4cf','隋門 隋文帝','周曇','唐','唐诗','tang','','[]','孤兒寡婦忍同欺，輔政剛教篡奪爲。',32,'全唐诗/poet.tang.41000.json','["孤兒寡婦忍同欺，輔政剛教篡奪爲。", "矯詔必能疎昉譯，直臣誠合重顏儀。"]'),
('8e500a26-ad42-49d2-80bb-a05909d0109e','隋門 獨孤后','周曇','唐','唐诗','tang','','[]','腹生奚強有親疎，憐者爲賢棄者愚。',32,'全唐诗/poet.tang.41000.json','["腹生奚強有親疎，憐者爲賢棄者愚。", "儲貳不遭讒搆死，隋亡寧便在江都。"]'),
('9e5c260c-f9a7-441d-bfd2-bba363d6ff40','隋門 煬帝','周曇','唐','唐诗','tang','','[]','拒諫勞兵作禍基，窮奢極武向戎夷。',32,'全唐诗/poet.tang.41000.json','["拒諫勞兵作禍基，窮奢極武向戎夷。", "兆人疲弊不堪命，天下嗷嗷新主資。"]'),
('46c85206-3bff-42fb-93d5-55f42d39b087','隋門 賀若弼','周曇','唐','唐诗','tang','','[]','破敵江軍意氣豪，請除傾國斬妖嬈。',32,'全唐诗/poet.tang.41000.json','["破敵江軍意氣豪，請除傾國斬妖嬈。", "紅綃忍染嬌春雪，瞪目看行切玉刀。"]'),
('b4d1014e-3925-486d-be40-13c9d856b23b','上清辭五首 一','李九齡','唐','唐诗','tang','','[]','入海浮生汗漫秋，紫皇高宴五雲樓。',32,'全唐诗/poet.tang.41000.json','["入海浮生汗漫秋，紫皇高宴五雲樓。", "霓裳曲罷天風起，吹散仙香滿十洲。"]'),
('e50bf1d4-8483-420d-85ab-424ee4e66a3d','上清辭五首 二','李九齡','唐','唐诗','tang','','[]','樓鏁彤霞地絕塵，碧桃花發九天春。',32,'全唐诗/poet.tang.41000.json','["樓鏁彤霞地絕塵，碧桃花發九天春。", "東皇近日慵遊宴，閑煞瑤池五色麟。"]'),
('88b706c5-b2a6-4aa0-8401-b89746c1cb9b','上清辭五首 三','李九齡','唐','唐诗','tang','','[]','上清仙路有丹梯，影響行人到即迷。',32,'全唐诗/poet.tang.41000.json','["上清仙路有丹梯，影響行人到即迷。", "不會無端箇漁父，阿誰教入武陵溪。"]'),
('7d0cabc8-868a-4b6e-a6ee-cb40c0980127','上清辭五首 四','李九齡','唐','唐诗','tang','','[]','本來方朔是真仙，偶別丹臺未得還。',32,'全唐诗/poet.tang.41000.json','["本來方朔是真仙，偶別丹臺未得還。", "何事玉皇消息晚，忍教顦顇向人間。"]'),
('3a17717a-0765-433b-bb1b-019bd24f830d','上清辭五首 五','李九齡','唐','唐诗','tang','','[]','新拜天官上玉都，紫皇親授五靈符。',32,'全唐诗/poet.tang.41000.json','["新拜天官上玉都，紫皇親授五靈符。", "羣仙箇箇來相問，人世風光似此無。"]'),
('d7b39c8f-2511-4f64-a627-f584111e48fa','讀三國志','李九齡','唐','唐诗','tang','','[]','有國由來在得賢，莫言興廢是循環。',32,'全唐诗/poet.tang.41000.json','["有國由來在得賢，莫言興廢是循環。", "武侯星落周瑜死，平蜀降吳似等閑。"]'),
('3f004730-8306-48e8-8842-40088ebfce1f','山舍南溪小桃花','李九齡','唐','唐诗','tang','','[]','一樹繁英奪眼紅，開時先合占東風。',32,'全唐诗/poet.tang.41000.json','["一樹繁英奪眼紅，開時先合占東風。", "可憐地僻無人賞，拋擲深山亂木中。"]'),
('5a7968d7-25df-4105-9be3-bb08960f25f4','春行遇雨','李九齡','唐','唐诗','tang','','[]','夾路輕風撼柳條，雨侵春態動無憀。',32,'全唐诗/poet.tang.41000.json','["夾路輕風撼柳條，雨侵春態動無憀。", "採香陌上誰家女，濕損釵頭翡翠翹。"]'),
('d6a8c837-3d80-460a-8463-c848e64419bc','登樓寄遠','李九齡','唐','唐诗','tang','','[]','滿城春色花如雪，極目煙光月似鉤。',32,'全唐诗/poet.tang.41000.json','["滿城春色花如雪，極目煙光月似鉤。", "總是動人鄉思處，更堪容易上高樓。"]'),
('dca00847-6a53-410e-8dbc-417173c2ca92','望思臺','李九齡','唐','唐诗','tang','','[]','漢武年高慢帝圖，任人曾不問賢愚。',32,'全唐诗/poet.tang.41000.json','["漢武年高慢帝圖，任人曾不問賢愚。", "直饒四老依前出，消得江充寵佞無。"]'),
('f409e465-e575-4f57-b1e2-46b24d725b56','山舍偶題','李九齡','唐','唐诗','tang','','[]','門掩松蘿一逕深，偶攜藜杖出前林。',32,'全唐诗/poet.tang.41000.json','["門掩松蘿一逕深，偶攜藜杖出前林。", "誰知盡日看山坐，萬古興亡總在心。"]'),
('bfadc7fe-c0bd-4925-ab66-eac8dcfac5d1','荆溪夜泊','李九齡','唐','唐诗','tang','','[]','點點漁燈照浪清，水煙疎碧月朧明。',32,'全唐诗/poet.tang.41000.json','["點點漁燈照浪清，水煙疎碧月朧明。", "小灘驚起鴛鴦處，一隻採蓮船過聲。"]'),
('cf93bd56-d49d-4dd3-b450-8a3927987459','旅舍臥病','李九齡','唐','唐诗','tang','','[]','家隔西秦無遠信，身隨東洛度流年。',32,'全唐诗/poet.tang.41000.json','["家隔西秦無遠信，身隨東洛度流年。", "病來旅館誰相問，牢落閑庭一樹蟬。"]'),
('6de797c3-85a3-464b-9026-94942a22743f','登昭福寺樓','李九齡','唐','唐诗','tang','','[]','旅懷秋興正無涯，獨倚危樓四望賒。',32,'全唐诗/poet.tang.41000.json','["旅懷秋興正無涯，獨倚危樓四望賒。", "谷變陵遷何處問，滿川空有舊煙霞。"]'),
('cffc9810-afe1-425a-80e1-b3de027497d5','代邊將','李九齡','唐','唐诗','tang','','[]','雪凍陰河半夜風，戰回狂虜血漂紅。',32,'全唐诗/poet.tang.41000.json','["雪凍陰河半夜風，戰回狂虜血漂紅。", "據鞍遙指長安路，須刻麟臺第一功。"]'),
('61d818be-d596-4433-88cf-93cdddd1343a','夜與張舒話別','李九齡','唐','唐诗','tang','','[]','愁聽南樓角又吹，曉雞啼後更分離。',32,'全唐诗/poet.tang.41000.json','["愁聽南樓角又吹，曉雞啼後更分離。", "如何銷得淒涼思，更勸燈前酒一巵。"]'),
('59cc85c8-b661-4084-9e3c-57b2083226df','寒梅詞','李九齡','唐','唐诗','tang','','[]','霜梅先拆嶺頭枝，萬卉千花凍不知。',32,'全唐诗/poet.tang.41000.json','["霜梅先拆嶺頭枝，萬卉千花凍不知。", "留得和羹滋味在，任他風雪苦相欺。"]'),
('2fe6b99a-efd9-4ce1-9a77-40dfbe2bbe1b','題靈泉寺','李九齡','唐','唐诗','tang','','[]','入谷先生一陣香，異花奇木簇禪堂。',32,'全唐诗/poet.tang.41000.json','["入谷先生一陣香，異花奇木簇禪堂。", "可憐門外高低路，萬轂千蹄日日忙。"]'),
('2bfd7eaa-a4a8-4664-825f-8c75045f4775','宿張正字別業','李九齡','唐','唐诗','tang','','[]','茅屋蕭寥煙暗後，松窗寂歷月明初。',32,'全唐诗/poet.tang.41000.json','["茅屋蕭寥煙暗後，松窗寂歷月明初。", "此時誰念孤吟客，唯有黃公一帙書。"]'),
('d54eb837-eed8-48a0-b2ba-4bf13ddad195','鶴','李九齡','唐','唐诗','tang','','[]','天上瑤池覆五雲，玉麟金鳳好爲羣。',32,'全唐诗/poet.tang.41000.json','["天上瑤池覆五雲，玉麟金鳳好爲羣。", "不須更飲人間水，直是清流也汗君。"]'),
('63f48c92-e53c-4aec-8af7-f1ce24ad351c','過相思谷','李九齡','唐','唐诗','tang','','[]','悠悠信馬春山曲，芳草和煙鋪嫩綠。',32,'全唐诗/poet.tang.41000.json','["悠悠信馬春山曲，芳草和煙鋪嫩綠。", "正被離愁著莫人，那堪更過相思谷。"]'),
('5af7e395-f69d-42e4-bed5-37e2604388fb','寫莊子','李九齡','唐','唐诗','tang','','[]','聖澤安排當散地，賢侯優貸借新居。',32,'全唐诗/poet.tang.41000.json','["聖澤安排當散地，賢侯優貸借新居。", "閑中亦有閑生計，寫得南華一部書。"]'),
('78496197-daf3-40b2-a468-a50f1acc6751','山中寄友人','李九齡','唐','唐诗','tang','','[]','亂雲堆裏結茅廬，已共紅塵跡漸疎。',32,'全唐诗/poet.tang.41000.json','["亂雲堆裏結茅廬，已共紅塵跡漸疎。", "莫問野人生計事，窗前流水枕前書。"]'),
('aaf798a7-fea9-4bcc-8ee5-697224d2bcd1','津亭','胡宿','唐','唐诗','tang','','[]','津亭欲闋戒棠舟，五兩風來不暫留。',64,'全唐诗/poet.tang.41000.json','["津亭欲闋戒棠舟，五兩風來不暫留。", "西北浮雲連魏闕，東南初日滿秦樓。", "層城渺渺人傷別，芳草萋萋客倦遊。", "平樂舊歡收不得，更憑飛夢到瀛洲。"]'),
('9c9a3e8f-f293-4757-bf40-5b13cd4b3d47','古別','胡宿','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','長道何年祖軷休，風帆不斷岳陽樓。',66,'全唐诗/poet.tang.41000.json','["長道何年祖軷休，風帆不斷岳陽樓。", "佳人挾瑟漳河曉，壯士悲歌易水秋。", "九帳[青]油徒自負，百壺芳醑豈消憂。", "至今長樂坡前水，不啻秦人怨隴頭。"]'),
('e703ceb8-ba4c-47c8-810d-cb95f3c5dae9','塞上','胡宿','唐','唐诗','tang','','[]','漢家神箭定天山，煙火相望萬里間。',64,'全唐诗/poet.tang.41000.json','["漢家神箭定天山，煙火相望萬里間。", "契利請盟金匕酒，將軍歸臥玉門關。", "雲沈老上妖氛斷，雪照回中探騎閑。", "五餌已行王道勝，絕無刁斗至闐顏。"]'),
('3e59dfb2-ade3-4f63-9fc6-66a1e34534da','寄昭潭王中立','胡宿','唐','唐诗','tang','','[]','高弦一弄武陵深，六幕天空萬里心。',64,'全唐诗/poet.tang.41000.json','["高弦一弄武陵深，六幕天空萬里心。", "吳苑歌驪成久別，楚峰回雁好歸音。", "十千美酒花期隔，三百枯棋弈思沈。", "莫上孤城頻送目，浮雲西北是家林。"]'),
('67916e82-f4c6-4438-addb-1ad5a77160ba','雪','胡宿','唐','唐诗','tang','','[]','屏翳驅雲結夜陰，素花飄墜惡氛沈。',64,'全唐诗/poet.tang.41000.json','["屏翳驅雲結夜陰，素花飄墜惡氛沈。", "色欺曹國麻衣淺，寒入荆王翠被深。", "天上明河銀作水，海中仙樹玉爲林。", "日高獨擁鸘裘臥，誰乞長安取酒金。"]'),
('56afb14b-8657-4692-9e0e-980ccc638f4c','沖虛觀','胡宿','唐','唐诗','tang','','[]','五粒青松護翠苔，石門岑寂斷纖埃。',64,'全唐诗/poet.tang.41000.json','["五粒青松護翠苔，石門岑寂斷纖埃。", "水浮花片知仙路，風遞鸞聲認嘯臺。", "桐井曉寒千乳歛，茗園春嫩一旗開。", "馳煙未勒山亭字，可是英靈許再來。"]'),
('389a537d-3e98-47a9-b31d-91531df9c0c2','淮南發運趙邢州被詔歸闕','胡宿','唐','唐诗','tang','','[]','天臺封詔紫泥馨，馬首前瞻北斗城。',64,'全唐诗/poet.tang.41000.json','["天臺封詔紫泥馨，馬首前瞻北斗城。", "人在函關先望氣，帝於京兆最知名。", "一區東第趨晨近，數刻西廂接晝榮。", "正是兩宮裁化日，百金雙璧拜虞卿。"]'),
('01afb5a7-318f-455b-bf37-d6d6c7ff86c2','天街曉望','胡宿','唐','唐诗','tang','','[]','長樂才聞一叩鐘，百官初謁未央宮。',64,'全唐诗/poet.tang.41000.json','["長樂才聞一叩鐘，百官初謁未央宮。", "金波穆穆沙隄月，玉樹琤琤上苑風。", "香重椒蘭橫結霧，氣寒龍虎遠浮空。", "嗟余索米無人問，行避霜臺御史驄。"]'),
('d40576b3-4499-41f3-a5bd-5961dab87947','淮南王','胡宿','唐','唐诗','tang','','[]','貪鑄金錢盜寫符，何曾七國戒前車。',64,'全唐诗/poet.tang.41000.json','["貪鑄金錢盜寫符，何曾七國戒前車。", "長生不待爐中藥，鴻寶誰收篋裏書。", "碧井牀空天影在，小山人去桂叢疎。", "雲中雞犬無消息，麥秀漸漸徧故墟。"]'),
('4d1b305d-a24e-4793-9878-48495be840f0','趙宗道歸輦下','胡宿','唐','唐诗','tang','','[]','沿牒相逢楚水湄，竹林文酒此攀嵇。',66,'全唐诗/poet.tang.41000.json','["沿牒相逢楚水湄，竹林文酒此攀嵇。", "半氈未暖還傷別，一臂初交又解攜。", "江浦嘔啞風送樐，河橋勃窣柳垂隄。", "明年四月秦關到，洗眼揚州看馬[蹄]。"]'),
('25db79dc-94ef-489c-a2c8-bc7b1d683f1f','憶薦福寺牡丹','胡宿','唐','唐诗','tang','','[]','十日春風隔翠岑，秪應繁朵自成陰。',64,'全唐诗/poet.tang.41000.json','["十日春風隔翠岑，秪應繁朵自成陰。", "樽前可要人頹玉，樹底遙知地側金。", "花界三千春渺渺，銅槃十二夜沈沈。", "雕槃分篸何由得，空作西州擁鼻吟。"]'),
('1ba4506a-3e07-4f05-8b56-ad3833954ba3','次韻和朱況雨中之什','胡宿','唐','唐诗','tang','','[]','蒼野迷雲黯不歸，遠風吹雨入巖扉。',64,'全唐诗/poet.tang.41000.json','["蒼野迷雲黯不歸，遠風吹雨入巖扉。", "石牀潤極琴絲緩，水閣寒多酒力微。", "夕夢將成還滴滴，春心欲斷正霏霏。", "憂花惜月長如此，爭得東陽病骨肥。"]'),
('4a6005f1-54ef-42f5-9fd7-859d7ae6b45d','感舊','胡宿','唐','唐诗','tang','','[]','千里青雲未致身，馬蹄空踏幾年塵。',64,'全唐诗/poet.tang.41000.json','["千里青雲未致身，馬蹄空踏幾年塵。", "曾迷玉洞花光老，欲過金城柳眼新。", "粉壁已沈題鳳字，酒壚猶記姓黃人。", "塢中橫笛偏多感，一涕闌干白角巾。"]'),
('0dc1d189-6f69-4723-9aae-a49cbb1575f4','城南','胡宿','唐','唐诗','tang','','[]','昨夜輕陰結夕霏，城南十里有香泥。',64,'全唐诗/poet.tang.41000.json','["昨夜輕陰結夕霏，城南十里有香泥。", "初聞山鳥驚新哢，遙見林花識舊蹊。", "蕩槳遠從芳草渡，墊巾還傍綠楊隄。", "羅敷正苦桑蠶事，惆悵南來五馬蹄。"]'),
('3972d5f3-df6a-4659-882a-0c525e7ba3fc','早夏','胡宿','唐','唐诗','tang','','[]','井轄投多思不禁，密垂珠箔晝沈沈。',64,'全唐诗/poet.tang.41000.json','["井轄投多思不禁，密垂珠箔晝沈沈。", "睡驚燕語頻移枕，病起蛛絲半在琴。", "雨徑亂花埋宿豔，月軒修竹轉涼陰。", "一春酒費知多少，探盡囊中換賦金。"]'),
('b1252e7e-437a-4da5-b233-ec08facccce4','侯家','胡宿','唐','唐诗','tang','','[]','洞戶春遲漏箭長，短轅初返雒陽傍。',64,'全唐诗/poet.tang.41000.json','["洞戶春遲漏箭長，短轅初返雒陽傍。", "綵雲按曲青岑醴，沈水薰衣白璧堂。", "前檻蘭苕依玉樹，後園桐葉護銀牀。", "宴殘紅燭長庚爛，還促朝珂謁未央。"]'),
('bbd42ad5-932b-4b0b-99e2-a74c27a5bdb3','函谷關','胡宿','唐','唐诗','tang','','[]','天開函谷壯關中，萬古驚塵向此空。',64,'全唐诗/poet.tang.41000.json','["天開函谷壯關中，萬古驚塵向此空。", "望氣竟能知老子，棄繻何不識終童。", "慢持白馬先生論，未抵鳴雞下客功。", "符命已歸如掌地，一丸曾誤隗王東。"]'),
('45bc85b7-5ac3-4313-b031-00742be47065','殘花','胡宿','唐','唐诗','tang','','[]','雨壓殘紅一夜凋，曉來簾外正飄搖。',64,'全唐诗/poet.tang.41000.json','["雨壓殘紅一夜凋，曉來簾外正飄搖。", "數枝翠葉空相對，萬片香魂不可招。", "長樂夢回春寂寂，武陵人去水迢迢。", "愁將玉笛傳遺恨，苦被芳風透綺寮。"]'),
('25066ec7-1250-4395-b4a5-429c0294da0d','次韻徐爽見寄','胡宿','唐','唐诗','tang','','[]','五兩青絲帝渥深，平時可敢嘆英沈。',64,'全唐诗/poet.tang.41000.json','["五兩青絲帝渥深，平時可敢嘆英沈。", "侏儒自是長三尺，澼絖都來直數金。", "寂寞死灰人喪偶，婆娑生意樹交陰。", "年來想見瓊枝色，久夢蘧蘧到竹林。"]'),
('d5ebf3d8-cd1c-4527-8c41-d157fe15b680','華清宮','杜常','唐','唐诗','tang','','[]','行盡江南數十程，曉星殘月入華清。',32,'全唐诗/poet.tang.41000.json','["行盡江南數十程，曉星殘月入華清。", "朝元閣上西風急，都入長楊作雨聲。"]'),
('bf02202a-3ff7-4f75-b18e-ab5c6f7dc47f','華清宮','杜常','唐','唐诗','tang','','[]','一別家山十六程，曉来和月到華清。',32,'全唐诗/poet.tang.41000.json','["一別家山十六程，曉来和月到華清。", "朝元閣上西風急，都入長楊作雨聲。"]'),
('4910aa66-39ef-46b3-9202-fb0202d488ac','題文川村居','滕白','唐','唐诗','tang','','[]','種茶巖接紅霞塢，灌稻泉生白石根。',32,'全唐诗/poet.tang.41000.json','["種茶巖接紅霞塢，灌稻泉生白石根。", "皤腹老翁眉似雪，海棠花下戲兒孫。"]'),
('4b7f1b46-e431-4fac-bf59-90fdb6d9301b','燕','滕白','唐','唐诗','tang','','[]','短羽新來別海陽，真珠高卷語雕梁。',32,'全唐诗/poet.tang.41000.json','["短羽新來別海陽，真珠高卷語雕梁。", "佳人未必全聽爾，正把金針繡鳳凰。"]'),
('0f5ae17d-840e-4036-a305-7c06d4f417fe','題嚴君觀','王嵒','唐','唐诗','tang','','[]','寒雲古木罩星臺，凡骨仙蹤信可哀。',32,'全唐诗/poet.tang.41000.json','["寒雲古木罩星臺，凡骨仙蹤信可哀。", "二十年前曾此到，一千年內未歸來。"]'),
('9143dc9a-a4ee-447e-b5c8-d060fb2c9879','山中有所思','王嵒','唐','唐诗','tang','','[]','零零夜雨漬愁根，觸物傷離好斷魂。',32,'全唐诗/poet.tang.41000.json','["零零夜雨漬愁根，觸物傷離好斷魂。", "莫怪杜鵑飛去盡，紫微花裏有啼猨。"]'),
('c447be74-4d94-46c0-bc7f-61e8a5b73409','燕','王嵒','唐','唐诗','tang','','[]','一巢功績破春光，絮落花殘兩翅狂。',32,'全唐诗/poet.tang.41000.json','["一巢功績破春光，絮落花殘兩翅狂。", "月樹風枝不棲去，強來言語泥雕梁。"]'),
('6b13f0a3-0100-4661-abd6-6ae42d55d972','貧女','王嵒','唐','唐诗','tang','','[]','難把菱花照素顏，試臨春水插花看。',32,'全唐诗/poet.tang.41000.json','["難把菱花照素顏，試臨春水插花看。", "木蘭船上遊春子，笑指荆釵下遠灘。"]'),
('4f414c01-c548-442b-b737-5bf2c4bebd8b','杪春寄友人','王嵒','唐','唐诗','tang','','[]','何處相逢萬事忙，卓家樓上百淘香。',32,'全唐诗/poet.tang.41000.json','["何處相逢萬事忙，卓家樓上百淘香。", "明朝漸近山僧寺，更爲殘花醉一場。"]'),
('0d93c8f0-0a34-4e21-b4b5-e34e7c244019','回舊山','王嵒','唐','唐诗','tang','','[]','庾家樓上謝家池，處處風煙少舊知。',32,'全唐诗/poet.tang.41000.json','["庾家樓上謝家池，處處風煙少舊知。", "明日落花誰共醉，野溪猨鳥恨歸遲。"]'),
('3f0b925d-4d38-486a-b708-5e6f6d8e2962','感巫州薺菜','高力士','唐','唐诗','tang','','[]','兩京作觔賣，五谿無人采。',24,'全唐诗/poet.tang.41000.json','["兩京作觔賣，五谿無人采。", "夷夏雖有殊，氣味都不改。"]'),
('cf729a6e-e368-4a65-affb-8bd646385303','句','高力士','唐','唐诗','tang','','[]','煙燻眼落膜，瘴染面朱虞。',12,'全唐诗/poet.tang.41000.json','["煙燻眼落膜，瘴染面朱虞。"]'),
('31876e9d-837c-4b5b-9135-e00fd13ab34f','使至灊山','王越賓','唐','唐诗','tang','','[]','碧塢煙霞晝未開，游人到處盡裴回。',32,'全唐诗/poet.tang.41000.json','["碧塢煙霞晝未開，游人到處盡裴回。", "憑誰借問巖前叟，曾託吾皇一夢來。"]'),
('79a76939-637c-4985-b8ee-ec9e2c8ef62e','和武相公中秋夜西蜀錦樓望月得清字','王良會','唐','唐诗','tang','','[]','德星搖此夜，珥月滿重城。',48,'全唐诗/poet.tang.41000.json','["德星搖此夜，珥月滿重城。", "杳靄煙氛色，飄颻砧杵聲。", "令行秋氣爽，樂感素風輕。", "共賞千年聖，長歌四海清。"]'),
('f4dfbf6c-dfce-4db0-b47f-900f03fff9f3','星回節游避風臺與清平官賦','南詔驃信','唐','唐诗','tang','','[]','避風善闡臺，極目見藤越。',72,'全唐诗/poet.tang.41000.json','["避風善闡臺，極目見藤越。", "悲哉古與今，依然煙與月。", "自我居震旦，翊衛類夔契。", "伊昔頸皇運，艱難仰忠烈。", "不覺歲云暮，感極星回節。", "元昶同一心，子孫堪貽厥。"]'),
('9b08e85f-3ce5-4ee7-b632-ebeb3911d3a0','星回節避風臺驃信命賦','趙叔達','唐','唐诗','tang','','[]','法駕避星回，波羅毘勇猜。',48,'全唐诗/poet.tang.41000.json','["法駕避星回，波羅毘勇猜。", "河潤冰難合，地暖梅先開。", "下令俚柔洽，獻賝弄棟來。", "願將不才質，千載侍游臺。"]'),
('66fe78b8-9324-481d-8134-4be027e7c882','途中詩','楊奇鯤','唐','唐诗','tang','','[]','□□□□□□□，□□□□□□□。',64,'全唐诗/poet.tang.41000.json','["□□□□□□□，□□□□□□□。", "風裏浪花吹更白，雨中山色洗還青。", "海鷗聚處窗前見，林狖啼時枕上聽。", "此際自然無限趣，王程不敢暫留停。"]'),
('5ddc5d05-2e72-45d1-b682-97ff77cc44d9','聽妓洞雲歌','布燮','唐','唐诗','tang','','[]','嵇叔夜，鼓琴飲酒無閑暇。',56,'全唐诗/poet.tang.41000.json','["嵇叔夜，鼓琴飲酒無閑暇。", "若使當時聞此歌，拋擲廣陵都不藉。", "劉伯倫，虛生浪死過青春。", "一飲一碩猶自醉，無人爲爾卜深塵。"]'),
('568b053f-50f2-4f54-8366-1bcbf56bd56a','思鄉作','布燮','唐','唐诗','tang','','[]','瀘北行人絕，雲南信未還。',48,'全唐诗/poet.tang.41000.json','["瀘北行人絕，雲南信未還。", "庭前花不埽，門外柳誰攀。", "坐久銷銀燭，愁多減玉顏。", "懸心秋夜月，萬里照關山。"]'),
('2146f106-49cf-4481-9520-a3b06c55fb08','銜命還國作','朝衡','唐','唐诗','tang','','[]','銜命將辭國，非才忝侍臣。',72,'全唐诗/poet.tang.41000.json','["銜命將辭國，非才忝侍臣。", "天中戀明主，海外憶慈親。", "伏奏違金闕，騑驂去玉津。", "蓬萊鄉路遠，若木故園林。", "西望懷恩日，東歸感義辰。", "平生一寶劒，留贈結交人。"]'),
('887e37c0-7878-4078-9f37-f30c0b85d5e8','繡袈裟衣緣','長屋','唐','唐诗','tang','','[]','山川異域，風月同天。',20,'全唐诗/poet.tang.41000.json','["山川異域，風月同天。", "寄諸佛子，共結來緣。"]'),
('01813f10-27a6-49e9-9ba4-18a75b8b31fe','憤怨詩','王巨仁','唐','唐诗','tang','','[]','于公慟哭三年旱，鄒衍含愁五月霜。',32,'全唐诗/poet.tang.41000.json','["于公慟哭三年旱，鄒衍含愁五月霜。", "今我幽愁還似古，皇天無語但蒼蒼。"]'),
('c6de2910-2263-43e1-a829-33c2e458a434','立木海上刻詩','李贊華','唐','唐诗','tang','','[]','小山壓大山，大山全無力。',24,'全唐诗/poet.tang.41000.json','["小山壓大山，大山全無力。", "羞見故鄉人，從此投外國。"]'),
('3107d287-37fc-4d27-8ac8-a6ac2c890014','戲語','成輔端','唐','唐诗','tang','','[]','秦地城池二百年，何期如此賤田園。',32,'全唐诗/poet.tang.41000.json','["秦地城池二百年，何期如此賤田園。", "一頃麥苗碩伍米，三間堂屋二千錢。"]'),
('23a35503-2f15-45a3-a46e-54f189b1ab4d','萬壽寺歌詞','張隱','唐','唐诗','tang','','[]','位乖燮理致傷殘，四面牆匡不忍看。',32,'全唐诗/poet.tang.41000.json','["位乖燮理致傷殘，四面牆匡不忍看。", "正是花時堪下淚，相公何必更追歡。"]'),
('c2a54f85-16d9-4b63-9465-13d497558ce3','迎孫刺史','朱元','唐','唐诗','tang','','[]','昔日郎君今刺史，朱元依舊守朱門。',32,'全唐诗/poet.tang.41000.json','["昔日郎君今刺史，朱元依舊守朱門。", "今朝竹馬諸童子，盡是當時竹馬孫。"]'),
('de3b5f15-1a1d-423e-b3b0-aa612e693247','臨刑詩','陳璠','唐','唐诗','tang','','[]','積玉堆金官又崇，禍來倏忽變成空。',32,'全唐诗/poet.tang.41000.json','["積玉堆金官又崇，禍來倏忽變成空。", "五年榮貴今何在，不異南柯一夢中。"]'),
('b300ad66-301d-4b9a-b903-63a1350010d3','詩','捧劒僕','唐','唐诗','tang','','[]','青鳥銜葡萄，飛上金井欄。',24,'全唐诗/poet.tang.41000.json','["青鳥銜葡萄，飛上金井欄。", "美人恐驚去，不敢捲簾看。"]'),
('955572f1-5c58-4f75-958a-ae824f049a8c','題牡丹','捧劒僕','唐','唐诗','tang','','[]','一種芳菲出後庭，却輸桃李得佳名。',32,'全唐诗/poet.tang.41000.json','["一種芳菲出後庭，却輸桃李得佳名。", "誰能爲向天人說，從此移根近太清。"]'),
('fbdcc1a3-f685-483d-bba4-ec8ca33802dc','將竄留詩','捧劒僕','唐','唐诗','tang','','[]','珍重郭四郎，臨行不得別。',48,'全唐诗/poet.tang.41000.json','["珍重郭四郎，臨行不得別。", "曉漏動離心，輕車冒殘雪。", "欲出主人門，零涕暗嗚咽。", "萬里隔關山，一心思漢月。"]'),
('1010f9b1-01b2-44a9-a499-ecc0dad48405','淮陽感懷','李密','唐','唐诗','tang','','["\u79cb\u5929", "\u6292\u6000", "\u60c6\u6005", "\u5199\u666f", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6000\u53e4"]','金風蕩初節，玉露凋晚林。',108,'全唐诗/poet.tang.41000.json','["金風蕩初節，玉露凋晚林。", "此夕窮塗士，鬱陶傷寸心。", "野平葭葦合，村荒藜藿深。", "眺聽良多感，徙倚獨霑襟。", "霑襟何所爲，悵然懷古意。", "秦俗猶未平，漢道將何翼。", "樊噲市井徒，蕭何刀筆吏。", "一朝時運會，千古傳名諡。", "寄言世上雄，虛生真可媿。"]'),
('3299eb9b-32bb-4bfc-862b-7c577921db27','南隱遊泉山','孔德紹','唐','唐诗','tang','','[]','名山狎招隱，俗外遠相求。',72,'全唐诗/poet.tang.41000.json','["名山狎招隱，俗外遠相求。", "還如倒景望，忽似閬風遊。", "臨崖俯大壑，披霧仰飛流。", "歲積松方偃，年深椿欲秋。", "野花開石鏡，雲葉掩山樓。", "何須問方士，此處即瀛洲。"]'),
('2c266c8b-bb64-4902-87c7-c2e405588092','行經太華','孔德紹','唐','唐诗','tang','','[]','紛吾世網暇，靈岳展幽尋。',60,'全唐诗/poet.tang.41000.json','["紛吾世網暇，靈岳展幽尋。", "寥廊風塵遠，杳冥川谷深。", "山昏五里霧，日落二華陰。", "疎峰起蓮葉，危塞隱桃林。", "何必東都外，此處可抽簪。"]'),
('96978520-b66d-433a-82bb-0b54fc559183','夜宿荒村','孔德紹','唐','唐诗','tang','','[]','綿綿夕漏深，客恨轉傷心。',72,'全唐诗/poet.tang.41000.json','["綿綿夕漏深，客恨轉傷心。", "撫弦無人聽，對酒時獨斟。", "故鄉萬里絕，窮愁百慮侵。", "秋草思邊馬，遶枝驚夜禽。", "風度谷餘響，月斜山半陰。", "勞歌欲敘意，終是白頭吟。"]'),
('a8789dec-8a0f-4334-abca-5e4622a6f70b','王澤嶺遭洪水','孔德紹','唐','唐诗','tang','','[]','地籟風聲急，天津雲色愁。',84,'全唐诗/poet.tang.41000.json','["地籟風聲急，天津雲色愁。", "悠然萬頃滿，俄爾百川浮。", "遠似金堤溢，翻如碧海流。", "驚濤遙起鷺，迴岸不分牛。", "徒知懷趙景，終是倦陽侯。", "木梗誠無託，蘆灰豈暇求。", "思得乘槎便，蕭然河漢遊。"]'),
('6f4c09bc-65c6-4f17-a7be-a5d6359c747b','登白馬山護明寺','孔德紹','唐','唐诗','tang','','[]','名岳標形勝，危峰遠鬱紆。',120,'全唐诗/poet.tang.41000.json','["名岳標形勝，危峰遠鬱紆。", "成象建環極，大壯闡規模。", "層臺從靈鷲，高殿邇陽烏。", "暫同遊閬苑，還類入仙都。", "三休開碧嶺，萬戶洞金鋪。", "攝心罄前禮，訪道挹中虛。", "遙瞻盡地軸，長望極天隅。", "白雲起梁棟，丹霞映栱櫨。", "露花疑濯錦，泉月似沈珠。", "今日桃源客，相顧失歸塗。"]'),
('b4a74c09-0fb7-4705-973d-eba7241be475','送舍利宿定普巖','孔德紹','唐','唐诗','tang','','[]','仁祠表虛曠，祗園展肅恭。',60,'全唐诗/poet.tang.41000.json','["仁祠表虛曠，祗園展肅恭。", "棲息翠微嶺，登頓白雲峰。", "映流看夜月，臨峰聽曉鐘。", "澗芳十步草，崖陰百丈松。", "蕭然遙路絕，無復市朝蹤。"]'),
('6d2b797e-4492-4bf5-80f2-41963cf4e5ef','觀太常奏新樂','孔德紹','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','大君膺寶曆，出豫表功成。',72,'全唐诗/poet.tang.41000.json','["大君膺寶曆，出豫表功成。", "鈞天金石響，洞庭弦管清。", "八音動繁會，九變叶希聲。", "和雲留睿賞，熏風悅聖情。", "盛烈光韶濩，易俗邁咸英。", "竊吹良無取，率舞抃羣生。"]'),
('861d5fd9-d498-4beb-b16e-4a4a9e15bea1','賦得涉江采芙蓉','孔德紹','唐','唐诗','tang','','[]','蓮舟泛錦磧，極目眺江干。',48,'全唐诗/poet.tang.41000.json','["蓮舟泛錦磧，極目眺江干。", "沿流渡檝易，逆浪取花難。", "有霧疑川廣，無風見水寬。", "朝來採摘倦，詎得久盤桓。"]'),
('f3797664-352d-40cd-b10a-1adb0947710f','賦得華亭鶴','孔德紹','唐','唐诗','tang','','[]','華亭失侶鶴，乘軒寵遂終。',48,'全唐诗/poet.tang.41000.json','["華亭失侶鶴，乘軒寵遂終。", "三山凌苦霧，千里激悲風。", "心危白露下，聲斷綵弦中。", "何言斯物變，翻復似遼東。"]'),
('48543b6f-b767-4421-b93f-60070e0c4ec6','送蔡君知入蜀二首 一','孔德紹','唐','唐诗','tang','','[]','金陵已去國，銅梁忽背飛。',24,'全唐诗/poet.tang.41000.json','["金陵已去國，銅梁忽背飛。", "失路遠相送，他鄉何日歸。"]'),
('71b1b257-1bc0-4a62-9c19-dbdd25c86910','送蔡君知入蜀二首 二','孔德紹','唐','唐诗','tang','','[]','靈關九折險，蜀道二星遙。',24,'全唐诗/poet.tang.41000.json','["靈關九折險，蜀道二星遙。", "乘槎若有便，希泛廣陵潮。"]'),
('afb9c85b-d867-4bda-8c84-516d90b554e0','落葉','孔德紹','唐','唐诗','tang','','["\u79cb\u5929", "\u601d\u4e61", "\u5199\u666f", "\u6f02\u6cca"]','早秋驚葉落，飄零似客心。',24,'全唐诗/poet.tang.41000.json','["早秋驚葉落，飄零似客心。", "翻飛未肯下，猶言惜故林。"]'),
('d0913c25-e918-4952-b798-44f0a09389cf','句','孔德紹','唐','唐诗','tang','','[]','誰分菱花影，還看蓬鬢秋。',12,'全唐诗/poet.tang.41000.json','["誰分菱花影，還看蓬鬢秋。"]'),
('209365b3-4cbc-430d-987a-056b27ce10b0','臨刑詩','鄭頲','唐','唐诗','tang','','[]','幻生還幻滅，大幻莫過身。',24,'全唐诗/poet.tang.41000.json','["幻生還幻滅，大幻莫過身。", "安心自有處，求人無有人。"]'),
('ab76c0fc-144b-4884-a054-efec2987e260','和謁孔子廟','劉斌','唐','唐诗','tang','','["\u6cf0\u5c71"]','性與雖天縱，主世乃無由。',60,'全唐诗/poet.tang.41000.json','["性與雖天縱，主世乃無由。", "何言泰山毀，空驚逝水流。", "及門思往烈，入室想前修。", "寂寞荒堦暮，摧殘古木秋。", "遺風曖如此，聊以慰蒸求。"]'),
('0412bbd4-4dcc-42dd-95d2-40c53e1ef120','和許給事傷牛尚書','劉斌','唐','唐诗','tang','','[]','名臣不世出，百工之所求。',144,'全唐诗/poet.tang.41000.json','["名臣不世出，百工之所求。", "況乃非常器，遭逢興運秋。", "符彩照千里，銓衡綜九流。", "經綸資百物，樽俎寄皇猷。", "韶濩傾復理，典禮紊還修。", "雖貞棟梁任，兼好藝文游。", "佇聞和鼎實，行當奉介丘。", "高衢翻稅駕，閱水遽遷舟。", "傳呼更何日，曳履聞無由。", "歸魂藐脩路，征櫂艤邗溝。", "林薄長風慘，江上寒雲愁。", "夜臺終不曙，遺芳徒自留。"]'),
('a9971af6-ff43-4a0c-9659-c4690ea261fd','送劉散員同賦陳思王詩得好鳥鳴高枝','劉斌','唐','唐诗','tang','','[]','春林已自好，時鳥復和鳴。',50,'全唐诗/poet.tang.41000.json','["春林已自好，時鳥復和鳴。", "枝交難奮翼，谷靜易流聲。", "間關纔得性，[矰]繳遽相驚。", "安知背飛遠，拂霧獨晨征。"]'),
('d83f4859-18c6-481b-b9ef-5aef52e35602','詠山','劉斌','唐','唐诗','tang','','[]','靈山峙千仞，蔽日且嵯峨。',48,'全唐诗/poet.tang.41000.json','["靈山峙千仞，蔽日且嵯峨。", "紫蓋雲陰遠，香爐煙氣多。", "石梁高鳥路，瀑水近天河。", "欲知聞道里，別自有仙歌。"]'),
('77ec8e4f-8eba-49b9-8ae3-f5e9925f44d8','登樓望月二首 一','劉斌','唐','唐诗','tang','','[]','圓月當新霽，高樓見最明。',72,'全唐诗/poet.tang.41000.json','["圓月當新霽，高樓見最明。", "素波流粉壁，丹桂拂飛甍。", "下瞰千門靜，旁觀萬象生。", "梧桐窗下影，鳥鵲檻前聲。", "嘯逸劉琨興，吟資庾亮情。", "遊人莫登眺，迢遞故鄉程。"]'),
('0bb587ba-21d0-4437-a519-6bc7a7317fa0','登樓望月二首 二','劉斌','唐','唐诗','tang','','[]','皎潔三秋月，巍峨百丈樓。',72,'全唐诗/poet.tang.41000.json','["皎潔三秋月，巍峨百丈樓。", "下分征客路，上有美人愁。", "帳卷芙蓉帶，簾褰玳瑁鉤。", "倚窗情渺渺，憑檻思悠悠。", "末得金波轉，俄成玉筯流。", "不堪三五夕，夫壻在邊州。"]'),
('0939af03-3cbb-4f62-bbcf-d5dcaed9c2ea','題菊花','黃巢','唐','唐诗','tang','','["\u548f\u7269", "\u83ca\u82b1", "\u690d\u7269", "\u8c6a\u58ee", "\u6292\u6000", "\u548f\u7269\u8bd7"]','颯颯西風滿院栽，蘂寒香冷蝶難來。',32,'全唐诗/poet.tang.41000.json','["颯颯西風滿院栽，蘂寒香冷蝶難來。", "他年我若爲青帝，報與桃花一處開。"]'),
('4a38ccaa-e3e3-4920-9f22-3a686c934000','不第後賦菊','黃巢','唐','唐诗','tang','','["\u548f\u7269", "\u83ca\u82b1", "\u62b1\u8d1f", "\u548f\u7269\u8bd7", "\u54c1\u683c"]','待到秋來九月八，我花開後百花殺。',32,'全唐诗/poet.tang.41000.json','["待到秋來九月八，我花開後百花殺。", "衝天香陣透長安，滿城盡帶黃金甲。"]'),
('e90727d6-db93-49ba-8850-13629dcec59a','自題像','黃巢','唐','唐诗','tang','','[]','記得當年草上飛，鐵衣著盡著僧衣。',32,'全唐诗/poet.tang.41000.json','["記得當年草上飛，鐵衣著盡著僧衣。", "天津橋上無人識，獨倚欄干看落暉。"]'),
('9af71473-30cc-45f1-bbf5-dbc548c8a611','柳','羅紹威','唐','唐诗','tang','','[]','妝點青春更有誰，青春常許占先知。',64,'全唐诗/poet.tang.41000.json','["妝點青春更有誰，青春常許占先知。", "亞夫營畔風輕處，元亮門前日暖時。", "花密宛如飄六出，葉繁何惜借雙眉。", "交情別緒論多少，好向仁人贈一枝。"]'),
('94f6a5a6-3e3a-49cb-98ad-06e288f3ca3f','白菊','羅紹威','唐','唐诗','tang','','[]','雖被風霜競欲催，皎然顏色不低摧。',64,'全唐诗/poet.tang.41000.json','["雖被風霜競欲催，皎然顏色不低摧。", "已疑素手能妝出，又似金錢未染來。", "香散自宜飄淥酒，葉交仍得蔭蒼苔。", "尋思閉戶中宵見，應認寒窗雪一堆。"]'),
('d492634f-f9c7-460d-ac55-940178c624a2','句','羅紹威','唐','唐诗','tang','','[]','樓前澹澹雲頭日，簾外蕭蕭雨脚風。',16,'全唐诗/poet.tang.41000.json','["樓前澹澹雲頭日，簾外蕭蕭雨脚風。"]'),
('37f35117-c17b-469d-b3aa-9774e47ef532','清明登奉先城樓','羅衮','唐','唐诗','tang','','[]','年來年去只艱危，春半堯山草尚衰。',64,'全唐诗/poet.tang.41000.json','["年來年去只艱危，春半堯山草尚衰。", "四海清平耆舊見，五陵寒食小臣悲。", "煙銷井邑隈樓檻，雪滿川原泥酒巵。", "拭盡賈生無限淚，一行歸雁遠參差。"]'),
('e5932ce9-aae5-4200-ab22-d88fc81e7d96','清明赤水寺居','羅衮','唐','唐诗','tang','','[]','榆火輕煙處處新，旋從閑望到諸鄰。',64,'全唐诗/poet.tang.41000.json','["榆火輕煙處處新，旋從閑望到諸鄰。", "浮生浮世祗多事，野水野花娛病身。", "濁酒不禁雲外景，碧峰猶冷寺前春。", "蓑衣毳衲誠吾黨，自結村園一社貧。"]'),
('a4602a50-d302-413b-9fca-07c7aeb05f9c','贈羅隱','羅衮','唐','唐诗','tang','','[]','平日時風好涕流，讒書雖盛一名休。',64,'全唐诗/poet.tang.41000.json','["平日時風好涕流，讒書雖盛一名休。", "寰區歎屈瞻天問，夷貊聞詩過海求。", "向夕便思青瑣拜，近年尋伴赤松遊。", "何當世祖從人望，早以公台命卓侯。"]'),
('e4e53053-451e-4a40-9997-e879e4d8df66','哭趙州和尚二首 一','王鎔','唐','唐诗','tang','','[]','師離㴲水動王侯，心印光潛麈尾收。',64,'全唐诗/poet.tang.41000.json','["師離㴲水動王侯，心印光潛麈尾收。", "碧落霧霾松嶺月，滄溟浪覆濟人舟。", "一燈乍滅波旬喜，雙眼重昏道侶愁。", "縱是了然雲外客，每瞻缾几淚還流。"]'),
('d894a481-af39-4b7d-9e5a-2aa62aa71dd5','哭趙州和尚二首 二','王鎔','唐','唐诗','tang','','[]','佛日西傾祖印隳，珠沈丹沼月沈輝。',64,'全唐诗/poet.tang.41000.json','["佛日西傾祖印隳，珠沈丹沼月沈輝。", "影敷丈室爐煙慘，風起禪堂松韻微。", "隻履乍來留化跡，五天何處又逢歸。", "解空弟子絕悲喜，猶自潸然對雪幃。"]'),
('272300a0-b692-4c21-a18c-3ed56547c867','荅同年李昉見贈次韻','鄧洵美','唐','唐诗','tang','','[]','詞場幾度讓長鞭，又向清朝賀九遷。',64,'全唐诗/poet.tang.41000.json','["詞場幾度讓長鞭，又向清朝賀九遷。", "品秩雖然殊此日，歲寒終不改當年。", "馳名早已超三院，侍直仍忻步八磚。", "今日相逢翻自媿，閑吟對酒倍潸然。"]'),
('0522e427-d0fd-4297-b951-b49d6fecb260','除夜長安作','李京','唐','唐诗','tang','','[]','長安朔風起，窮巷掩雙扉。',48,'全唐诗/poet.tang.41000.json','["長安朔風起，窮巷掩雙扉。", "新歲明朝是，故鄉何路歸。", "鬢絲饒鏡色，隙雪奪燈輝。", "却羨秦州雁，逢春盡北飛。"]'),
('2de02ac5-cdd6-497f-8b77-4857a3567202','登嶺望','許鼎','唐','唐诗','tang','','[]','淼淼三江水，悠悠五嶺關。',24,'全唐诗/poet.tang.41000.json','["淼淼三江水，悠悠五嶺關。", "雁飛猶不度，人去若爲還。"]'),
('dac9f65e-2498-4818-8ec7-61e0594493a7','㟧嶺四望','許鼎','唐','唐诗','tang','','[]','漢家仙仗在咸陽，洛水東流出建章。',32,'全唐诗/poet.tang.41000.json','["漢家仙仗在咸陽，洛水東流出建章。", "野老至今猶望辛，離宮秋樹獨蒼蒼。"]'),
('9b51815e-1a80-46ec-adb5-fd0c03e11c71','官左拾遺歸隱作','王易簡','唐','唐诗','tang','','[]','汨沒朝班媿不才，誰能低折向塵埃。',32,'全唐诗/poet.tang.41000.json','["汨沒朝班媿不才，誰能低折向塵埃。", "青山得去且歸去，官職有來還自來。"]'),
('9f2ca905-f6f9-430a-9d92-98842e2cd081','悼楊氏妓琴弦','朱褒','唐','唐诗','tang','','[]','魂歸寥廊魄歸泉，只住人間十五年。',32,'全唐诗/poet.tang.41000.json','["魂歸寥廊魄歸泉，只住人間十五年。", "昨日施僧裙帶上，斷腸猶繫琵琶弦。"]'),
('483abfe4-ae97-42bb-a0f8-c92752d51df3','公子行','黃損','唐','唐诗','tang','','[]','春草綠綿綿，驕驂驟煖煙。',48,'全唐诗/poet.tang.41000.json','["春草綠綿綿，驕驂驟煖煙。", "微風飄樂韻，半日醉花邊。", "打鵲拋金盞，招人舉玉鞭。", "田翁與蠶婦，平地看神仙。"]'),
('b517a5c3-3975-4638-8a1f-5c51eddcd8c2','讀史','黃損','唐','唐诗','tang','','[]','逐鹿走紅塵，炎炎火德新。',48,'全唐诗/poet.tang.41000.json','["逐鹿走紅塵，炎炎火德新。", "家肥生孝子，國霸有餘臣。", "帝道雲龍合，民心草木春。", "須知煙閣上，一半老儒真。"]'),
('42fab1cf-ad7f-4c48-be72-f4a1f215aca2','出山吟','黃損','唐','唐诗','tang','','[]','來書初出白雲扃，乍躡秋風馬走輕。',64,'全唐诗/poet.tang.41000.json','["來書初出白雲扃，乍躡秋風馬走輕。", "遠近留連分岳色，別離嗚咽亂泉聲。", "休將巢許爭喧雜，自共伊臯論太平。", "昨夜細看雲色裏，進賢星座甚分明。"]'),
('77af18b1-1de2-4000-860f-6d6da8349e2f','書壁','黃損','唐','唐诗','tang','','[]','一別人間歲月多，歸來人事已銷磨。',32,'全唐诗/poet.tang.41000.json','["一別人間歲月多，歸來人事已銷磨。", "惟有門前鑑池水，春風不改舊時波。"]'),
('e1ffb563-e56f-46de-8667-9c6e3562b55a','句','黃損','唐','唐诗','tang','','[]','機關纔運動，勝敗便相隨。',136,'全唐诗/poet.tang.41000.json','["機關纔運動，勝敗便相隨。", "忽遇南遷客，若爲西入心。", "往來三島近，活計一囊空。", "三通明主詔，一片白雲心。", "掃地待明月，踏花迎野僧。", "水諳彭澤闊，山憶武陵深。", "金鐙冷光風宛轉，錦袍紅潤雨霏微。", "高齊日月方爲道，動合乾坤始是心。", "傍水野禽通體白，飣盤山菓半邊紅。", "而今世上多離別，莫向相思樹下啼。"]'),
('684bc1a4-1b63-497b-9df6-93e387f45752','梁郊祀樂章 慶肅','張衮','唐','唐诗','tang','','[]','籩豆簠簋，黍稷非馨。',40,'全唐诗/poet.tang.41000.json','["籩豆簠簋，黍稷非馨。", "懿茲彝器，厥德惟明。", "金石匏革，以和以平。", "由此無疆，期乎永寧。"]'),
('64aaf38c-58b2-4b25-a2d2-d03388c2c215','梁郊祀樂章 慶熙','張衮','唐','唐诗','tang','','[]','哲后躬享，旨酒斯陳。',40,'全唐诗/poet.tang.41000.json','["哲后躬享，旨酒斯陳。", "王恭無斁，嚴祀惟寅。", "皇祖以配，大孝以振。", "宜錫景福，永休下民。"]'),
('02122e2d-f7f5-47b5-9e42-0924f4e45acc','梁郊祀樂章 慶隆','張衮','唐','唐诗','tang','','[]','恭祀上帝，于國之陽。',20,'全唐诗/poet.tang.41000.json','["恭祀上帝，于國之陽。", "爵醴是荷，鴻基永昌。"]'),
('c19ffb32-9417-4fcf-9a88-0365f13e78ba','梁郊祀樂章 慶融','張衮','唐','唐诗','tang','','[]','導和氣兮襲氤氳，宣皇使兮彰聖神。',32,'全唐诗/poet.tang.41000.json','["導和氣兮襲氤氳，宣皇使兮彰聖神。", "服遐裔兮敷質文，格苗扈兮息煙塵。"]'),
('6bf741e0-5fdc-4608-bac9-0ba36f47de03','梁郊祀樂章 慶休','張衮','唐','唐诗','tang','','[]','大業來四夷，仁風和萬國。',48,'全唐诗/poet.tang.41000.json','["大業來四夷，仁風和萬國。", "白日體無私，皇天輔有德。", "七旬罪已服，六旬師方克。", "偉哉帝道隆，終始常作則。"]'),
('2533cef0-3afa-4c02-995d-109b62814792','梁郊祀樂章 慶和','張衮','唐','唐诗','tang','','[]','煙燎昇，禮容徹。',32,'全唐诗/poet.tang.41000.json','["煙燎昇，禮容徹。", "誠感達，人神悅。", "靈貺彰，聖情結。", "玉座寂，金罏歇。"]'),
('9cbda0f3-35f6-4a45-ac70-b08a79eec38c','梁郊祀樂章 慶和 一','趙光逢','唐','唐诗','tang','','[]','就陽位，昇圜丘。',32,'全唐诗/poet.tang.41000.json','["就陽位，昇圜丘。", "佩雙玉，御大裘。", "膺天命，擁神休。", "萬靈感，百祿遒。"]'),
('d512676d-d05d-43ba-a2dc-387c41b5f8f7','梁郊祀樂章 慶和 二','趙光逢','唐','唐诗','tang','','[]','秉黃鉞，建朱旗。',32,'全唐诗/poet.tang.41000.json','["秉黃鉞，建朱旗。", "震八表，清二儀。", "帝業顯，王道夷。", "受景命，啓皇基。"]'),
('2e2e7e2a-c8b1-49a4-9c81-ad84d3000fa8','梁郊祀樂章 慶和 三','趙光逢','唐','唐诗','tang','','[]','開九門，懷百神。',32,'全唐诗/poet.tang.41000.json','["開九門，懷百神。", "通肸蠁，接氤氳。", "明粢薦，廣樂陳。", "奠嘉璧，燎芳薪。"]'),
('9b51eef9-6a73-4e67-a878-a42ba109cb39','梁郊祀樂章 慶和 四','趙光逢','唐','唐诗','tang','','[]','膺寶圖，執左契。',32,'全唐诗/poet.tang.41000.json','["膺寶圖，執左契。", "德應天，聖饗帝。", "薦表衷，荷靈惠。", "壽萬年，祚百世。"]'),
('d152f46d-9fa4-403d-ab40-672416710ee1','梁郊祀樂章 慶和 五','趙光逢','唐','唐诗','tang','','[]','惟德動天，有感必通。',40,'全唐诗/poet.tang.41000.json','["惟德動天，有感必通。", "秉茲一德，禋於六宗。", "欽夤寶命，恭肅禮容。", "來顧來享，永穆皇風。"]'),
('87792c2e-d2b7-4eac-8d2d-2aa1fa6240a2','梁郊祀樂章 慶和 六','趙光逢','唐','唐诗','tang','','[]','天惟佑德，辟乃奉天。',40,'全唐诗/poet.tang.41000.json','["天惟佑德，辟乃奉天。", "交感斯在，昭事罔愆。", "歲功已就，王道無偏。", "於焉報本，是用告虔。"]'),
('0f5202c1-6836-4721-bce6-06bdb058466b','梁郊祀樂章 慶順','趙光逢','唐','唐诗','tang','','[]','聖皇戾止，天步舒遲。',40,'全唐诗/poet.tang.41000.json','["聖皇戾止，天步舒遲。", "乾乾睿相，穆穆皇儀。", "進退必肅，陟降是祗。", "六變克協，萬靈協隨。"]'),
('50b3e7d3-dbc8-403f-80bd-432b02ac60ca','梁郊祀樂章 慶平','趙光逢','唐','唐诗','tang','','[]','天命降鑒，帝德惟馨。',40,'全唐诗/poet.tang.41000.json','["天命降鑒，帝德惟馨。", "享祀不忒，禮容孔明。", "奠璧布幣，薦純獻精。", "神祐以荅，敷錫永寧。"]'),
('a55092e8-0ff9-4291-89a9-085f5ea53724','宮詞百首 一','和凝','唐','唐诗','tang','','[]','紫燎光銷大駕歸，御樓初見赭黃衣。',32,'全唐诗/poet.tang.41000.json','["紫燎光銷大駕歸，御樓初見赭黃衣。", "千聲鼓定將宣赦，竿上金雞翅欲飛。"]'),
('9962a1b2-55f8-4aac-a8f7-8150f5ea6d32','宮詞百首 二','和凝','唐','唐诗','tang','','[]','北闕晴分五鳳樓，嵩山秀色護神州。',32,'全唐诗/poet.tang.41000.json','["北闕晴分五鳳樓，嵩山秀色護神州。", "洛河自契千年運，更擬波中出九疇。"]'),
('d806ecc3-fec4-4995-bc77-2588deca4ba0','宮詞百首 三','和凝','唐','唐诗','tang','','[]','中興殿上曉光融，一炷天香舞瑞風。',32,'全唐诗/poet.tang.41000.json','["中興殿上曉光融，一炷天香舞瑞風。", "百辟虔心齊稽首，捲簾遙見御衣紅。"]'),
('bccda39f-8653-4646-98e2-c2b1a9b699b2','宮詞百首 四','和凝','唐','唐诗','tang','','[]','日和風暖御樓時，萬姓齊瞻八彩眉。',32,'全唐诗/poet.tang.41000.json','["日和風暖御樓時，萬姓齊瞻八彩眉。", "瑞氣祥烟籠細仗，閤門宣赦四方知。"]'),
('d47db8c4-ad10-4c53-abc1-768716215c98','宮詞百首 五','和凝','唐','唐诗','tang','','[]','鳳吹鸞歌曉日明，豐年觀稼出神京。',32,'全唐诗/poet.tang.41000.json','["鳳吹鸞歌曉日明，豐年觀稼出神京。", "封人爭獻南山壽，五色雲中御輦平。"]'),
('1bf0edf7-f8f5-4abb-84f8-b0f0adea887b','宮詞百首 六','和凝','唐','唐诗','tang','','[]','聖主臨軒待曉時，穿花宮漏正遲遲。',32,'全唐诗/poet.tang.41000.json','["聖主臨軒待曉時，穿花宮漏正遲遲。", "雞人一唱乾坤曉，百辟分班儼羽儀。"]'),
('886a47d9-bdde-41be-a827-e2072c705f40','宮詞百首 七','和凝','唐','唐诗','tang','','[]','朦朧西月照池亭，初夜椒房掩畫屏。',32,'全唐诗/poet.tang.41000.json','["朦朧西月照池亭，初夜椒房掩畫屏。", "宮女相呼有何事，上樓同看老人星。"]'),
('2e2c40fb-62a7-43cb-b0d2-e33d11b8da9e','宮詞百首 八','和凝','唐','唐诗','tang','','[]','紅泥椒殿綴珠璫，帳蹙金龍窣地長。',32,'全唐诗/poet.tang.41000.json','["紅泥椒殿綴珠璫，帳蹙金龍窣地長。", "紅獸慢然天色暖，鳳爐時復爇沈香。"]'),
('ff00e8da-9f3c-453b-9584-ae7246131fa0','宮詞百首 九','和凝','唐','唐诗','tang','','[]','九重樓殿簇丹青，高柳含烟覆井亭。',32,'全唐诗/poet.tang.41000.json','["九重樓殿簇丹青，高柳含烟覆井亭。", "宮內不知今日幾，自來階下數堯蓂。"]'),
('798f19b6-66eb-411f-b8cc-c4c7178d47d1','宮詞百首 十','和凝','唐','唐诗','tang','','[]','寢殿香濃玉漏嚴，雲隨涼月下西南。',32,'全唐诗/poet.tang.41000.json','["寢殿香濃玉漏嚴，雲隨涼月下西南。", "帳前宮女低聲道，主上還應夢傅巖。"]'),
('d7133c7f-b36f-4bde-a65e-2c3096342cb5','宮詞百首 十一','和凝','唐','唐诗','tang','','[]','遶殿鉤欄壓玉階，內人輕語凭蔥薹。',32,'全唐诗/poet.tang.41000.json','["遶殿鉤欄壓玉階，內人輕語凭蔥薹。", "皆言明主垂衣理，不假朱雲傍檻來。"]'),
('2006fd35-62b4-49e6-acd5-8fe7a8857379','宮詞百首 十二','和凝','唐','唐诗','tang','','[]','顢頇冰面瑩池心，風刮瑤階臘雪深。',32,'全唐诗/poet.tang.41000.json','["顢頇冰面瑩池心，風刮瑤階臘雪深。", "怪得宮中無獸炭，步搖釵是辟寒金。"]'),
('aee17ffc-eba8-415d-b08b-c5a342f6e59c','宮詞百首 十三','和凝','唐','唐诗','tang','','[]','蘭殿春融自靘笙，玉顏風透象紗明。',32,'全唐诗/poet.tang.41000.json','["蘭殿春融自靘笙，玉顏風透象紗明。", "金簧如語鶯聲滑，可使雲和獨得名。"]'),
('dd4d993b-7808-418e-8725-b582e707201a','宮詞百首 十四','和凝','唐','唐诗','tang','','[]','蘭燭時將鳳髓添，寒星遙映夜光簾。',32,'全唐诗/poet.tang.41000.json','["蘭燭時將鳳髓添，寒星遙映夜光簾。", "龍樓露著鴛鴦瓦，誰近螭頭擲玉籤。"]'),
('eecfb756-93c5-41fd-b5c3-2f6cfabbca56','宮詞百首 十五','和凝','唐','唐诗','tang','','["\u9ec4\u6cb3"]','玉甃蓮池春水平，小魚雙竝錦鱗行。',32,'全唐诗/poet.tang.41000.json','["玉甃蓮池春水平，小魚雙竝錦鱗行。", "內中知是黃河樣，九曲今年徹底清。"]'),
('e4908530-bd4b-4664-bbf6-ec6e6cedf0f9','宮詞百首 十六','和凝','唐','唐诗','tang','','[]','真珠簾外靜無塵，耿耿涼天景象新。',32,'全唐诗/poet.tang.41000.json','["真珠簾外靜無塵，耿耿涼天景象新。", "金殿夜深銀燭晃，宮嬪來奏月重輪。"]'),
('7f156b9f-d033-44cc-8a3b-57dc28f2a825','宮詞百首 十七','和凝','唐','唐诗','tang','','[]','魚犀月掌夜通頭，自著盤鶯錦臂韝。',32,'全唐诗/poet.tang.41000.json','["魚犀月掌夜通頭，自著盤鶯錦臂韝。", "多把沈檀配龍麝，宮中掌浸十香油。"]'),
('2e545b86-8026-4d49-843d-4bb2f2d979d1','宮詞百首 十八','和凝','唐','唐诗','tang','','[]','香雲雙颭玉蟬輕，侍從君王苑裏行。',32,'全唐诗/poet.tang.41000.json','["香雲雙颭玉蟬輕，侍從君王苑裏行。", "嘉瑞忽逢連理木，一時跪拜賀文明。"]'),
('fd80718b-1764-439b-b605-7f14622de429','宮詞百首 十九','和凝','唐','唐诗','tang','','[]','金鸞雙立紫檀槽，暖殿無風韻自高。',32,'全唐诗/poet.tang.41000.json','["金鸞雙立紫檀槽，暖殿無風韻自高。", "含笑試彈紅蘂調，君王宣賜酪櫻桃。"]'),
('ec9c2ae1-b5dc-4334-aea7-a3bf422a6ebf','宮詞百首 二十','和凝','唐','唐诗','tang','','[]','斑簟如霞可殿鋪，更開新進瑞蓮圖。',32,'全唐诗/poet.tang.41000.json','["斑簟如霞可殿鋪，更開新進瑞蓮圖。", "誰人築損珊瑚架，子細看時認瀝蘇。"]'),
('4983b102-f06d-479b-b5d5-a897f19f89c1','宮詞百首 二十一','和凝','唐','唐诗','tang','','[]','金盆初曉洗纖纖，銀鴨香焦特地添。',32,'全唐诗/poet.tang.41000.json','["金盆初曉洗纖纖，銀鴨香焦特地添。", "出戶忽看春雪下，六宮齊捲水晶簾。"]'),
('bad15ec0-9b1f-4126-aa61-24a3ad2f7570','宮詞百首 二十二','和凝','唐','唐诗','tang','','[]','暖金盤裏點酥山，擬望君王子細看。',32,'全唐诗/poet.tang.41000.json','["暖金盤裏點酥山，擬望君王子細看。", "更向眉中分曉黛，巖邊染出碧琅玕。"]'),
('c55168d9-3cc8-471e-970e-c98a2c3c6139','宮詞百首 二十三','和凝','唐','唐诗','tang','','[]','雲母屏前繡柱衣，龍牀閑卷諫書幃。',32,'全唐诗/poet.tang.41000.json','["雲母屏前繡柱衣，龍牀閑卷諫書幃。", "黃金檻外螭頭活，日照紅蘭露未晞。"]'),
('b2be5e48-2b13-4f93-b547-f440af96ab9f','宮詞百首 二十四','和凝','唐','唐诗','tang','','[]','樓西殘月尚朧明，中禁雞人報曉聲。',32,'全唐诗/poet.tang.41000.json','["樓西殘月尚朧明，中禁雞人報曉聲。", "清旦司天臺進狀，夜來晴霽泰階平。"]'),
('6b3da3a0-3d67-42f1-bd5a-3eb293b69c75','宮詞百首 二十五','和凝','唐','唐诗','tang','','[]','纖轡摩軒響佩環，銀臺門外集鴛鸞。',32,'全唐诗/poet.tang.41000.json','["纖轡摩軒響佩環，銀臺門外集鴛鸞。", "三鐘五鼓祥烟歛，日照仙人捧露盤。"]'),
