('ac980cbc-d0f9-473c-b4b3-33589ac78b55','楊柳枝 三','和凝','唐','唐诗','tang','','[]','鵲橋初就咽銀河，今夜仙郎自姓和。',32,'全唐诗/poet.tang.41000.json','["鵲橋初就咽銀河，今夜仙郎自姓和。", "不是昔年攀桂樹，豈能月裏索姮娥。"]'),
('4aa80578-413a-4eee-8bc3-43b03b0d002a','解紅歌','和凝','唐','唐诗','tang','','[]','百戲罷，五音清，解紅一曲新教成。',32,'全唐诗/poet.tang.41000.json','["百戲罷，五音清，解紅一曲新教成。", "兩個瑤池小仙子，此時奪却柘枝名。"]'),
('81402442-de07-4c52-9dd1-be8da36819ad','題鷹獵兔畫','和凝','唐','唐诗','tang','','[]','雖是丹青物，沈吟亦可傷。',48,'全唐诗/poet.tang.41000.json','["雖是丹青物，沈吟亦可傷。", "君誇鷹眼疾，我憫兔心忙。", "豈動騷人興，惟增獵客狂。", "鮫綃百餘尺，爭及製衣裳。"]'),
('9e1efc81-76ee-4de1-9790-903686d5e018','醴泉院','和凝','唐','唐诗','tang','','[]','萬山嵐靄簇洋城，數處禪齋盡有名。',64,'全唐诗/poet.tang.41000.json','["萬山嵐靄簇洋城，數處禪齋盡有名。", "古柏八株堆翠色，靈泉一派逗寒聲。", "暫遊頗愛閑滋味，久住翻嫌俗性情。", "珍重支公每相勉，我于儒行也修行。"]'),
('c01be0d9-71cf-4733-90bb-97fca42039fd','興勢觀','和凝','唐','唐诗','tang','','[]','山名興勢鎮梁洋，儼有真風福此方。',64,'全唐诗/poet.tang.41000.json','["山名興勢鎮梁洋，儼有真風福此方。", "瘦柏握盤籠殿紫，靈泉澄潔浸花香。", "暫遊頗愛閑人少，久住翻嫌白日忙。", "只向五千文字內，願成金骨住仙鄉。"]'),
('961503a7-cf65-4ae9-a873-03f9dee1f343','洋川','和凝','唐','唐诗','tang','','[]','華夷圖上見洋川，知在青山綠水邊。',32,'全唐诗/poet.tang.41000.json','["華夷圖上見洋川，知在青山綠水邊。", "官閑最好遊僧舍，江近應須買釣船。"]'),
('b8d02e2d-8b03-4e1a-aaba-a1b6fe33b429','句','和凝','唐','唐诗','tang','','[]','先生自舞琴。',22,'全唐诗/poet.tang.41000.json','["先生自舞琴。", "波上人如潘玉兒，掌中花似趙飛燕。"]'),
('fd11f8f2-028a-4479-ba65-f988e7ddef7b','從蜀後主幸秦川上梓潼山','王仁裕','唐','唐诗','tang','','[]','綵仗拂寒煙，鳴騶在半天。',48,'全唐诗/poet.tang.41000.json','["綵仗拂寒煙，鳴騶在半天。", "黃雲生馬足，白日下松巔。", "盛德安疲俗，仁風扇極邊。", "前程問成紀，此去尚三千。"]'),
('a0d401a3-d85b-45f5-9b51-9245a0b29340','和蜀後主題劒門','王仁裕','唐','唐诗','tang','','[]','孟陽曾有語，刊在白雲稜。',48,'全唐诗/poet.tang.41000.json','["孟陽曾有語，刊在白雲稜。", "李杜常挨托，孫劉亦恃憑。", "庸才安可守，上德始堪矜。", "暗指長天路，濃巒蔽幾層。"]'),
('37c93c13-19ca-49ce-890e-b2a1073c7694','荆南席上詠胡琴妓二首 一','王仁裕','唐','唐诗','tang','','[]','紅妝齊抱紫檀槽，一抹朱弦四十條。',64,'全唐诗/poet.tang.41000.json','["紅妝齊抱紫檀槽，一抹朱弦四十條。", "湘水淩波慚鼓瑟，秦樓明月罷吹簫。", "寒敲白玉聲偏婉，暖逼黃鶯語自嬌。", "丹禁舊臣來側耳，骨清神爽似聞韶。"]'),
('72b8a953-409b-40a5-a8ad-883b4d0e3d4e','荆南席上詠胡琴妓二首 二','王仁裕','唐','唐诗','tang','','[]','玉纖挑落折冰聲，散入秋空韻轉清。',64,'全唐诗/poet.tang.41000.json','["玉纖挑落折冰聲，散入秋空韻轉清。", "二五指中句塞雁，十三弦上囀春鶯。", "譜從陶室偷將妙，曲向秦樓寫得成。", "無限細腰宮裏女，就中偏愜楚王情。"]'),
('e6247b20-a2c9-4850-93ce-f0d11aedb09e','題麥積山天堂','王仁裕','唐','唐诗','tang','','[]','躡盡懸空萬仞梯，等閑身共白雲齊。',64,'全唐诗/poet.tang.41000.json','["躡盡懸空萬仞梯，等閑身共白雲齊。", "簷前下視羣山小，堂上平分落日低。", "絕頂路危人少到，古巖松健鶴頻棲。", "天邊爲要留名姓，拂石殷勤身自題。"]'),
('e06d0ab0-a6aa-4523-acc7-e5e6f05c37a7','題斗山觀','王仁裕','唐','唐诗','tang','','[]','霞衣欲舉醉陶陶，不覺全家住絳霄。',64,'全唐诗/poet.tang.41000.json','["霞衣欲舉醉陶陶，不覺全家住絳霄。", "拔宅只知雞犬在，上天誰信路岐遙。", "三清遼廊拋塵夢，八景雲煙事早朝。", "爲有故林蒼柏健，露華涼葉鎖金飆。"]'),
('5e081164-bdc3-4f92-93b1-9fe47045ebf7','題孤雲絶頂淮陰祠','王仁裕','唐','唐诗','tang','','[]','一握寒天古木深，路人猶說漢淮陰。',64,'全唐诗/poet.tang.41000.json','["一握寒天古木深，路人猶說漢淮陰。", "孤雲不掩興亡策，兩角曾懸去住心。", "不是冕旒輕布素，豈勞丞相遠追尋。", "當時若放還西楚，尺寸中華未可侵。"]'),
('7ecc63b6-9fda-4e5a-8e4f-be38e38150b2','和韓昭從駕過白衛嶺','王仁裕','唐','唐诗','tang','','[]','龍斾飄颻指極邊，到時猶更二三千。',64,'全唐诗/poet.tang.41000.json','["龍斾飄颻指極邊，到時猶更二三千。", "登高曉蹋巉巖石，冒冷朝衝斷續煙。", "自學漢皇開土宇，不同周穆好神仙。", "秦民莫遣無恩及，大散關東別有天。"]'),
('6804fe1d-98d6-45de-8cb7-69acdd2a38d4','賀王溥入相','王仁裕','唐','唐诗','tang','','[]','一戰文場拔趙旗，便調金鼎佐無爲。',64,'全唐诗/poet.tang.41000.json','["一戰文場拔趙旗，便調金鼎佐無爲。", "白麻驟降恩何極，黃髮初聞喜可知。", "跋勅案前人到少，築沙堤上馬歸遲。", "立班始得遙相見，親洽爭如未貴時。"]'),
('36f0ca4a-62f6-4c68-8a81-96a1561ca05c','與諸門生春日會飲繁臺賦','王仁裕','唐','唐诗','tang','','[]','柳陰如霧絮成堆，又引門生飲古臺。',64,'全唐诗/poet.tang.41000.json','["柳陰如霧絮成堆，又引門生飲古臺。", "淑景即隨風雨去，芳樽宜命管弦開。", "謾誇列鼎鳴鐘貴，寧免朝烏夜兔催。", "爛醉也須詩一首，不能空放馬頭回。"]'),
('ce95e775-7127-4a40-acab-439564dd1d8e','示諸門生','王仁裕','唐','唐诗','tang','','[]','二百一十四門生，春風初長羽毛成。',64,'全唐诗/poet.tang.41000.json','["二百一十四門生，春風初長羽毛成。", "擲金換得天邊桂，鑿壁偷將榜上名。", "何辛不才逢聖世，偶將疎網罩羣英。", "衰翁漸老兒孫小，異日知誰略有情。"]'),
('948b988f-b7b3-428a-b6a4-d5f9bac17dc5','過平戎谷弔胡翽','王仁裕','唐','唐诗','tang','','[]','立馬荒郊滿目愁，伊人何罪死林丘。',64,'全唐诗/poet.tang.41000.json','["立馬荒郊滿目愁，伊人何罪死林丘。", "風號古木悲長在，雨濕寒莎淚暗流。", "莫道文章爲衆嫉，只應輕薄是身讐。", "不緣魂寄孤山下，此地堪名鸚鵡洲。"]'),
('593d8f0a-774f-45c2-a38c-1593144c1d5a','奉詔賦劒州途中鷙獸','王仁裕','唐','唐诗','tang','','[]','劒牙釘舌血毛腥，窺算勞心豈暫停。',64,'全唐诗/poet.tang.41000.json','["劒牙釘舌血毛腥，窺算勞心豈暫停。", "不與大朝除患難，惟餘當路食生靈。", "從將戶口資嚵口，未委三丁稅幾丁。", "今日帝王親出狩，白雲巖下好藏形。"]'),
('85683f0a-98d9-472c-9988-7fbd46cd61ed','放猿','王仁裕','唐','唐诗','tang','','[]','放爾丁寧復故林，舊來行處好追尋。',64,'全唐诗/poet.tang.41000.json','["放爾丁寧復故林，舊來行處好追尋。", "月明巫峽堪憐靜，路隔巴山莫厭深。", "棲宿免勞青嶂夢，躋攀應愜白雲心。", "三秋果熟松梢健，任抱高枝徹曉吟。"]'),
('43d1a72b-348f-4231-b98a-c9b03ffdeba8','遇放猿再作','王仁裕','唐','唐诗','tang','','[]','嶓冢祠前漢水濱，飲猿連臂下嶙峋。',64,'全唐诗/poet.tang.41000.json','["嶓冢祠前漢水濱，飲猿連臂下嶙峋。", "漸來子細窺行客，認得依稀是野賓。", "月宿從勞羈絏夢，松餐非復稻粱身。", "數聲腸斷和雲呌，識是前時舊主人。"]'),
('d6cb87a3-68af-48b3-921a-dca670fd2d9a','句','王仁裕','唐','唐诗','tang','','[]','鐵鎖寨門扃白日，大張旗幟插青天。',16,'全唐诗/poet.tang.41000.json','["鐵鎖寨門扃白日，大張旗幟插青天。"]'),
('0fd804ba-2f5d-4176-a481-1f63620452f3','天道','馮道','唐','唐诗','tang','','["\u54f2\u7406"]','窮達皆由命，何勞發歎聲。',48,'全唐诗/poet.tang.41000.json','["窮達皆由命，何勞發歎聲。", "但知行好事，莫要問前程。", "冬去冰須泮，春來草自生。", "請君觀此理，天道甚分明。"]'),
('505ac72c-43b4-4a40-a307-3e26980c6789','偶作','馮道','唐','唐诗','tang','','[]','莫爲危時便愴神，前程往往有期因。',64,'全唐诗/poet.tang.41000.json','["莫爲危時便愴神，前程往往有期因。", "須知海嶽歸明主，未必乾坤陷吉人。", "道德幾時曾去世，舟車何處不通津？", "但教方寸無諸惡，狼虎叢中也立身。"]'),
('3f02b511-c2d6-492c-87bb-d5e3d44170c0','北使還京作','馮道','唐','唐诗','tang','','[]','去年今日奉皇華，只爲朝廷不爲家。',64,'全唐诗/poet.tang.41000.json','["去年今日奉皇華，只爲朝廷不爲家。", "殿上一杯天子泣，門前雙節國人嗟。", "龍荒冬往時時雪，兔苑春歸處處花。", "上下一行如骨肉，幾人身死掩風沙。"]'),
('a43fae35-3168-4909-aa05-9c7342e1169c','贈竇十','馮道','唐','唐诗','tang','','[]','燕山竇十郎，教子有義方。',24,'全唐诗/poet.tang.41000.json','["燕山竇十郎，教子有義方。", "靈椿一株老，丹桂五枝芳。"]'),
('635822c3-e7b0-4ef8-95bf-b0aa2bb092f4','放魚書所鑰戶','馮道','唐','唐诗','tang','','[]','高卻垣牆鑰却門，監丞從此罷垂綸。',32,'全唐诗/poet.tang.41000.json','["高卻垣牆鑰却門，監丞從此罷垂綸。", "池中魚鱉應相賀，從此方知有主人。"]'),
('6231bb7f-5249-4221-b07c-7ee2639bb836','句','馮道','唐','唐诗','tang','','[]','朝披四襖專藏手，夜覆三衾怕露頭。',60,'全唐诗/poet.tang.41000.json','["朝披四襖專藏手，夜覆三衾怕露頭。", "牛頭偏得賜，象笏更容持。", "已落地花方遣埽，未經霜草莫教鋤。", "視草北來唐學士，擁旄西去漢將軍。"]'),
('e3db7e75-942e-4c0b-825e-2e2e5b8d7228','後唐宗廟樂舞辭','盧文紀','唐','唐诗','tang','','[]','仁君御宇，環海謐清。',40,'全唐诗/poet.tang.41000.json','["仁君御宇，環海謐清。", "運符武德，道協文明。", "九成式敍，百度惟成。", "金門積慶，玉葉傳榮。"]'),
('a28ed34d-c456-4d7b-826b-17a56bf62763','後唐宗廟樂舞辭','崔居儉','唐','唐诗','tang','','[]','艱難王業，返正皇唐。',40,'全唐诗/poet.tang.41000.json','["艱難王業，返正皇唐。", "先天在造，却日重光。", "漢紹世祖，夏資少康。", "功成德茂，率祀無疆。"]'),
('0d0c1e3d-f33b-4a0e-aeed-8d1b8417141e','春社從李昉乞酒','李濤','唐','唐诗','tang','','[]','社公今日沒心情，爲乞治聾酒一瓶。',32,'全唐诗/poet.tang.41000.json','["社公今日沒心情，爲乞治聾酒一瓶。", "惱亂玉堂將欲徧，依稀巡到第三廳。"]'),
('7ec66820-1403-4d24-aaa1-52cbca88ab14','句','李濤','唐','唐诗','tang','','[]','溪聲長在耳，山色不離門。',40,'全唐诗/poet.tang.41000.json','["溪聲長在耳，山色不離門。", "掃地樹留影，拂妝琴有聲。", "一言寤主寧復聽，三諫不從歸去來。"]'),
('8f9043ab-563f-43fa-adf1-e7a2e5767c1d','靈溪老松歌','盧士衡','唐','唐诗','tang','','[]','靈溪古觀壇西角，千尺鱗皴棟梁樸。',98,'全唐诗/poet.tang.41000.json','["靈溪古觀壇西角，千尺鱗皴棟梁樸。", "橫出一枝戛樓閣，直上一枝掃寥廊。", "白石蒼苔擁根脚，月明風憾寒光落。", "有時風雨晦瞑，擺撼若黑龍之騰躍。", "合生於象外峰巒，枉滯乎人間山岳。", "安得巨靈受請託，拔向青桂白榆邊安著。"]'),
('184d43de-20af-46d2-b72b-46f6cb30fb95','遊靈溪觀','盧士衡','唐','唐诗','tang','','[]','雲藏寶殿風塵外，粉壁松軒入看初。',64,'全唐诗/poet.tang.41000.json','["雲藏寶殿風塵外，粉壁松軒入看初。", "話久仙童顏色老，病來玄鶴羽毛疎。", "樵翁接引尋紅朮，道士留連說紫書。", "不爲壯心降未得，便堪從此翫清虛。"]'),
('baec7927-fed9-4872-ad3a-4d4b6096577a','寄天台道友','盧士衡','唐','唐诗','tang','','[]','相思遙指玉霄峰，悵望江上阻萬重。',64,'全唐诗/poet.tang.41000.json','["相思遙指玉霄峰，悵望江上阻萬重。", "曾隔曉窗聞法鼓，幾同寒榻聽疎鐘。", "別來知子長餐栢，吟處將誰對倚松。", "且住人間行聖教，莫思天路便登龍。"]'),
('9acd27f7-5796-47a9-80f8-e7f1e05c527e','花落','盧士衡','唐','唐诗','tang','','[]','迎風嘯未已，和雨落穀穀。',24,'全唐诗/poet.tang.41000.json','["迎風嘯未已，和雨落穀穀。", "千枝與萬枝，不如一竿竹。"]'),
('7cf5a7bf-abd6-4eb7-8902-dfbfb183c805','鍾陵鐵柱','盧士衡','唐','唐诗','tang','','[]','千年埋沒竟何爲，變化宜將萬物齊。',32,'全唐诗/poet.tang.41000.json','["千年埋沒竟何爲，變化宜將萬物齊。", "安得風胡借方便，鑄成神劍斬鯨鯢。"]'),
('5361e2a1-f1ca-4504-a291-2729e41f0cd8','僧房聽雨','盧士衡','唐','唐诗','tang','','[]','古寺松軒雨聲別，寒窗聽久詩魔發。',32,'全唐诗/poet.tang.41000.json','["古寺松軒雨聲別，寒窗聽久詩魔發。", "記得年前在赤城，石樓夢覺三更雪。"]'),
('61aae385-73c7-4b84-aa32-1e6135092019','題牡丹','盧士衡','唐','唐诗','tang','','[]','萬葉紅綃翦盡春，丹青任寫不如真。',32,'全唐诗/poet.tang.41000.json','["萬葉紅綃翦盡春，丹青任寫不如真。", "風光九十無多日，難惜尊前折贈人。"]'),
('0c394d83-0ccf-418d-a866-c08c9812fd03','祖龍詞','熊皦','唐','唐诗','tang','','[]','平吞六國更何求，童女童男問十洲。',32,'全唐诗/poet.tang.41000.json','["平吞六國更何求，童女童男問十洲。", "滄海不回應悵望，始知徐福解風流。"]'),
('c5c57820-2eb2-4e68-a513-ab011781c5bd','謫居海上','熊皦','唐','唐诗','tang','','[]','家臨涇水隔秦川，來往關河路八千。',32,'全唐诗/poet.tang.41000.json','["家臨涇水隔秦川，來往關河路八千。", "堪恨此身何處老，始皇橋畔又經年。"]'),
('ea237aed-c64d-49fb-92d3-ffea84ecfb66','冬日原居酬光上人見訪','熊皎','唐','唐诗','tang','','[]','吾道喪已久，吾師何此來。',48,'全唐诗/poet.tang.41000.json','["吾道喪已久，吾師何此來。", "門無塵事閉，卷有國風開。", "野迥霜先白，庭荒葉自堆。", "寒暄吟罷後，猶喜話天台。"]'),
('aef3983c-9c07-430f-8187-b74fc5308071','早梅','熊皎','唐','唐诗','tang','','[]','江南近臘時，已亞雪中枝。',48,'全唐诗/poet.tang.41000.json','["江南近臘時，已亞雪中枝。", "一夜欲開盡，百花猶未知。", "人情皆共惜，天意欲教遲。", "莫訝無濃豔，芳筵正好吹。"]'),
('38949be4-e4e7-4cfe-a7d9-ced3e13d64f1','懷三茅道友','熊皎','唐','唐诗','tang','','[]','塵事何年解客嘲，十年容易到三茅。',64,'全唐诗/poet.tang.41000.json','["塵事何年解客嘲，十年容易到三茅。", "長思碧洞雲窗下，曾借黃庭雪夜抄。", "丹桂有心憑至論，五峰無信問深交。", "杏壇仙侶應相笑，只爲浮名未肯拋。"]'),
('58468d96-fd17-4b47-9be1-a0ec543d3260','贈胥尊師','熊皎','唐','唐诗','tang','','[]','綠髮童顏羽服輕，天台王屋幾經行。',64,'全唐诗/poet.tang.41000.json','["綠髮童顏羽服輕，天台王屋幾經行。", "雲程去速因風起，酒債還遲待藥成。", "房閉十洲煙浪闊，籙開三洞鬼神驚。", "他年華表重歸日，却恐桑田已變更。"]'),
('77f44d17-757d-4cd0-a382-0b331dc5ba6d','句','熊皎','唐','唐诗','tang','','[]','山前猶見月，陌上未逢人。',72,'全唐诗/poet.tang.41000.json','["山前猶見月，陌上未逢人。", "果熟秋先落，禽寒夜未棲。", "深逢野草皆爲藥，靜見樵人恐是仙。", "厭聽啼鳥夢醒後，慵掃落花春盡時。", "廢土有人耕不畏，古廳無訟醉何妨。"]'),
('fabc9d62-2962-4109-98ef-bf118fdbec83','塞上','趙延壽','唐','唐诗','tang','','[]','黃沙風捲半空拋，雲動陰山雪滿郊。',64,'全唐诗/poet.tang.41000.json','["黃沙風捲半空拋，雲動陰山雪滿郊。", "探水人迴移帳就，射鵰箭落著弓抄。", "鳥逢霜果飢還啄，馬渡冰河渴自跑。", "占得高原肥草地，夜深生火折林梢。"]'),
('c86b476a-a2eb-48d2-9d38-e7ca3feecee1','棊','高輦','唐','唐诗','tang','','[]','野客圍棊坐，搘頤向暮秋。',48,'全唐诗/poet.tang.41000.json','["野客圍棊坐，搘頤向暮秋。", "不言如守默，設計似平讎。", "決勝雖關勇，防危亦合憂。", "看他終一局，白却少年頭。"]'),
('fa7150bd-a04c-4c5a-8cf3-ddf15f46e06d','句','高輦','唐','唐诗','tang','','[]','飄飄送下遙天雪，颯颯吹乾旅舍煙。',16,'全唐诗/poet.tang.41000.json','["飄飄送下遙天雪，颯颯吹乾旅舍煙。"]'),
('10fe3de9-955a-44b1-821d-db985760aa67','與李專美','韓昭裔','唐','唐诗','tang','','[]','昭裔登庸汝未登，鳳池雞樹冷如冰。',32,'全唐诗/poet.tang.41000.json','["昭裔登庸汝未登，鳳池雞樹冷如冰。", "何如且作宣徽使，免被人呼粥飯僧。"]'),
('b07716a7-b91e-4ad5-9535-c4fc092dc942','題龍窩洞','張仁溥','唐','唐诗','tang','','[]','折花攜酒看龍窩，鏤玉長旌俊彥過。',32,'全唐诗/poet.tang.41000.json','["折花攜酒看龍窩，鏤玉長旌俊彥過。", "他日各爲雲外客，碧紗籠却又如何。"]'),
('1960aeb8-32c0-466c-8bde-13f47a109947','留題座主和凝舊閣','李瀚','唐','唐诗','tang','','[]','座主登庸歸鳳闕，門生批詔立鰲頭。',32,'全唐诗/poet.tang.41000.json','["座主登庸歸鳳闕，門生批詔立鰲頭。", "玉堂舊閣多珍玩，可作西齋潤筆不。"]'),
('2e57a59e-22e9-412c-9718-c7466335d25b','題家園','楊昭儉','唐','唐诗','tang','','[]','池蓮憔悴無顏色，園竹低垂減翠陰。',32,'全唐诗/poet.tang.41000.json','["池蓮憔悴無顏色，園竹低垂減翠陰。", "園竹池蓮莫惆悵，相看恰似主人心。"]'),
('a6ef29f9-e836-4464-9614-aa5165787f8c','書從事廳屏上','劉坦','唐','唐诗','tang','','[]','金殿試迴新折桂，將軍留辟向江城。',32,'全唐诗/poet.tang.41000.json','["金殿試迴新折桂，將軍留辟向江城。", "思量一醉猶難得，辜負揚州管記名。"]'),
('1b7d057e-678d-43e0-8e83-2d1d74c04a9d','題施璘畫竹圖','韋遵','唐','唐诗','tang','','[]','枯籜危根繳石頭，千竿交映近清流。',32,'全唐诗/poet.tang.41000.json','["枯籜危根繳石頭，千竿交映近清流。", "堪珍仲寶窮幽筆，留得荆湘一片秋。"]'),
('3b1cf8d0-62d6-4166-a330-44cc2ec51025','陪遊鳳皇臺獻詩','宋齊丘','唐','唐诗','tang','','[]','嵯峨壓洪泉，岝峉撐碧落。',288,'全唐诗/poet.tang.41000.json','["嵯峨壓洪泉，岝峉撐碧落。", "宜哉秦始皇，不驅亦不鑿。", "上有布政臺，八顧背城郭。", "山蹙龍虎健，水黑螭蜃作。", "白虹欲吞人，赤驥相𤍿㩧。", "畫棟泥金碧，石路盤墝埆。", "倒挂哭月猿，危立思天鶴。", "鑿池養蛟龍，栽桐棲鸑鷟。", "梁間燕教雛，石罅蛇懸殼。", "養花如養賢，去草如去惡。", "日晚嚴城鼓，風來蕭寺鐸。", "掃地驅塵埃，翦蒿除鳥雀。", "金桃帶葉摘，綠李和衣嚼。", "貞竹無盛衰，媚柳先搖落。", "塵飛景陽井，草合臨春閣。", "芙蓉如佳人，迴首似調謔。", "當軒有直道，無人肯駐脚。", "夜半鼠窸窣，天陰鬼敲啄。", "松孤不易立，石醜難安著。", "自憐啄木鳥，去蠹終不錯。", "晚風吹梧桐，樹頭鳴嚗嚗。", "峨峨江令石，青苔何淡薄。", "不話興亡事，舉首思眇邈。", "吁哉未到此，褊劣同尺蠖。"]'),
('06e90fad-906e-46d3-8487-bf00cda8d6ca','贈仰山慧度禪師','宋齊丘','唐','唐诗','tang','','[]','初聞如自解，及見勝初聞。',48,'全唐诗/poet.tang.41000.json','["初聞如自解，及見勝初聞。", "兩鬢堆殘雪，一身披斷雲。", "道應齊古佛，高不揖吾君。", "稽首清涼月，蕭然萬象分。"]'),
('08f6ae6f-be3d-4d11-88c0-456ac5f203c3','陪華林園試小妓羯鼓','宋齊丘','唐','唐诗','tang','','[]','切斷牙牀鏤紫金，最宜平穩玉槽深。',64,'全唐诗/poet.tang.41000.json','["切斷牙牀鏤紫金，最宜平穩玉槽深。", "因逢淑景開佳宴，爲出花奴奏雅音。", "掌底輕璁孤鵲噪，枝頭乾快亂蟬吟。", "開元天子曾如此，今日將軍好用心。"]'),
('3c07e1dd-a16e-432b-816e-5becb1557d30','句','宋齊丘','唐','唐诗','tang','','[]','大似賢臣扶社稷，遇明則見暗還藏。',16,'全唐诗/poet.tang.41000.json','["大似賢臣扶社稷，遇明則見暗還藏。"]'),
('22c53cbd-efbc-4f7e-9ddd-5aa173459759','早朝','馮延巳','唐','唐诗','tang','','[]','銅壺滴漏初晝，高閣雞鳴半空。',70,'全唐诗/poet.tang.41000.json','["銅壺滴漏初晝，高閣雞鳴半空。", "催啓五門金鎖，猶垂三殿簾櫳。", "階前御柳搖綠，仗下宮花散紅。", "鴛瓦數行曉日，鸞旗百尺春風。", "侍臣踏舞重拜，聖壽南山永同。"]'),
('814d881b-1203-4732-8e9f-3aef2c2e2cf3','句','馮延巳','唐','唐诗','tang','','[]','青樓阿監應相笑，書記登壇又却回。',16,'全唐诗/poet.tang.41000.json','["青樓阿監應相笑，書記登壇又却回。"]'),
('2919e4ef-8da8-4185-ad9c-8bff0920eeeb','感懷詩二章 一','韓熙載','唐','唐诗','tang','','[]','僕本江北人，今作江南客。',48,'全唐诗/poet.tang.41000.json','["僕本江北人，今作江南客。", "再去江北遊，舉目無相識。", "金風吹我寒，秋月爲誰白。", "不如歸去來，江南有人憶。"]'),
('b707000e-1430-4cea-8954-7c5122e00bf2','感懷詩二章 二','韓熙載','唐','唐诗','tang','','[]','未到故鄉時，將爲故鄉好。',88,'全唐诗/poet.tang.41000.json','["未到故鄉時，將爲故鄉好。", "及至親得歸，爭如身不到。", "目前相識無一人，出入空傷我懷抱。", "風雨蕭蕭旅館秋，歸來窗下和衣倒。", "夢中忽到江南路，尋得花邊舊居處。", "桃臉蛾眉笑出門，爭向前頭擁將去。"]'),
('156f1bd4-e618-4f41-b1ab-2b1a419ca8a2','溧水無相寺贈僧','韓熙載','唐','唐诗','tang','','[]','無相景幽遠，山屏四面開。',48,'全唐诗/poet.tang.41000.json','["無相景幽遠，山屏四面開。", "憑師領鶴去，待我挂冠來。", "藥爲依時採，松宜繞舍栽。", "林泉自多興，不是效劉雷。"]'),
('883fd778-5607-4cf5-bbad-2cf9ec2b0118','書歌妓泥金帶','韓熙載','唐','唐诗','tang','','[]','風柳搖搖無定枝，陽臺雲雨夢中歸。',32,'全唐诗/poet.tang.41000.json','["風柳搖搖無定枝，陽臺雲雨夢中歸。", "他年蓬島音塵斷，留取尊前舊舞衣。"]'),
('18f70208-5a28-4c02-b8ef-0cb1dda12c13','送徐鉉流舒州','韓熙載','唐','唐诗','tang','','[]','昔年悽斷此江湄，風滿征帆淚滿衣。',32,'全唐诗/poet.tang.41000.json','["昔年悽斷此江湄，風滿征帆淚滿衣。", "今日重憐鶺鴒羽，不堪波上又分飛。"]'),
('61b362b1-0dbe-4571-9b58-e179b9cfd7ec','句','韓熙載','唐','唐诗','tang','','[]','幾人平地上，看我半天中。',12,'全唐诗/poet.tang.41000.json','["幾人平地上，看我半天中。"]'),
('0d041545-4f66-490b-8099-44aa8a820e8c','登祝融峰','李徵古','唐','唐诗','tang','','[]','欲上祝融峰，先登古石橋。',24,'全唐诗/poet.tang.41000.json','["欲上祝融峰，先登古石橋。", "鑿開巇嶮處，取路到丹霄。"]'),
('fc3267e5-7cae-484d-beef-796a19bcefbb','七歲吟','潘佑','唐','唐诗','tang','','[]','朝遊滄海東，暮歸何太速。',28,'全唐诗/poet.tang.41000.json','["朝遊滄海東，暮歸何太速。", "祗因騎折白龍腰，謫向人間三十六。"]'),
('f46dcbe8-c58a-446e-8082-fcdcffe727ad','送許處士堅往茅山','潘佑','唐','唐诗','tang','','[]','天壇雲似雪，玉洞水如琴。',48,'全唐诗/poet.tang.41000.json','["天壇雲似雪，玉洞水如琴。", "白雲與流水，千載清人心。", "君攜布囊去，路長風滿林。", "一入華陽洞，千秋那可尋。"]'),
('54d8ab7a-622e-4dbb-9cb5-5159d4497fce','送人往宣城','潘佑','唐','唐诗','tang','','[]','江畔送行人，千山生暮氛。',24,'全唐诗/poet.tang.41000.json','["江畔送行人，千山生暮氛。", "謝安團扇上，爲畫敬亭雲。"]'),
('949fa54d-0f8e-46fb-9194-b42dbc1811f7','失題','潘佑','唐','唐诗','tang','','[]','誰家舊宅春無主，深院簾垂杏花雨。',32,'全唐诗/poet.tang.41000.json','["誰家舊宅春無主，深院簾垂杏花雨。", "香飛綠瑣人未歸，巢燕承塵默無語。"]'),
('2caf0313-abe1-4ec1-acd0-c02009f0dcb2','句','潘佑','唐','唐诗','tang','','[]','勸君此醉直須歡，明朝又是花狼藉。',16,'全唐诗/poet.tang.41000.json','["勸君此醉直須歡，明朝又是花狼藉。"]'),
('99583e4b-a4a3-4498-8768-6d2edd91bd68','寄孟賓于','李昉','唐','唐诗','tang','','[]','初攜書劒別湘潭，金榜標名第十三。',64,'全唐诗/poet.tang.41000.json','["初攜書劒別湘潭，金榜標名第十三。", "昔日聲名喧洛下，近來詩價滿江南。", "長爲邑令情終屈，縱處曹郎志未甘。", "莫學馮唐便休去，明君晚事未爲慚。"]'),
('dd7eb14d-cb20-4aa1-82fc-b9944057863b','送孟賓于','馬致恭','唐','唐诗','tang','','[]','曾聞洛下綴神仙，火樹南棲幾十年。',64,'全唐诗/poet.tang.41000.json','["曾聞洛下綴神仙，火樹南棲幾十年。", "白首自忻丹桂在，詩名已得四方傳。", "行隨秋渚將歸雁，吟傍梅花欲雪天。", "今日還家莫惆悵，不同初上渡頭船。"]'),
('a0e56e1e-22a7-4afa-8f2b-9da47aff3e0e','奉和聖製元日大雪登樓','張義方','唐','唐诗','tang','','[]','恰當歲日紛紛落，天寶瑤花助物華。',64,'全唐诗/poet.tang.41000.json','["恰當歲日紛紛落，天寶瑤花助物華。", "自古最先標瑞牒，有誰輕擬比楊花。", "密飄粉署光同冷，靜壓青松勢欲斜。", "豈但小臣添興詠，狂歌醉舞一家家。"]'),
('46e5a98d-f8ae-4b5a-8fed-ee9651d6f57a','中酒寄劉行軍','李建勳','唐','唐诗','tang','','[]','甚矣頻頻醉，神昏體亦虛。',48,'全唐诗/poet.tang.41000.json','["甚矣頻頻醉，神昏體亦虛。", "肺傷徒問藥，髮落不盈梳。", "戀寢嫌明室，修生媿道書。", "西峯老僧語，相勸合何如。"]'),
('430c58cd-8ce9-45e6-b188-27c66665bef4','白雁','李建勳','唐','唐诗','tang','','[]','東溪一白雁，毛羽何皎潔。',72,'全唐诗/poet.tang.41000.json','["東溪一白雁，毛羽何皎潔。", "薄暮浴清波，斜陽共明滅。", "差池失羣久，幽獨依人切。", "旅食賴菰蒲，單棲怯霜雪。", "邊風昨夜起，顧影空哀咽。", "不及牆上烏，相將繞雙闕。"]'),
('50795a4e-7de6-4bf7-9d23-bdba4df0353e','早春寄懷','李建勳','唐','唐诗','tang','','[]','家山歸未得，又是看春過。',48,'全唐诗/poet.tang.41000.json','["家山歸未得，又是看春過。", "老覺光陰速，閑悲世路多。", "風和吹岸柳，雪盡見庭莎。", "欲向東溪醉，狂眠一放歌。"]'),
('d848298e-f251-4ff7-9613-d7bc3da5490d','春日東山正堂作','李建勳','唐','唐诗','tang','','[]','身閑贏得出，天氣漸暄和。',48,'全唐诗/poet.tang.41000.json','["身閑贏得出，天氣漸暄和。", "蜀馬登山穩，南朝古寺多。", "早花微弄色，新酒欲生波。", "從此唯行樂，閑愁奈我何。"]'),
('10de17d0-7021-438f-9009-40f766eadfe3','春日小園晨看兼招同舍','李建勳','唐','唐诗','tang','','[]','最有杏花繁，枝枝若手摶。',48,'全唐诗/poet.tang.41000.json','["最有杏花繁，枝枝若手摶。", "須知一春促，莫厭百迴看。", "鳥囀風潛息，蜂遲露未乾。", "可容排飲否，兼折贈頭冠。"]'),
('daaff867-cd1e-4616-a2df-5edcc90ed68f','惜花寄孫員外','李建勳','唐','唐诗','tang','','[]','朝始一枝開，暮復一枝落。',56,'全唐诗/poet.tang.41000.json','["朝始一枝開，暮復一枝落。", "只恐雨淋漓，又見春蕭索。", "侵晨結駟攜酒徒，尋芳踏盡長安衢。", "思量少壯不自樂，他日白頭空歎吁。"]'),
('eab45f3a-d018-4ecb-8d18-532640c1ceca','春日病中','李建勳','唐','唐诗','tang','','[]','纔得歸閑去，還教病臥頻。',48,'全唐诗/poet.tang.41000.json','["纔得歸閑去，還教病臥頻。", "無由全勝意，終是負青春。", "綠柳漸拂地，黃鶯如喚人。", "方爲醫者勸，斷酒已經旬。"]'),
('fef28786-86fb-443d-b3f2-2700a8d625cb','毆妓','李建勳','唐','唐诗','tang','','[]','自爲專房甚，怱怱有所傷。',48,'全唐诗/poet.tang.41000.json','["自爲專房甚，怱怱有所傷。", "當時心已悔，徹夜手猶香。", "恨枕堆雲髻，啼襟揾月黃。", "起來猶忍惡，剪破繡鴛鴦。"]'),
('d41799d3-50e1-4067-be68-84cb21afaab6','踏青罇前','李建勳','唐','唐诗','tang','','[]','期君速行樂，不要旋還家。',48,'全唐诗/poet.tang.41000.json','["期君速行樂，不要旋還家。", "永日雖無雨，東風自落花。", "詩毫黏酒淡，歌袖向人斜。", "薄暮忘歸路，垂楊噪亂鵶。"]'),
('0a8fb253-5414-42a3-acd5-3e9ef673286d','正月晦日','李建勳','唐','唐诗','tang','','[]','莫倦尋春去，都無百日遊。',48,'全唐诗/poet.tang.41000.json','["莫倦尋春去，都無百日遊。", "更堪正月過，已是一分休。", "泉暖聲纔出，雲寒勢未收。", "晚來重作雪，翻爲杏花愁。"]'),
('1b64961c-38ee-45bc-8903-ffaef335fb89','惜花','李建勳','唐','唐诗','tang','','[]','白髮今如此，紅芳莫更催。',48,'全唐诗/poet.tang.41000.json','["白髮今如此，紅芳莫更催。", "預愁多日謝，翻怕十分開。", "點滴無時雨，荒涼滿地苔。", "閑堦一桮酒，惟待故人來。"]'),
('6858d85e-df5a-4d83-9332-61794820725a','金谷園落花','李建勳','唐','唐诗','tang','','[]','愁見清明後，紛紛蓋地紅。',48,'全唐诗/poet.tang.41000.json','["愁見清明後，紛紛蓋地紅。", "惜看難過日，自落不因風。", "蝶散餘香在，鶯啼半樹空。", "堪悲一尊酒，從此似西東。"]'),
('dd13e8d5-fced-41b5-bbe1-1d5660aee5fb','柳花寄宋明府','李建勳','唐','唐诗','tang','','[]','每愛江城裏，青春向盡時。',48,'全唐诗/poet.tang.41000.json','["每愛江城裏，青春向盡時。", "一迴新雨歇，是處好風吹。", "破石黏蟲網，高樓撲酒旗。", "遙知陶令宅，五樹正離披。"]'),
('1c3385b1-ff12-4c71-b7b8-84b2593a1299','送人','李建勳','唐','唐诗','tang','','[]','相見未逾月，堪悲遠別離。',48,'全唐诗/poet.tang.41000.json','["相見未逾月，堪悲遠別離。", "非君誰顧我，萬里又南之。", "雨逼清明日，花陰杜宇時。", "愁看挂帆處，鷗鳥共遲遲。"]'),
('d0b3ccc2-bfff-4e19-9a0a-bb0030f6546c','閑遊','李建勳','唐','唐诗','tang','','[]','攜酒復攜觴，朝朝一似忙。',48,'全唐诗/poet.tang.41000.json','["攜酒復攜觴，朝朝一似忙。", "馬諳頻到路，僧借舊眠牀。", "道勝他圖薄，身閑白日長。", "扁舟動歸思，高處見滄浪。"]'),
('e80f32a4-ebf5-4ab0-afcf-b09e159a2ebd','栢梁隔句韻詩','李建勳','唐','唐诗','tang','','[]','不喜長亭柳，枝枝擬送君。',48,'全唐诗/poet.tang.41000.json','["不喜長亭柳，枝枝擬送君。", "惟憐北窗□，樹樹解留人。", "圓缺都如月，東西只似雲。", "愁看離席散，歸蓋動行塵。"]'),
('a8c014ad-5e4f-47c9-9a80-3ac7320c79be','贈趙學士','李建勳','唐','唐诗','tang','','[]','常欽趙夫子，遠作五侯賓。',48,'全唐诗/poet.tang.41000.json','["常欽趙夫子，遠作五侯賓。", "見面到今日，操心如古人。", "醉同華席少，吟訪野僧頻。", "寂寂長河畔，荒齋與廟隣。"]'),
('e216b0f6-abd9-48f6-bb92-547a6c142b0b','春陰','李建勳','唐','唐诗','tang','','[]','老雨不肯休，東風勢還作。',48,'全唐诗/poet.tang.41000.json','["老雨不肯休，東風勢還作。", "未放草蒙茸，已遣花蕭索。", "浮生何苦勞，觸事妨行樂。", "寄語達生人，須知酒勝藥。"]'),
('96eea1d5-da49-46fc-9f8b-2b729959e72f','春日金谷園','李建勳','唐','唐诗','tang','','[]','火急召親賓，歡遊莫厭頻。',48,'全唐诗/poet.tang.41000.json','["火急召親賓，歡遊莫厭頻。", "日長徒似歲，花過即非春。", "晚雨來何定，東風自不勻。", "須知三箇月，不是負芳晨。"]'),
('dac0699b-eeca-4e71-8001-80d7ba4e9106','夏日酬祥松二公見訪','李建勳','唐','唐诗','tang','','[]','多謝空門客，時時出草堂。',48,'全唐诗/poet.tang.41000.json','["多謝空門客，時時出草堂。", "從容非有約，淡薄不相忘。", "池映春篁老，簷垂夏果香。", "西峯正清霽，自與拂吟牀。"]'),
('211bc9e5-75b6-4da9-be84-45521d0bd47a','懷贈操禪師','李建勳','唐','唐诗','tang','','[]','嘗憶曹溪子，龕居面碧嵩。',48,'全唐诗/poet.tang.41000.json','["嘗憶曹溪子，龕居面碧嵩。", "杉松新夏後，雨雹夜禪中。", "道匪因經悟，心能向物空。", "秋來得音信，又在剡山東。"]'),
('9c58422a-13e8-4a56-b139-d0f7c28c647a','閑居秋思呈祥松二字','李建勳','唐','唐诗','tang','','[]','秋光雖即好，客思轉悠哉。',48,'全唐诗/poet.tang.41000.json','["秋光雖即好，客思轉悠哉。", "去國身將老，流年雁又來。", "葉紅堆晚徑，菊冷藉空罍。", "不得師相訪，難將道自開。"]'),
('d4ac580a-af1f-48ba-bada-f4cb33428560','賦得冬日青溪草堂四十字','李建勳','唐','唐诗','tang','','[]','莫道無幽致，常來到日西。',48,'全唐诗/poet.tang.41000.json','["莫道無幽致，常來到日西。", "地雖當北闕，天與設東溪。", "疎葦寒多折，驚鳧去不齊。", "坐中皆作者，長愛覓分題。"]'),
('bf139b23-fe98-48b3-8b60-b12d7c4b3773','溪齋','李建勳','唐','唐诗','tang','','[]','水木遶吾廬，搴簾晚檻虛。',48,'全唐诗/poet.tang.41000.json','["水木遶吾廬，搴簾晚檻虛。", "衰條寒露鵲，幽果落驚魚。", "愛酒貧還甚，趨時老更疎。", "乖慵自有素，不是忽簪裾。"]'),
('b0030fc9-0c71-42c3-9d3b-221f155ba287','留題愛敬寺','李建勳','唐','唐诗','tang','','[]','野性竟未改，何以居朝廷。',48,'全唐诗/poet.tang.41000.json','["野性竟未改，何以居朝廷。", "空爲百官首，但愛千峯青。", "南風新雨後，與客攜觴行。", "斜陽惜歸去，萬壑啼鳥聲。"]'),
('7c043722-16b0-4de6-a3bd-68cd3a9c2a4f','小園','李建勳','唐','唐诗','tang','','[]','小園吾所好，栽植忘勞形。',48,'全唐诗/poet.tang.41000.json','["小園吾所好，栽植忘勞形。", "晚果經秋赤，寒蔬近社青。", "竹蘿荒引蔓，土井淺生萍。", "更欲從人勸，憑高置草亭。"]'),
('0f09e72a-fdd1-4e96-bee9-061ebe3396df','宿山房','李建勳','唐','唐诗','tang','','[]','石窗燈欲盡，松檻月還明。',48,'全唐诗/poet.tang.41000.json','["石窗燈欲盡，松檻月還明。", "就枕渾無睡，披衣却出行。", "巖高泉亂滴，林動鳥時驚。", "倏忽山鐘曙，喧喧僕馬聲。"]'),
('49241607-83c3-4d27-b8f1-eb65a63bdd6e','金陵所居青溪草堂閑興','李建勳','唐','唐诗','tang','','[]','窗外皆連水，杉松欲作林。',48,'全唐诗/poet.tang.41000.json','["窗外皆連水，杉松欲作林。", "自憐趨競地，獨有愛閑心。", "素壁題看遍，危冠醉不簪。", "江僧暮相訪，簾卷見秋岑。"]'),
('94af9972-9a17-4f27-993b-2556503f58fc','闕下偶書寄孫員外','李建勳','唐','唐诗','tang','','[]','長安驅馳地，貴賤共悠悠。',48,'全唐诗/poet.tang.41000.json','["長安驅馳地，貴賤共悠悠。", "白日誰相促，勞生自不休。", "鳳翔雙闕曉，蟬噪六街秋。", "獨有南宮客，時來話釣舟。"]'),
('cce7d01a-5e76-420a-9ed6-d50efcc8f651','寄魏郎中','李建勳','唐','唐诗','tang','','[]','碌碌但隨羣，蒿蘭任不分。',48,'全唐诗/poet.tang.41000.json','["碌碌但隨羣，蒿蘭任不分。", "未嘗矜有道，求遇向吾君。", "逸駕秋尋寺，長歌醉望雲。", "高齋紙屏古，塵暗北山文。"]'),
('5d737630-e386-4505-85f5-4b323a1d37c2','病中書懷寄王二十六','李建勳','唐','唐诗','tang','','[]','落葉滿山州，閑眠病未瘳。',48,'全唐诗/poet.tang.41000.json','["落葉滿山州，閑眠病未瘳。", "窗陰連竹枕，藥氣染茶甌。", "路匪人遮去，官須自覓休。", "焉宜更羸老，扶杖作公侯。"]'),
('d741e7d5-1b00-4480-bea0-6405f505950b','採菊','李建勳','唐','唐诗','tang','','[]','簇簇竟相鮮，一枝開幾番。',48,'全唐诗/poet.tang.41000.json','["簇簇竟相鮮，一枝開幾番。", "味甘資麴糵，香好勝蘭蓀。", "古道風搖遠，荒籬露壓繁。", "盈筐時採得，服餌近知門。"]'),
('fde2f140-5dcb-45b1-be3e-2c44525b74fa','送王郎中之官吉水','李建勳','唐','唐诗','tang','','[]','南望廬陵郡，山連五嶺長。',48,'全唐诗/poet.tang.41000.json','["南望廬陵郡，山連五嶺長。", "吾君憐遠俗，從事輟名郎。", "移戶多無土，春蠶不滿筐。", "惟應勞贊畫，溪峒況彊梁。"]'),
('395dfe8f-d365-4004-aa64-1a9ace4fe391','孤雁','李建勳','唐','唐诗','tang','','[]','欲食不敢食，合栖猶未栖。',48,'全唐诗/poet.tang.41000.json','["欲食不敢食，合栖猶未栖。", "聞風亦驚過，避繳恨飛低。", "水闊緣湘因，雲寒過磧迷。", "悲鳴感人意，不見夜烏啼。"]'),
('de2c988f-b1d7-4f6f-9941-360a899b75dc','贈送致仕郎中','李建勳','唐','唐诗','tang','','[]','鶴立瘦稜稜，髭長白似銀。',48,'全唐诗/poet.tang.41000.json','["鶴立瘦稜稜，髭長白似銀。", "衣冠皆古製，氣貌異常人。", "聽雪添詩思，看山滯酒巡。", "西峯重歸路，唯許野僧親。"]'),
('32d62146-5646-4252-ba15-854c9df4344e','宿友人山居寄司徒相公 一','李建勳','唐','唐诗','tang','','[]','雨雪正霏霏，令人不憶歸。',48,'全唐诗/poet.tang.41000.json','["雨雪正霏霏，令人不憶歸。", "地爐僧坐暖，山枿火聲肥。", "隔紙烘茶蘂，移鐺剝芋衣。", "知君在霄漢，此興得還稀。"]'),
('cd74f109-f401-4227-817a-f7dd923efc3f','宿友人山居寄司徒相公 二','李建勳','唐','唐诗','tang','','[]','郢客相尋夜，荒庭雪灑篙。',48,'全唐诗/poet.tang.41000.json','["郢客相尋夜，荒庭雪灑篙。", "虛堂看向曙，吟坐共忘勞。", "溪凍聲全減，燈寒焰不高。", "他人莫相笑，未易會吾曹。"]'),
('bcd224b0-89c8-4371-93cd-0c715002720e','感故府二首 一','李建勳','唐','唐诗','tang','','[]','戚戚復戚戚，期懷安可釋。',48,'全唐诗/poet.tang.41000.json','["戚戚復戚戚，期懷安可釋。", "百年金石心，中路生死隔。", "新墳應草合，舊地空苔色。", "白日燈熒熒，凝塵滿几席。"]'),
('02723ded-c993-41ed-bd0c-b8f559e9bda1','感故府二首 二','李建勳','唐','唐诗','tang','','[]','悒悒復悒悒，思君安可及。',48,'全唐诗/poet.tang.41000.json','["悒悒復悒悒，思君安可及。", "永日在堦前，披衣隨風立。", "高樓暮角斷，遠樹寒鴉集。", "惆悵幾行書，遺蹤墨猶濕。"]'),
('cc93d6a1-981e-409f-8652-cdfcb41e9783','田家三首 一','李建勳','唐','唐诗','tang','','[]','畢歲知無事，兵銷復舊丁。',48,'全唐诗/poet.tang.41000.json','["畢歲知無事，兵銷復舊丁。", "竹門桑徑狹，春日稻畦青。", "犬吠隈籬落，雞飛上碓桯。", "歸田起□思，蛙叫草冥冥。"]'),
('d678d3db-4821-4880-a373-85b3d19f5735','田家三首 二','李建勳','唐','唐诗','tang','','[]','不識城中路，熙熙樂有年。',48,'全唐诗/poet.tang.41000.json','["不識城中路，熙熙樂有年。", "木槃擎社酒，瓦鼓送神錢。", "霜落牛歸屋，禾收雀滿田。", "遙陂過秋水，閑閣釣魚船。"]'),
('649f46d0-c827-4fb0-942d-dec4c4840a67','田家三首 三','李建勳','唐','唐诗','tang','','[]','長愛田家事，時時欲一過。',48,'全唐诗/poet.tang.41000.json','["長愛田家事，時時欲一過。", "垣籬皆樹槿，廳院亦堆禾。", "病果因風落，寒蔬向日多。", "遙聞數聲笛，牛晚下前坡。"]'),
('ee6d7492-2367-4e5f-a3ad-1b7d81b6e765','新竹','李建勳','唐','唐诗','tang','','[]','嫋嫋薰風軟，娟娟湛露光。',96,'全唐诗/poet.tang.41000.json','["嫋嫋薰風軟，娟娟湛露光。", "參差仙子仗，迤邐羽林槍。", "迥去侵花地，斜來破蘚牆。", "籜乾猶抱翠，粉膩若塗裝。", "逕曲莖難數，陰疎葉未長。", "嬾嫌吟客倚，甘畏夏蟲傷。", "映水如爭立，當軒自著行。", "北庭尊酒興，還爲此君狂。"]'),
('f1fa8bf6-82b6-4c5b-9741-075c14f73e5a','歸燕詞','李建勳','唐','唐诗','tang','','[]','羽翼勢雖微，雲霄亦可期。',96,'全唐诗/poet.tang.41000.json','["羽翼勢雖微，雲霄亦可期。", "飛翻自有路，鴻鵠莫相嗤。", "待侶臨書幌，尋泥傍藻池。", "衝人穿柳徑，捕蝶遶花枝。", "廣廈來應徧，深宮去不疑。", "雕梁聲上下，煙浦影參差。", "舊地人潛換，新巢雀謾窺。", "雙雙暮歸處，疎雨滿江湄。"]'),
('885206a6-c0a5-4f13-8f78-327815ce2140','題魏壇二首 一','李建勳','唐','唐诗','tang','','[]','不遇至真傳道要，曾看真誥亦何爲。',64,'全唐诗/poet.tang.41000.json','["不遇至真傳道要，曾看真誥亦何爲。", "舊碑經亂沈荒澗，靈篆因耕出故基。", "蛙黽自喧澆藥井，牛羊閑過放生池。", "蕭條夕景空壇畔，朽檜枝斜綠蔓垂。"]'),
('3d28001d-793e-47ea-885c-371ec9145af5','題魏壇二首 二','李建勳','唐','唐诗','tang','','[]','一尋遺跡到仙鄉，雲鶴沈沈思渺茫。',64,'全唐诗/poet.tang.41000.json','["一尋遺跡到仙鄉，雲鶴沈沈思渺茫。", "丹井歲深生草木，芝田春廢臥牛羊。", "雨淋殘畫摧荒壁，鼠引飢虵落壞梁。", "薄暮欲歸仍佇立，菖蒲風起水泱泱。"]'),
('dbdfa90f-36bb-4661-bf03-c661bf6fbdd4','東樓看雪','李建勳','唐','唐诗','tang','','["\u5e90\u5c71"]','一上高樓醉復醒，日西江雪更冥冥。',64,'全唐诗/poet.tang.41000.json','["一上高樓醉復醒，日西江雪更冥冥。", "化風吹火全無氣，平望惟松少露青。", "臘內不妨南地少，夜長應得小窗聽。", "因思舊隱匡廬日，閑看杉檉掩石扃。"]'),
('b598b29c-4f70-435d-846c-5ad0f19efc4d','落花','李建勳','唐','唐诗','tang','','[]','惜花無計又花殘，獨遶芳叢不忍看。',64,'全唐诗/poet.tang.41000.json','["惜花無計又花殘，獨遶芳叢不忍看。", "暖豔動隨鶯翅落，冷香愁雜燕泥乾。", "綠珠倚檻魂初散，巫峽歸雲夢又闌。", "忍把一尊重命樂，送春招客亦何歡。"]'),
('63302b0f-792a-4dcc-bea7-6651839bb5a7','春雪','李建勳','唐','唐诗','tang','','[]','南國春寒朔氣迴，霏霏還阻百花開。',64,'全唐诗/poet.tang.41000.json','["南國春寒朔氣迴，霏霏還阻百花開。", "全移暖律何方去，似誤新鶯昨日來。", "平野旋銷難蔽草，遠林高綴却遮梅。", "不知金勒誰家子，只待晴明賞帝臺。"]'),
('2500ec18-5118-4c60-9d0e-827c27bc23dc','重戲和春雪寄沈員外','李建勳','唐','唐诗','tang','','[]','誰道江南要雪難，半春猶得倚樓看。',64,'全唐诗/poet.tang.41000.json','["誰道江南要雪難，半春猶得倚樓看。", "却遮遲日偷鶯暖，密灑西風借鶴寒。", "散漫不容梨豔去，輕明應笑玉華乾。", "和來瓊什雖無敵，且是儂家比興殘。"]'),
('63d2ce5a-3f52-4e25-b8c7-0b5c395a7b9b','春日尊前示從事','李建勳','唐','唐诗','tang','','[]','州中案牘魚鱗密，界上軍書竹節稠。',64,'全唐诗/poet.tang.41000.json','["州中案牘魚鱗密，界上軍書竹節稠。", "眼底好花渾似雪，甕頭春酒漫如油。", "東君不爲留遲日，清鏡唯知促白頭。", "最覺此春無氣味，不如庭草解忘憂。"]'),
('adf5c9f8-dd95-460e-a41f-af31d586d521','尊前','李建勳','唐','唐诗','tang','','[]','官爲將相復何求，世路多端早合休。',64,'全唐诗/poet.tang.41000.json','["官爲將相復何求，世路多端早合休。", "漸老更知春可惜，正歡唯怕客難留。", "雨催草色還依舊，晴放花枝始自由。", "莫厭百壺相勸倒，免教無事結閑愁。"]'),
('f85fe346-311e-4df1-9372-9ffde856db78','薔薇二首 一','李建勳','唐','唐诗','tang','','[]','萬蘂爭開照檻光，詩家何物可相方。',64,'全唐诗/poet.tang.41000.json','["萬蘂爭開照檻光，詩家何物可相方。", "錦江風撼雲霞碎，仙子衣飄黼黻香。", "裛露早英濃壓架，背人狂蔓暗穿牆。", "綵牋蠻榼旬休日，欲召親賓看一場。"]'),
('eeed933b-535b-4678-873e-950374568c82','薔薇二首 二','李建勳','唐','唐诗','tang','','[]','拂簷拖地對前墀，蝶影蜂聲爛熳時。',64,'全唐诗/poet.tang.41000.json','["拂簷拖地對前墀，蝶影蜂聲爛熳時。", "萬倍馨香勝玉蘂，一生顏色笑西施。", "忘歸醉客臨高架，恃寵佳人索好枝。", "將並舞腰誰得及，惹衣傷手盡從伊。"]'),
('85a6623e-0b79-4396-9cf4-fdeb8f5589f3','殘牡丹','李建勳','唐','唐诗','tang','','[]','腸斷題詩如執別，芳茵愁更繞闌鋪。',64,'全唐诗/poet.tang.41000.json','["腸斷題詩如執別，芳茵愁更繞闌鋪。", "風飄金蘂看全落，露滴檀英又暫蘇。", "失意婕妤妝漸薄，背身妃子病難扶。", "迴看池館春休也，又是迢迢看畫圖。"]'),
('6f125e89-3225-4935-bcd7-3a27b3975b6a','春雨二首 一','李建勳','唐','唐诗','tang','','[]','春霖未免妨遊賞，唯到詩家自有情。',64,'全唐诗/poet.tang.41000.json','["春霖未免妨遊賞，唯到詩家自有情。", "花徑不通新草合，蘭舟初動曲池平。", "淨緣高樹莓苔色，飢集虛廊燕雀聲。", "閑憶昔年爲客處，悶留山館阻行行。"]'),
('6159a192-4c05-478b-804f-654ebb514aef','春雨二首 二','李建勳','唐','唐诗','tang','','[]','蕭蕭春雨密還疎，景象三時固不如。',64,'全唐诗/poet.tang.41000.json','["蕭蕭春雨密還疎，景象三時固不如。", "寒入遠林鶯翅重，暖抽新麥土膏虛。", "細濛臺榭微兼日，潛漲漣漪欲動魚。", "唯稱乖慵多睡者，掩門中酒覽閑書。"]'),
('26859c26-4330-4704-acaa-2961b2ff0f04','醉中惜花更書與諸從事','李建勳','唐','唐诗','tang','','[]','公退尋芳已是遲，莫因他事更來稀。',64,'全唐诗/poet.tang.41000.json','["公退尋芳已是遲，莫因他事更來稀。", "未經旬日唯憂落，算有開時不合歸。", "歌檻宴餘風褭褭，閑園吟散雨霏霏。", "高樓鼓絕重門閉，長爲拋迴恨解衣。"]'),
('5fba7a4e-5ee0-4ba6-bc7f-56a9570954b3','和判官喜雨','李建勳','唐','唐诗','tang','','[]','去禱山川尚未還，雲雷尋作遠聲寒。',64,'全唐诗/poet.tang.41000.json','["去禱山川尚未還，雲雷尋作遠聲寒。", "人情便似秋登悅，天色休勞夜起看。", "高檻氣濃藏柳郭，小庭流擁沒花壇。", "須知太守重牆內，心極農夫望處歡。"]'),
('f2448723-48a4-4953-8125-26010aa28a06','離闕下日感恩','李建勳','唐','唐诗','tang','','[]','二年塵冒處中台，喜得南歸退不才。',64,'全唐诗/poet.tang.41000.json','["二年塵冒處中台，喜得南歸退不才。", "即路敢期皇子送，出關猶有御書來。", "未知天地恩何報，翻對江山思莫開。", "斜日葦汀凝立處，遠波微颺翠如苔。"]'),
('d20ad00a-b082-42a9-8746-602ca4d0a5be','細雨遙懷故人','李建勳','唐','唐诗','tang','','[]','江雲未散東風暖，溟濛正在高樓見。',64,'全唐诗/poet.tang.41000.json','["江雲未散東風暖，溟濛正在高樓見。", "細柳緣堤少過人，平蕪隔水時飛燕。", "我有近詩誰與和，憶君狂醉愁難破。", "昨夜南窗不得眠，閑堦點滴迴燈坐。"]'),
('b859b5a3-5a70-411c-95a2-b77d3fc8d5fd','春水','李建勳','唐','唐诗','tang','','[]','萬派爭流雨過時，晚來春靜更逶迤。',64,'全唐诗/poet.tang.41000.json','["萬派爭流雨過時，晚來春靜更逶迤。", "輕鷗散遶夫差國，遠樹微分夏禹祠。", "青岸漸平濡柳帶，舊溪應暖負蓴絲。", "風鬟倚檝誰家子，愁看鴛鴦望所之。"]'),
('c411a89d-2577-4088-959a-ffb5927cde5c','蝶','李建勳','唐','唐诗','tang','','[]','粉蝶翩翩若有期，南園長是到春歸。',64,'全唐诗/poet.tang.41000.json','["粉蝶翩翩若有期，南園長是到春歸。", "閑依柳帶參差起，困傍桃花獨自飛。", "潛被燕驚還散亂，偶因人逐入簾幃。", "晚來欲雨東風急，迴看池塘影漸稀。"]'),
('d882c545-6957-4bd4-8cf4-8f412c49d72a','中春寫懷寄沈彬員外','李建勳','唐','唐诗','tang','','[]','省從騎竹學謳吟，便殢光陰役此心。',64,'全唐诗/poet.tang.41000.json','["省從騎竹學謳吟，便殢光陰役此心。", "寓目不能閑一日，閉門長勝得千金。", "窗懸夜雨殘燈在，庭掩春風落絮深。", "唯有故人同此興，近來何事嬾相尋。"]'),
('4c622bbb-4810-4a02-9b03-9c19c636f7e3','鍾山寺避暑勉二三子','李建勳','唐','唐诗','tang','','[]','樓臺雖少景何深，滿地青苔勝布金。',64,'全唐诗/poet.tang.41000.json','["樓臺雖少景何深，滿地青苔勝布金。", "松影晚留僧共坐，水聲閑與客同尋。", "清涼會擬歸蓮社，沈湎終須棄竹林。", "長愛寄吟經案上，石窗秋霽向千岑。"]'),
('2bbc5827-0e78-4514-905b-95818e4732b2','道林寺','李建勳','唐','唐诗','tang','','[]','雖向鍾峯數寺連，就中奇勝出其間。',64,'全唐诗/poet.tang.41000.json','["雖向鍾峯數寺連，就中奇勝出其間。", "不教幽樹妨閑地，別著高窗向遠山。", "蓮沼水從雙澗入，客堂僧自九華還。", "無因得結香燈社，空向王門玷玉班。"]'),
('a2af938a-ec66-4d45-be35-cac49777111f','和致仕沈郎中','李建勳','唐','唐诗','tang','','[]','欲謀休退尚因循，且向東溪種白蘋。',64,'全唐诗/poet.tang.41000.json','["欲謀休退尚因循，且向東溪種白蘋。", "謬應星辰居四輔，終期冠褐作閑人。", "城中隔日趨朝嬾，楚外千峯入夢頻。", "殘照晚庭沈醉醒，靜吟斜倚老松身。"]'),
('9f84b4da-a372-48d8-ad2f-ff44b0870f16','醉中詠梅花','李建勳','唐','唐诗','tang','','[]','十月清霜尚未寒，雪英重疊已如摶。',64,'全唐诗/poet.tang.41000.json','["十月清霜尚未寒，雪英重疊已如摶。", "還悲獨詠東園裏，老作南州刺史看。", "北客見皆驚節氣，郡僚癡欲望盃盤。", "交親罕至長安遠，一醉如泥豈自歡。"]'),
('1cac2fe6-686f-4688-83f1-da7bfa1e062e','閑出書懷','李建勳','唐','唐诗','tang','','[]','閑遊何用問東西，寓興皆非有所期。',64,'全唐诗/poet.tang.41000.json','["閑遊何用問東西，寓興皆非有所期。", "斷酒只攜僧共去，看山從聽馬行遲。", "溪田雨漲禾生耳，原野鶯啼黍熟時。", "應有交親長笑我，獨輕人事鬢將衰。"]'),
('ee276a25-8216-4377-a74d-45a581aae9d3','寺居陸處士相訪感懷却寄二三友人','李建勳','唐','唐诗','tang','','[]','湘寺閑居亦半年，就中昨夜好潸然。',64,'全唐诗/poet.tang.41000.json','["湘寺閑居亦半年，就中昨夜好潸然。", "人歸遠岫疎鐘後，雪打高杉古屋前。", "投足正逢他國亂，冥心未解祖師禪。", "爐煙向冷孤燈下，唯有寒吟到曙天。"]'),
('9c1c6580-3df1-44d0-a207-2362f407f742','春雪','李建勳','唐','唐诗','tang','','[]','隨風竟日勢漫漫，特地繁於故歲看。',64,'全唐诗/poet.tang.41000.json','["隨風竟日勢漫漫，特地繁於故歲看。", "幽榭凍黏花屋重，短簷斜濕燕巢寒。", "閑聽不寐詩魂爽，淨喫無厭酒肺乾。", "莫道便爲桑麥藥，亦勝焦涸到春殘。"]'),
('3ca81a07-cd0a-40e9-8e5f-b4136ada501c','惜花','李建勳','唐','唐诗','tang','','[]','淡淡西園日又垂，一尊何忍負芳枝。',64,'全唐诗/poet.tang.41000.json','["淡淡西園日又垂，一尊何忍負芳枝。", "莫言風雨長相促，直是晴明得幾時。", "心破只愁鶯踐落，眼穿唯怕客來遲。", "年年使我成狂叟，腸斷紅牋幾首詩。"]'),
('c52be58f-f2e9-4b41-9178-44aa28c15cb7','梅花寄所親','李建勳','唐','唐诗','tang','','[]','一氣才新物未知，每慙青律與先吹。',64,'全唐诗/poet.tang.41000.json','["一氣才新物未知，每慙青律與先吹。", "雪霜迷素猶嫌早，桃杏雖紅且後時。", "雲鬢自黏飄處粉，玉鞭誰指出牆枝。", "老夫多病無風味，只向尊前詠舊詩。"]'),
('e9615461-b95b-4c77-80b1-b0a34a84b7e2','登昇元閣','李建勳','唐','唐诗','tang','','[]','登高始覺太虛寬，白雪須知唱和難。',64,'全唐诗/poet.tang.41000.json','["登高始覺太虛寬，白雪須知唱和難。", "雲渡瑣窗金牓濕，月移珠箔水精寒。", "九天星象簾前見，六代城池直下觀。", "唯有上層人未到，金烏飛過拂闌干。"]'),
('7a649c5a-a616-4085-9a94-d3b80b1e0c80','雪有作','李建勳','唐','唐诗','tang','','[]','霏霏奕奕滿寒空，況是難逢值臘中。',64,'全唐诗/poet.tang.41000.json','["霏霏奕奕滿寒空，況是難逢值臘中。", "未白已堪張宴會，漸繁偏好去簾櫳。", "庭莎易集看盈地，池柳難裝旋逐風。", "長愛清華入詩句，預愁遲日放消融。"]'),
('1ba734c9-fa8a-4fd3-9dfe-38e0f961a755','宮詞','李建勳','唐','唐诗','tang','','[]','自遠凝旒守上陽，舞衣頓減舊朝香。',64,'全唐诗/poet.tang.41000.json','["自遠凝旒守上陽，舞衣頓減舊朝香。", "簾垂粉閣春將盡，門掩梨花日漸長。", "草色深濃封輦路，水聲低咽轉宮牆。", "君王一去不迴駕，皓齒青蛾空斷腸。"]'),
('1c1a0c6e-5881-44de-a4a5-bf3388c44919','晚春送牡丹','李建勳','唐','唐诗','tang','','[]','攜觴邀客遶朱闌，腸斷殘春送牡丹。',64,'全唐诗/poet.tang.41000.json','["攜觴邀客遶朱闌，腸斷殘春送牡丹。", "風雨數來留不得，離披將謝忍重看。", "氛氳蘭麝香初減，零落雲霞色漸乾。", "借問少年能幾許，不須推酒厭桮盤。"]'),
('fafbb7ae-fa9f-4f1e-83ed-71d959a7e4e6','歲暮晚泊望廬山不見因懷岳僧呈察判','李建勳','唐','唐诗','tang','','["\u5e90\u5c71"]','貪程只爲看廬阜，及到停舟恨頗濃。',64,'全唐诗/poet.tang.41000.json','["貪程只爲看廬阜，及到停舟恨頗濃。", "雲暗半空藏萬仞，雪迷雙瀑在中峯。", "林端莫辨曾遊路，鳥際微聞向暮鐘。", "長愧昔年招我入，共尋香社見芙蓉。"]'),
('ea521fb1-4996-42b3-82b5-d02a6a4a0de4','重臺蓮','李建勳','唐','唐诗','tang','','[]','斜倚秋風絕比倫，千英和露染難勻。',64,'全唐诗/poet.tang.41000.json','["斜倚秋風絕比倫，千英和露染難勻。", "自爲祥瑞生南國，誰把丹青寄北人。", "明月幾宵同綠水，牡丹無路出紅塵。", "憐伊不算多時立，贏得馨香暗上身。"]'),
('69b1b7d2-a95f-4c14-afc6-4712ea03c4c1','迎神','李建勳','唐','唐诗','tang','','[]','攂蠻鼉，吟塞笛，女巫結束分行立。',64,'全唐诗/poet.tang.41000.json','["攂蠻鼉，吟塞笛，女巫結束分行立。", "空中再拜神且來，滿奠椒漿齊獻揖。", "陰風窣窣吹紙錢，妖巫瞑目傳神言。", "與君降福爲豐年，莫教賽祀虧常筵。"]'),
('de26ce37-27b5-4252-85d6-e28fcd4f940f','春詞','李建勳','唐','唐诗','tang','','[]','日高閑步下堂階，細草春莎沒繡鞋。',32,'全唐诗/poet.tang.41000.json','["日高閑步下堂階，細草春莎沒繡鞋。", "折得玫瑰花一朵，憑君簪向鳳皇釵。"]'),
('00cb362d-2814-40dc-a7e7-c75d1dcdf307','獨夜作','李建勳','唐','唐诗','tang','','[]','佳人一去無消息，夢覺香殘愁復入。',32,'全唐诗/poet.tang.41000.json','["佳人一去無消息，夢覺香殘愁復入。", "空庭悄悄月如霜，獨倚闌干伴花立。"]'),
('14aafa71-90cf-4156-9c6e-f26b8be6c3d5','竹','李建勳','唐','唐诗','tang','','[]','瓊節高吹宿鳳枝，風流交我立忘歸。',32,'全唐诗/poet.tang.41000.json','["瓊節高吹宿鳳枝，風流交我立忘歸。", "最憐瑟瑟斜陽下，花影相和滿客衣。"]'),
('1db4fe9b-99dd-4c06-9f44-8ef674165e93','清明日','李建勳','唐','唐诗','tang','','[]','他皆攜酒尋芳去，我獨關門好靜眠。',32,'全唐诗/poet.tang.41000.json','["他皆攜酒尋芳去，我獨關門好靜眠。", "唯有楊花似相覓，因風時復到牀前。"]'),
('71901041-e74d-48b4-b41f-15456b4ea1b1','宮詞','李建勳','唐','唐诗','tang','','[]','宮門長閉舞衣閑，略識君王鬢便斑。',32,'全唐诗/poet.tang.41000.json','["宮門長閉舞衣閑，略識君王鬢便斑。", "却羨落花春不管，御溝流得到人間。"]'),
('72c4582b-dc80-4b42-9254-c5bbedc3c0ca','送喻鍊師歸茅山','李建勳','唐','唐诗','tang','','[]','休糧知幾載，臉色似桃紅。',48,'全唐诗/poet.tang.41000.json','["休糧知幾載，臉色似桃紅。", "半醉離城去，單衣行雪中。", "水聲茅洞曉，雲影石房空。", "莫學秦時客，音書便不通。"]'),
('28108a90-daca-4cea-82f3-62d11e7800cc','和元宗元日大雪登樓','李建勳','唐','唐诗','tang','','[]','紛紛忽降當元曾，著物輕明似月華。',64,'全唐诗/poet.tang.41000.json','["紛紛忽降當元曾，著物輕明似月華。", "狂灑玉墀初散絮，密黏宮樹未妨花。", "迥封雙闕千尋峭，冷壓南山萬仞斜。", "寧意傳來中使出，御題先賜老僧家。"]'),
('01643106-a50d-43ae-8e94-369cf471c3db','遊棲霞寺','李建勳','唐','唐诗','tang','','[]','養花天氣近平分，瘦馬來敲白下門。',64,'全唐诗/poet.tang.41000.json','["養花天氣近平分，瘦馬來敲白下門。", "曉色未開山意遠，春容猶淡月華昏。", "琅琊冷落存遺跡，籬舍稀疎帶舊村。", "此地幾經人聚散，只今王謝獨名存。"]'),
('4ea08fb0-5cec-4d60-83b9-edfe83ad9f5a','答湯悅','李建勳','唐','唐诗','tang','','[]','司空猶不作，那敢作司徒。',24,'全唐诗/poet.tang.41000.json','["司空猶不作，那敢作司徒。", "幸有山翁號，如何不見呼。"]'),
('aec93488-8070-465d-95c1-0de241f0b2d3','金山','李建勳','唐','唐诗','tang','','[]','不嗟白髮曾遊此，不歎征帆無了期。',32,'全唐诗/poet.tang.41000.json','["不嗟白髮曾遊此，不歎征帆無了期。", "盡日憑闌誰會我，祗悲不見韓垂詩。"]'),
('8f5ef1be-c754-4000-86b5-be933da334cc','送李冠','李建勳','唐','唐诗','tang','','[]','勻如春澗長流水，怨似秋枝欲斷蟬。',32,'全唐诗/poet.tang.41000.json','["勻如春澗長流水，怨似秋枝欲斷蟬。", "可惜人間容易聽，清聲不到御樓前。"]'),
('f70dd26c-8e11-4e27-97ae-4ee31eb7ac20','遊宋興寺東巖','李建勳','唐','唐诗','tang','','[]','幾年不到東巖下，舊住僧亡屋亦無。',32,'全唐诗/poet.tang.41000.json','["幾年不到東巖下，舊住僧亡屋亦無。", "寒日蕭條何物在，朽松經燒石池枯。"]'),
('b7b33b0a-c92b-4382-b620-3b7021025f1f','批周宗書後','李建勳','唐','唐诗','tang','','[]','偶罷阿衡來典郡，固無閑可物應官。',32,'全唐诗/poet.tang.41000.json','["偶罷阿衡來典郡，固無閑可物應官。", "憑君爲報羣胥道，莫作循州刺史看。"]'),
('9c904c1a-dbc8-4ef0-a843-08be459c9d39','題信果觀壁','李建勳','唐','唐诗','tang','','[]','春來漲水流而活，曉色西山勢似行。',32,'全唐诗/poet.tang.41000.json','["春來漲水流而活，曉色西山勢似行。", "玉洞主人經劫在，攜竿步步就長生。"]'),
('8128bebe-c97f-465f-942b-a9b6c63e0216','送八分書與友人繼以詩','李建勳','唐','唐诗','tang','','[]','跁跒爲詩跁跒書，不封將去寄仙都。',32,'全唐诗/poet.tang.41000.json','["跁跒爲詩跁跒書，不封將去寄仙都。", "仙翁拍手應相笑，得似秦朝次仲無。"]'),
('e86bdcc3-6013-4905-a780-a195f4bb3bbd','句','李建勳','唐','唐诗','tang','','[]','桃花流水須長信，不學劉郎去又來。',48,'全唐诗/poet.tang.41000.json','["桃花流水須長信，不學劉郎去又來。", "粟多未必全爲計，師老須防有伏兵。", "徧尋雲壑重題石，欲下山門更倚松。"]'),
('4a00fa54-aa77-4726-9ea0-0866cc72208b','蟠溪懷古','孟賓于','唐','唐诗','tang','','[]','良哉呂尚父，深隱始歸周。',48,'全唐诗/poet.tang.41000.json','["良哉呂尚父，深隱始歸周。", "釣石千年在，春風一水流。", "松根盤蘚石，花影臥沙鷗。", "誰更懷韜術，追思古渡頭。"]'),
('636e156e-117e-4506-8fcf-557bd5da97a4','懷連上舊居','孟賓于','唐','唐诗','tang','','[]','閑思連上景難齊，樹繞仙鄉路繞溪。',64,'全唐诗/poet.tang.41000.json','["閑思連上景難齊，樹繞仙鄉路繞溪。", "明月夜舟漁父唱，春風平野鷓鴣啼。", "城邊寄信歸雲外，花下傾杯到日西。", "更憶海陽垂釣侶，昔年相遇草萋萋。"]'),
('e54d0343-a5ee-4079-9ea4-0b72082b8d29','公子行','孟賓于','唐','唐诗','tang','','[]','錦衣紅奪彩霞明，侵曉春遊向野庭。',32,'全唐诗/poet.tang.41000.json','["錦衣紅奪彩霞明，侵曉春遊向野庭。", "不識農夫辛苦力，驕驄蹋爛麥青青。"]'),
('63f8808a-0eff-4a69-9e65-869fa764205a','湘江亭','孟賓于','唐','唐诗','tang','','[]','獨宿大中年裏寺，樊籠得出事無心。',32,'全唐诗/poet.tang.41000.json','["獨宿大中年裏寺，樊籠得出事無心。", "寒山夢覺一聲磬，霜葉滿林秋正深。"]'),
('26d9ad8a-7895-4172-a864-9f116161aedf','題梅仙館','孟賓于','唐','唐诗','tang','','[]','仙界路遙雲縹渺，古壇風冷葉蕭騷。',32,'全唐诗/poet.tang.41000.json','["仙界路遙雲縹渺，古壇風冷葉蕭騷。", "後來豈合言淹滯，一尉昇騰道最高。"]'),
('399d9ce5-5158-4b93-a0cb-7730ca336576','題顏氏亭宇','孟賓于','唐','唐诗','tang','','[]','園林蕭灑聞來久，欲訪因循二十秋。',32,'全唐诗/poet.tang.41000.json','["園林蕭灑聞來久，欲訪因循二十秋。", "今日開襟吟不盡，碧山重疊水長流。"]'),
('3e8179bc-b010-43c5-8d11-02f308ad1c73','晚眺','孟賓于','唐','唐诗','tang','','[]','倚杖殘秋裏，吟中四顧頻。',48,'全唐诗/poet.tang.41000.json','["倚杖殘秋裏，吟中四顧頻。", "西風天際雁，落日渡頭人。", "草色衰平野，山陰歛暮塵。", "却尋苔徑去，明月照村鄰。"]'),
('df59a889-d5ba-43ce-bc33-c3da2e5f27e8','獻主司','孟賓于','唐','唐诗','tang','','[]','那堪雨後更聞蟬，溪隔重湖路七千。',32,'全唐诗/poet.tang.41000.json','["那堪雨後更聞蟬，溪隔重湖路七千。", "憶昔故園楊柳岸，全家送上渡頭船。"]'),
('876d8255-63e4-488e-9c61-468bf7db08a0','句','孟賓于','唐','唐诗','tang','','[]','遠樹連沙靜，閑舟入浦遲。',208,'全唐诗/poet.tang.41000.json','["遠樹連沙靜，閑舟入浦遲。", "簾垂羣吏散，苔長訟庭閑。", "去年曾折處，今日又垂條。", "早知落處隨疎雨，悔得開時順暖風。", "千家簾幕春空在，幾處樓臺月自明。", "臘雪化爲流水去，春風吹出好山來。", "昔日聲塵喧洛下，近年詩句滿江南。", "匝地人家憑檻見，遠山秋色捲簾看。", "蟾宮空手下，澤國更誰來。", "水國二親應探榜，龍門三月又傷春。", "仙鳥却回空說夢，清朝未達自嫌身。", "失意從他桃李春，嵩陽經過歇行塵。", "雲僧不見城中事，問是今年第幾人。", "因逢日者教重應，忍被雲僧勸却歸。"]'),
('5c09f00a-7a12-472a-a44c-bdf98cd689c0','九日陪董內召登高','廖匡圖','唐','唐诗','tang','','[]','祝融峰下逢嘉節，相對那能不愴神。',64,'全唐诗/poet.tang.41000.json','["祝融峰下逢嘉節，相對那能不愴神。", "煙裏共尋幽磵菊，樽前俱是異鄉人。", "遙山帶日應連越，孤雁來時想別秦。", "自古登高盡惆悵，茱萸休笑淚盈巾。"]'),
('980a7a70-83c5-46ab-bf62-1b8f93643d9f','贈泉陵上人','廖匡圖','唐','唐诗','tang','','[]','暫把枯藤倚碧根，禪堂初創楚江濆。',64,'全唐诗/poet.tang.41000.json','["暫把枯藤倚碧根，禪堂初創楚江濆。", "直疑松小難留鶴，未信山低住得雲。", "草接寺橋牛笛近，日銜村樹鳥行分。", "每來共憶曾遊處，萬壑泉聲絕頂聞。"]'),
('50f7ae86-25dc-41c8-bf03-46e4b6ed191a','和人贈沈彬','廖匡圖','唐','唐诗','tang','','[]','冥鴻跡在煙霞上，燕雀休誇大廈巢。',64,'全唐诗/poet.tang.41000.json','["冥鴻跡在煙霞上，燕雀休誇大廈巢。", "名利最爲浮世重，古今能有幾人拋。", "逼真但使心無著，混俗何妨手強抄。", "深喜卜居連岳色，水邊竹下得論交。"]'),
('6f2c68f2-a84f-4c11-b91e-1e1a73c26ead','松','廖匡圖','唐','唐诗','tang','','[]','曾於西晉封中散，又向東吳作大夫。',64,'全唐诗/poet.tang.41000.json','["曾於西晉封中散，又向東吳作大夫。", "濃翠自知千古在，清聲誰道四時無。", "枝柯偃後龍蛇老，根脚盤來爪距粗。", "直待素秋搖落日，始將凡木鬬榮枯。"]'),
('2d42db92-dffc-4404-b46b-5ccd9d7ef146','句','廖匡圖','唐','唐诗','tang','','[]','正悲世上事無限，細看水中塵更多。',16,'全唐诗/poet.tang.41000.json','["正悲世上事無限，細看水中塵更多。"]'),
('5e27965a-bf4c-41ed-b300-3cf8542908a1','中秋月','廖凝','唐','唐诗','tang','','[]','九十日秋色，今宵已半分。',48,'全唐诗/poet.tang.41000.json','["九十日秋色，今宵已半分。", "孤光含列宿，四面絕纖雲。", "衆木排疎影，寒流疊細紋。", "遙遙望丹桂，心緒正紛紛。"]'),
('80ab1f77-9294-40b8-abae-4c9fe5d5a629','聞蟬','廖凝','唐','唐诗','tang','','[]','一聲初應侯，萬木已西風。',48,'全唐诗/poet.tang.41000.json','["一聲初應侯，萬木已西風。", "便感異鄉客，先於離塞鴻。", "日斜金谷靜，雨過石城空。", "此處不堪聽，蕭條千古同。"]'),
('bb5de79c-5ecd-4b4a-b8ee-89d78d8912c1','彭澤解印','廖凝','唐','唐诗','tang','','[]','五斗徒勞謾折腰，三年兩鬢爲誰焦。',32,'全唐诗/poet.tang.41000.json','["五斗徒勞謾折腰，三年兩鬢爲誰焦。", "今朝官滿重歸去，還挈來時舊酒瓢。"]'),
('06d9c021-de1b-401d-ae24-f062567e1ab8','句','廖凝','唐','唐诗','tang','','[]','滿汀漚不散，一局黑全輸。',80,'全唐诗/poet.tang.41000.json','["滿汀漚不散，一局黑全輸。", "獵回千帳雪，探密大河冰。", "落盡最高樹，始知松柏青。", "飯僧春嶺蕨，醒酒雪潭魚。", "風清竹閣留僧宿，雨濕莎庭放吏衙。", "紅躑躅繁金殿暖，碧芙蓉笑水宮秋。"]'),
('1a7551da-e569-4f7e-a343-e09bfed39750','贈廖凝','韋鼎','唐','唐诗','tang','','[]','君與白雲鄰，生涯久忍貧。',48,'全唐诗/poet.tang.41000.json','["君與白雲鄰，生涯久忍貧。", "姓名高雅道，寰海許何人。", "岳氣秋來早，亭寒果落新。", "幾回吟石畔，孤鶴自相親。"]'),
('cbb150aa-6df0-4757-8d17-47c2d8fc32e9','寄廬山白上人','左偃','唐','唐诗','tang','','["\u5e90\u5c71"]','潦倒門前客，閑眠歲又殘。',48,'全唐诗/poet.tang.41000.json','["潦倒門前客，閑眠歲又殘。", "連天數峰雪，終日與誰看。", "萬丈高松古，千尋落水寒。", "仍聞有新作，嬾寄入長安。"]'),
('4e42a672-25b2-4aa5-875d-2adff751fa30','寄韓侍郎','左偃','唐','唐诗','tang','','[]','謀身謀隱兩無成，拙計深慙負耦耕。',64,'全唐诗/poet.tang.41000.json','["謀身謀隱兩無成，拙計深慙負耦耕。", "漸老可堪懷故國，多愁翻覺厭浮生。", "言詩幸遇明公許，守朴甘遭俗者輕。", "今日況聞搜草澤，獨悲顦顇臥昇平。"]'),
('e863be7b-16ee-49c9-83d0-90e388ec4ba3','漢宮詞','左偃','唐','唐诗','tang','','[]','寒燭照清夜，笙歌隔蘚牆。',24,'全唐诗/poet.tang.41000.json','["寒燭照清夜，笙歌隔蘚牆。", "一從飛燕入，便不見君王。"]'),
('2d8b5c7e-7adb-4067-9925-0ceb2bcb5f74','送君去','左偃','唐','唐诗','tang','','[]','關河月未曉，行子心已急。',24,'全唐诗/poet.tang.41000.json','["關河月未曉，行子心已急。", "佳人無一言，獨背殘燈泣。"]'),
('dd329003-2ea6-4652-93ea-558cd723e270','秋晚野望','左偃','唐','唐诗','tang','','[]','倚筇聊一望，何處是秦川？草色初晴路，鴻聲欲暮天。',24,'全唐诗/poet.tang.41000.json','["倚筇聊一望，何處是秦川？草色初晴路，鴻聲欲暮天。"]'),
('2b06d609-c982-47e4-bc74-365915028465','郊原晚望懷李秘書','左偃','唐','唐诗','tang','','[]','歸鳥入平野，寒雲在遠村。',24,'全唐诗/poet.tang.41000.json','["歸鳥入平野，寒雲在遠村。", "徒令睇望久，不復見王孫。"]'),
('2aecaff2-79e4-447b-932c-92f1af0f1a30','言懷別同志','左偃','唐','唐诗','tang','','[]','慚老將誰託，勞生每自慙。',24,'全唐诗/poet.tang.41000.json','["慚老將誰託，勞生每自慙。", "何當重攜手，風雨滿江南。"]'),
('970c4e17-97b4-4465-bd1c-a3bbc609910a','江上晚泊','左偃','唐','唐诗','tang','','[]','寒雲淡淡天無際，片帆落處沙鷗起。',32,'全唐诗/poet.tang.41000.json','["寒雲淡淡天無際，片帆落處沙鷗起。", "水闊風高日復斜，扁舟獨宿蘆花裏。"]'),
('60cea404-3830-4800-b1d0-e38385b967fc','寄鑒上人','左偃','唐','唐诗','tang','','[]','一從攜手阻戈鋋，屈指如今已十年。',32,'全唐诗/poet.tang.41000.json','["一從攜手阻戈鋋，屈指如今已十年。", "長記二林同宿夜，竹齋聽雨共忘眠。"]'),
('24e9ebdf-00a4-4ba7-b431-ffcf6a1ee786','送人','左偃','唐','唐诗','tang','','[]','一莖二莖華髮生，千枝萬枝梨花白。',32,'全唐诗/poet.tang.41000.json','["一莖二莖華髮生，千枝萬枝梨花白。", "春色江南獨未歸，今朝又送還鄉客。"]'),
('18b1a46b-d2cf-4a45-b40b-4e188810fa72','句','左偃','唐','唐诗','tang','','[]','胡笳聞欲死，漢月望還生。',24,'全唐诗/poet.tang.41000.json','["胡笳聞欲死，漢月望還生。", "日華離碧海，雲影散青霄。"]'),
('cdb04b93-228b-45a6-b419-ba486c4e909a','景陽臺懷古','陳貺','唐','唐诗','tang','','[]','景陽六朝地，運極自依依。',48,'全唐诗/poet.tang.41000.json','["景陽六朝地，運極自依依。", "一會皆同是，到頭誰論非。", "酒濃沈遠慮，花好失前機。", "見此尤宜戒，正當家國肥。"]'),
('9f898059-c453-4067-98f2-44b1094e5eda','石城懷古','劉洞','唐','唐诗','tang','','[]','石城古岸頭，一望思悠悠。',24,'全唐诗/poet.tang.41000.json','["石城古岸頭，一望思悠悠。", "幾許六朝事，不禁江水流。"]'),
('6321d8f2-241f-4b5d-98c0-7324d0798b9e','句','劉洞','唐','唐诗','tang','','["\u957f\u6c5f"]','千里長江皆渡馬，十年養士得何人。',44,'全唐诗/poet.tang.41000.json','["千里長江皆渡馬，十年養士得何人。", "翻憶潘郎章奏內，愔愔日暮好沾巾。", "百骸同草木，萬象入心靈。"]'),
('60a99fa6-e1df-4946-a4df-8a0b94891b3f','旅懷','江爲','唐','唐诗','tang','','[]','迢迢江漢路，秋色又堪驚。',48,'全唐诗/poet.tang.41000.json','["迢迢江漢路，秋色又堪驚。", "半夜聞鴻雁，多年別弟兄。", "高風雲影斷，微雨菊花明。", "欲寄東歸信，裴回無限情。"]'),
('560e327d-3754-4136-84fe-2d0df565fc99','江行','江爲','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','越信隔年稀，孤舟幾夢歸。',48,'全唐诗/poet.tang.41000.json','["越信隔年稀，孤舟幾夢歸。", "月寒花露重，江晚水煙微。", "峰直帆相望，沙空鳥自飛。", "何時洞庭上，春雨滿蓑衣。"]'),
('c11ca31f-2354-4bf8-8be4-101c5e81c601','登潤州城','江爲','唐','唐诗','tang','','[]','天末江城晚，登臨客望迷。',48,'全唐诗/poet.tang.41000.json','["天末江城晚，登臨客望迷。", "春潮平島嶼，殘雨隔虹霓。", "鳥與孤帆遠，煙和獨樹低。", "鄉山何處是，目斷廣陵西。"]'),
('be02f3fe-eb71-419e-b365-b9976197bd7a','岳陽樓','江爲','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','倚樓高望極，展轉念前途。',48,'全唐诗/poet.tang.41000.json','["倚樓高望極，展轉念前途。", "晚葉紅殘楚，秋江碧入吳。", "雲中來雁急，天末去帆孤。", "明月誰同我，悠悠上帝都。"]'),
('02f5de3b-419a-493d-9fd6-185ce3802149','送客','江爲','唐','唐诗','tang','','[]','明月孤舟遠，吟髭鑷更華。',48,'全唐诗/poet.tang.41000.json','["明月孤舟遠，吟髭鑷更華。", "天形圍澤國，秋色露人家。", "水館螢交影，霜洲橘委花。", "何當尋舊隱，泉石好生涯。"]'),
('4e31f81e-ea21-44d1-b963-faa4c784c7bd','臨刑詩','江爲','唐','唐诗','tang','','[]','街鼓侵人急，西傾日欲斜。',24,'全唐诗/poet.tang.41000.json','["街鼓侵人急，西傾日欲斜。", "黃泉無旅店，今夜宿誰家。"]'),
('224881c4-99ea-440d-8d77-893e03e64dfd','塞下曲','江爲','唐','唐诗','tang','','[]','萬里黃雲凍不飛，磧煙烽火夜深微。',32,'全唐诗/poet.tang.41000.json','["萬里黃雲凍不飛，磧煙烽火夜深微。", "胡兒移帳寒笳絕，雪路時聞探馬歸。"]'),
('5e25d0b2-5f9f-4e91-a639-c86d05561510','隋堤柳','江爲','唐','唐诗','tang','','[]','錦纜龍舟萬里來，醉鄉繁盛忽塵埃。',32,'全唐诗/poet.tang.41000.json','["錦纜龍舟萬里來，醉鄉繁盛忽塵埃。", "空餘兩岸千株柳，雨葉風花作恨媒。"]'),
('3ac15061-cff3-4487-b9e1-b96ddd64f800','句','江爲','唐','唐诗','tang','','[]','吟登蕭寺旃檀閣，醉倚王家玳瑁筵。',32,'全唐诗/poet.tang.41000.json','["吟登蕭寺旃檀閣，醉倚王家玳瑁筵。", "遠遠朝宗出白雲，方圓隨處性長存。"]'),
('3698adf0-0bcb-4e9f-8e97-6ef4de6e1205','詠鷹','高越','唐','唐诗','tang','','[]','雪爪星眸世所稀，摩天專待振毛衣。',32,'全唐诗/poet.tang.41000.json','["雪爪星眸世所稀，摩天專待振毛衣。", "虞人莫謾張羅網，未肯平原淺草飛。"]'),
('2253630c-33f0-44c3-bd15-efb4562d4bcf','惜花','張泌','唐','唐诗','tang','','[]','蝶散鶯啼尚數枝，日斜風定更離披。',32,'全唐诗/poet.tang.41000.json','["蝶散鶯啼尚數枝，日斜風定更離披。", "看多記得傷心事，金谷樓前委地時。"]'),
('afc2e6d6-e67f-4513-a6ab-82841d2f97cc','寄人 一','張泌','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u4e03\u8a00\u7edd\u53e5", "\u6708\u4eae", "\u7231\u60c5"]','別夢依依到謝家，小廊迴合曲闌斜。',32,'全唐诗/poet.tang.41000.json','["別夢依依到謝家，小廊迴合曲闌斜。", "多情只有春庭月，猶爲離人照落花。"]'),
('d590059b-5af2-47e5-b5c1-302afda05bd7','寄人 二','張泌','唐','唐诗','tang','','[]','酷憐風月爲多情，還到春時別恨生。',32,'全唐诗/poet.tang.41000.json','["酷憐風月爲多情，還到春時別恨生。", "倚柱尋思倍惆悵，一場春夢不分明。"]'),
('1e58e1d3-e0f2-41b4-9592-f0d126835822','邊上','張泌','唐','唐诗','tang','','[]','戍樓吹角起征鴻，獵獵寒旌背晚風。',64,'全唐诗/poet.tang.41000.json','["戍樓吹角起征鴻，獵獵寒旌背晚風。", "千里暮煙愁不盡，一川秋草恨無窮。", "山河慘澹關城閉，人物蕭條市井空。", "只此旅魂招未得，更堪回首夕陽中。"]'),
('68c0c67f-eb61-4dfc-8685-a43c60f1e0e2','長安道中早行','張泌','唐','唐诗','tang','','[]','客離孤館一燈殘，牢落星河欲曙天。',64,'全唐诗/poet.tang.41000.json','["客離孤館一燈殘，牢落星河欲曙天。", "雞唱未沈函谷月，鴈聲新度灞陵煙。", "浮生已悟莊周蝶，壯志仍輸祖逖鞭。", "何事悠悠策羸馬，此中辛苦過流年。"]'),
('ca299bb7-8032-49a5-98c1-2e5b1be183ed','洞庭阻風','張泌','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u6292\u60c5", "\u4f24\u6625", "\u5199\u666f", "\u5730\u65b9", "\u5b64\u5bc2"]','空江浩蕩景蕭然，盡日菰蒲泊釣船。',64,'全唐诗/poet.tang.41000.json','["空江浩蕩景蕭然，盡日菰蒲泊釣船。", "青草浪高三月渡，綠楊花撲一溪煙。", "情多莫舉傷春目，愁極兼無買酒錢。", "猶有漁人數家住，不成村落夕陽邊。"]'),
('cfcad900-d09c-4c60-8b65-d1bc4aa3ab16','春日旅泊桂州','張泌','唐','唐诗','tang','','[]','暖風芳草竟芊綿，多病多愁負少年。',64,'全唐诗/poet.tang.41000.json','["暖風芳草竟芊綿，多病多愁負少年。", "弱柳未勝寒食雨，好花爭奈夕陽天。", "溪邊物色堪圖畫，林畔鶯聲似管弦。", "獨有離人開淚眼，強憑杯酒亦澘然。"]'),
('73467be0-bcdc-4a1d-a528-463192baaa52','晚次（一作「歇」）湘源縣','張泌','唐','唐诗','tang','','[]','煙郭遙聞向晚雞，水平舟靜浪聲齊。',71,'全唐诗/poet.tang.41000.json','["煙郭遙聞向晚雞，水平舟靜浪聲齊。", "高林帶雨楊梅熟，曲岸籠雲謝豹啼。", "二女廟荒汀（一作「宫」）樹老，九疑山碧楚天低。", "湘南自古多離怨，莫動哀吟易慘悽。"]'),
('b3372012-3d57-4646-ae05-98b2f6b96cca','惆悵吟','張泌','唐','唐诗','tang','','[]','秋風丹葉動荒城，慘澹雲遮日半明。',64,'全唐诗/poet.tang.41000.json','["秋風丹葉動荒城，慘澹雲遮日半明。", "晝夢却因惆悵得，晚愁多爲別離生。", "江淹彩筆空留恨，莊叟玄譚未及情。", "千古怨魂銷不得，一江寒浪若爲平。"]'),
('ce7ee03a-66cf-48f4-ab4d-b723df99e5ed','秋晚過洞庭','張泌','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','征帆初挂酒初酣，暮景離情兩不堪。',64,'全唐诗/poet.tang.41000.json','["征帆初挂酒初酣，暮景離情兩不堪。", "千里晚霞雲夢北，一洲霜橘洞庭南。", "溪風送雨過秋寺，磵石驚龍落夜潭。", "莫把羈魂弔湘魄，九疑愁絕銷煙嵐。"]'),
('9d0f6d82-728b-4eb1-b76b-654623b89bca','題華嚴寺木塔','張泌','唐','唐诗','tang','','[]','六街晴色動秋光，雨霽憑高只易傷。',64,'全唐诗/poet.tang.41000.json','["六街晴色動秋光，雨霽憑高只易傷。", "一曲晚煙浮渭水，半橋斜日照咸陽。", "休將世路悲塵事，莫指雲山認故鄉。", "回首漢宮樓閣暮，數聲鐘鼓自微茫。"]'),
('dbe87cea-bd22-40d4-b6bc-894cddd62f7a','經舊遊','張泌','唐','唐诗','tang','','[]','暫到高唐曉又還，丁香結夢水潺潺。',32,'全唐诗/poet.tang.41000.json','["暫到高唐曉又還，丁香結夢水潺潺。", "不知雲雨歸何處，歷歷空留十二山。"]'),
('d06e3198-2b51-47b8-a6f5-c247402453e7','碧戶','張泌','唐','唐诗','tang','','[]','碧戶扃魚鏁，蘭窗掩鏡臺。',120,'全唐诗/poet.tang.41000.json','["碧戶扃魚鏁，蘭窗掩鏡臺。", "落花疑悵望，歸燕自裴回。", "詠絮知難敵，傷春不易裁。", "恨從芳草起，愁爲晚風來。", "衣惹湘雲薄，眉分楚岫開。", "香濃眠舊枕，夢好醉春杯。", "小障明金鳳，幽屏點翠苔。", "寶箏橫塞鴈，怨笛落江梅。", "卓氏仍多酒，相如正富才。", "莫教琴上意，翻作鶴聲哀。"]'),
('f364b96e-c18c-4b10-afda-4e3fa15d810c','芍藥','張泌','唐','唐诗','tang','','[]','香清粉澹怨殘春，蝶翅蜂鬚戀蘂塵。',64,'全唐诗/poet.tang.41000.json','["香清粉澹怨殘春，蝶翅蜂鬚戀蘂塵。", "閑倚晚風生悵望，靜留遲日學因循。", "休將薜荔爲青瑣，好與玫瑰作近鄰。", "零落若教隨暮雨，又應愁殺別離人。"]'),
('1f7ad772-3ffa-475f-b711-3858e89a1541','春晚謠','張泌','唐','唐诗','tang','','[]','雨微微，煙霏霏，小庭半拆紅薔薇。',64,'全唐诗/poet.tang.41000.json','["雨微微，煙霏霏，小庭半拆紅薔薇。", "鈿箏斜倚畫屏曲，零落幾行金鴈飛。", "蕭關夢斷無尋處，萬疊春波起南浦。", "凌亂楊花撲繡簾，晚窗時有流鶯語。"]'),
('95270121-f720-408d-a4bd-106f52bd5578','所思','張泌','唐','唐诗','tang','','[]','空塘水碧春雨微，東風散漫楊柳飛。',96,'全唐诗/poet.tang.41000.json','["空塘水碧春雨微，東風散漫楊柳飛。", "依依南浦夢猶在，脈脈高唐雲不歸。", "江頭日暮多芳草，極目傷心煙悄悄。", "隔江紅杏一枝明，似玉佳人俯清沼。", "休向春臺更迴望，銷魂自古因惆悵。", "銀河碧海共無情，兩處悠悠起風浪。"]'),
('b4e2ef26-9f13-4339-9e5e-c75ba95ccaa1','春夕言懷','張泌','唐','唐诗','tang','','[]','風透疎簾月滿庭，倚欄無事倍傷情。',64,'全唐诗/poet.tang.41000.json','["風透疎簾月滿庭，倚欄無事倍傷情。", "煙垂柳帶纖腰軟，露滴花房怨臉明。", "愁逐野雲銷不盡，情隨春浪去難平。", "幽窗謾結相思夢，欲化西園蝶未成。"]'),
('a2251bf3-1fd1-44ee-8d12-49180f52e8d5','春江雨','張泌','唐','唐诗','tang','','[]','雨溟溟，風泠泠，老松瘦竹臨煙汀。',64,'全唐诗/poet.tang.41000.json','["雨溟溟，風泠泠，老松瘦竹臨煙汀。", "空江冷落野雲重，村中鬼火微如星。", "夜驚溪上漁人起，滴瀝篷聲滿愁耳。", "子規叫斷獨未眠，罨岸春濤打船尾。"]'),
('7d15acf8-4559-45ee-b860-f6f85d2bf6c1','送容州中丞赴鎮','張泌','唐','唐诗','tang','','[]','交趾同星坐，龍泉佩斗文。',48,'全唐诗/poet.tang.41000.json','["交趾同星坐，龍泉佩斗文。", "燒香翠羽帳，看舞鬱金裙。", "鷁首衝瀧浪，犀渠拂嶺雲。", "莫教銅柱北，祗說馬將軍。"]'),
('8d9ec1a3-a8f8-4dca-91c3-b9ac0f495747','贈韓道士','張泌','唐','唐诗','tang','','[]','日暮秋風吹野花，上清歸客意無涯。',64,'全唐诗/poet.tang.41000.json','["日暮秋風吹野花，上清歸客意無涯。", "桃源寂寂煙霞閉，天路悠悠星漢斜。", "還似世人生白髮，定知仙骨變黃芽。", "東城南陌頻相見，應是壺中別有家。"]'),
('dbbd40ba-bf9d-40cc-9e41-b9c911858946','甘露寺','孫魴','唐','唐诗','tang','','[]','寒暄皆有景，孤絕畫難形。',48,'全唐诗/poet.tang.41000.json','["寒暄皆有景，孤絕畫難形。", "地拱千尋嶮，天垂四面青。", "晝燈籠鴈塔，夜磬徹漁汀。", "最愛僧房好，波光滿戶庭。"]'),
('67bfae1b-6a28-47f5-a3d8-9c5c52c43b7e','題金山寺','孫魴','唐','唐诗','tang','','[]','萬古波心寺，金山名目新。',48,'全唐诗/poet.tang.41000.json','["萬古波心寺，金山名目新。", "天多剩得月，地少不生塵。", "過樐妨僧定，驚濤濺佛身。", "誰言張處士，題後更無人。"]'),
('b8fa90ac-0893-4543-8d54-714b5b810fd9','楊柳枝詞五首 一','孫魴','唐','唐诗','tang','','[]','靈和風暖太昌春，舞線搖絲向昔人。',32,'全唐诗/poet.tang.41000.json','["靈和風暖太昌春，舞線搖絲向昔人。", "何似曉來江雨後，一行如畫隔遙津。"]'),
('6008ef1c-8df1-43b9-9108-8f0ba028d032','楊柳枝詞五首 二','孫魴','唐','唐诗','tang','','[]','彭澤初栽五樹時，只應閑看一枝垂。',32,'全唐诗/poet.tang.41000.json','["彭澤初栽五樹時，只應閑看一枝垂。", "不知天意風流處，要與佳人學畫眉。"]'),
('47439efa-8a39-41ff-8c99-d621e1e5d621','楊柳枝詞五首 三','孫魴','唐','唐诗','tang','','[]','暖傍離亭靜拂橋，入流穿檻綠陰搖。',32,'全唐诗/poet.tang.41000.json','["暖傍離亭靜拂橋，入流穿檻綠陰搖。", "不知落日誰相送，魂斷千條與萬條。"]'),
('3fdaac82-19ca-43f0-95d2-2c978a405eaa','楊柳枝詞五首 四','孫魴','唐','唐诗','tang','','[]','春來綠樹遍天涯，未見垂楊未可誇。',32,'全唐诗/poet.tang.41000.json','["春來綠樹遍天涯，未見垂楊未可誇。", "晴日萬株煙一陣，閑坊兼是莫愁家。"]'),
('b68ad0d3-e3e0-41de-9688-d7b4686f3e03','楊柳枝詞五首 五','孫魴','唐','唐诗','tang','','[]','十首當年有舊詞，唱青歌翠幾無遺。',32,'全唐诗/poet.tang.41000.json','["十首當年有舊詞，唱青歌翠幾無遺。", "未曾得向行人道，不謂離情莫折伊。"]'),
('9c6ced2c-8a6c-4be4-b4d5-297a9cdd2b0d','句','孫魴','唐','唐诗','tang','','[]','遊子未歸去，野花愁破心。',64,'全唐诗/poet.tang.41000.json','["遊子未歸去，野花愁破心。", "劃多灰漸冷，坐久席成痕。", "結宇孤峰上，安禪巨浪間。", "分開朝海浪，留住過江雲。", "劃多灰雜蒼虯跡，坐久煙消寶鴨香。"]'),
('f5042001-bf58-4636-bfe6-0a99c4ee7920','入塞二首 一','沈彬','唐','唐诗','tang','','[]','欲爲皇王服遠戎，萬人金甲鼓鼙中。',64,'全唐诗/poet.tang.41000.json','["欲爲皇王服遠戎，萬人金甲鼓鼙中。", "陣雲黯塞三邊黑，兵血愁天一片紅。", "半夜翻營旗攪月，深秋防戍劒磨風。", "謗書未及明君爇，臥骨將軍已歿功。"]'),
('290c46a3-d66e-4a6c-be75-97cd9a91b7ec','入塞二首 二','沈彬','唐','唐诗','tang','','[]','苦戰沙門臥箭痕，戍樓閑上望星文。',64,'全唐诗/poet.tang.41000.json','["苦戰沙門臥箭痕，戍樓閑上望星文。", "生希國澤分偏將，死奪河源荅聖君。", "鳶覰敗兵眠白草，馬驚邊鬼哭陰雲。", "功多地遠無人紀，漢閣笙歌日又曛。"]'),
('20d2c7b0-1b43-450e-a5b5-ac0c58bf1d32','塞下三首 一','沈彬','唐','唐诗','tang','','[]','塞葉聲悲秋欲霜，寒山數點下牛羊。',64,'全唐诗/poet.tang.41000.json','["塞葉聲悲秋欲霜，寒山數點下牛羊。", "映霞旅鴈隨疎雨，向磧行人帶夕陽。", "邊騎不來沙路失，國恩深後海城荒。", "胡兒向化新成長，猶自千回問漢王。"]'),
('5bcb3149-2569-415c-9882-0e90c56a4198','塞下三首 二','沈彬','唐','唐诗','tang','','[]','貴主和親殺氣沉，燕山閑獵鼓鼙音。',64,'全唐诗/poet.tang.41000.json','["貴主和親殺氣沉，燕山閑獵鼓鼙音。", "旗分雪草偷邊馬，箭入寒雲落塞禽。", "隴月盡牽鄉思動，戰衣誰寄淚痕深。", "金釵謾作封侯別，劈破佳人萬里心。"]'),
('157c973d-0652-41e7-84e4-39488103a905','塞下三首 三','沈彬','唐','唐诗','tang','','[]','月冷榆關過鴈行，將軍寒笛老思鄉。',64,'全唐诗/poet.tang.41000.json','["月冷榆關過鴈行，將軍寒笛老思鄉。", "貳師骨恨千夫壯，李廣魂飛一劒長。", "戍角就沙催落日，陰雲分磧護飛霜。", "誰知漢武輕中國，閑奪天山草木荒。"]'),
('b152a308-22b9-4f18-86a5-975a93cf9a02','秋日','沈彬','唐','唐诗','tang','','[]','秋含砧杵擣斜陽，笛引西風顥氣涼。',64,'全唐诗/poet.tang.41000.json','["秋含砧杵擣斜陽，笛引西風顥氣涼。", "薜荔惹煙籠蟋蟀，芰荷翻雨潑鴛鴦。", "當年酒賤何妨醉，今日時難不易狂。", "腸斷舊遊從一別，潘安惆悵滿頭霜。"]'),
('086aff2d-11ac-4c35-abbb-99e446f6049b','金陵雜題二首 一','沈彬','唐','唐诗','tang','','[]','王氣生秦四百年，晉元東渡浪花船。',64,'全唐诗/poet.tang.41000.json','["王氣生秦四百年，晉元東渡浪花船。", "正慙海內皆塗地，來保江南一片天。", "古樹著行臨遠岸，暮山相亞出微煙。", "千征萬戰英雄盡，落日牛羊食野田。"]'),
('e7ab6598-5092-4968-9701-cf8430fcd747','金陵雜題二首 二','沈彬','唐','唐诗','tang','','[]','暮潮聲落草光沉，賈客來帆宿岸陰。',64,'全唐诗/poet.tang.41000.json','["暮潮聲落草光沉，賈客來帆宿岸陰。", "一笛月明何處酒，滿城秋色幾家砧。", "時清曾惡桓溫盛，山翠長牽謝傅心。", "今日到來何物在，碧煙和雨鎖寒林。"]'),
('7a78535e-067d-42b5-ac8c-e6259e6d9120','麻姑山','沈彬','唐','唐诗','tang','','[]','紺殿松蘿太古山，仙人曾此話桑田。',64,'全唐诗/poet.tang.41000.json','["紺殿松蘿太古山，仙人曾此話桑田。", "閑傾雲液十分日，已過浮生一萬年。", "花洞路中逢鶴信，水簾巖底見龍眠。", "我來遊禮酬心願，欲共怡神契自然。"]'),
('f570916f-2c46-439a-934b-1dd7fd6fe27d','題蘇仙山','沈彬','唐','唐诗','tang','','[]','眼穿林罅見郴州，井里交連側局揪。',64,'全唐诗/poet.tang.41000.json','["眼穿林罅見郴州，井里交連側局揪。", "味道不來閑處坐，勞生更欲幾時休。", "蘇仙宅古煙霞老，義帝墳荒草木愁。", "千古是非無處問，夕陽西去水東流。"]'),
('c81bf6a5-7217-4d74-a255-3fd02f5b217b','洪州解至長安初舉納省卷夢仙謠','沈彬','唐','唐诗','tang','','[]','□□□□□□□，□□□□□□□。',64,'全唐诗/poet.tang.41000.json','["□□□□□□□，□□□□□□□。", "玉殿大開從客入，金桃爛熟沒人偷。", "鳳驚寶扇頻翻翅，龍懼金鞭不轉頭。", "□□□□□□□，□□□□□□□。"]'),
('ae03b7a3-56e4-42da-a842-7bc5b9dd0143','憶仙謠','沈彬','唐','唐诗','tang','','[]','白榆風颯九天秋，王母朝迴宴玉樓。',64,'全唐诗/poet.tang.41000.json','["白榆風颯九天秋，王母朝迴宴玉樓。", "日月漸長雙鳳睡，桑田欲變六鼇愁。", "雲翻簫管相隨去，星觸旌幢各自流。", "詩酒近來狂不得，騎龍却憶上清遊。"]'),
('863c7f41-2575-48f8-921a-f440ef000fd5','納省卷贈爲首劉象','沈彬','唐','唐诗','tang','','[]','曾應大中天子舉，四朝風月鬢蕭疎。',64,'全唐诗/poet.tang.41000.json','["曾應大中天子舉，四朝風月鬢蕭疎。", "不隨世祖重攜劒，却爲文皇再讀書。", "十載戰塵銷舊業，滿城春雨壞貧居。", "一枝何事於君借，仙桂年年幸有餘。"]'),
('f7153f24-aa84-49ab-9465-882f218b4d47','贈王定保','沈彬','唐','唐诗','tang','','[]','仙桂曾攀第一枝，薄遊湘水阻佳期。',64,'全唐诗/poet.tang.41000.json','["仙桂曾攀第一枝，薄遊湘水阻佳期。", "皋橋已失齊眉願，蕭寺行逢落髮師。", "廢苑露寒蘭寂寞，丹山雲斷鳳參差。", "聞公已有平生約，謝絕女蘿依兔絲。"]'),
('4b68cd1b-481e-4221-b1ad-1dc2726a4444','結客少年場行','沈彬','唐','唐诗','tang','','[]','重義輕生一劒知，白虹貫日報讎歸。',32,'全唐诗/poet.tang.41000.json','["重義輕生一劒知，白虹貫日報讎歸。", "片心惆悵清平世，酒市無人問布衣。"]'),
('e75c94fe-9831-4e84-8ac9-d9f13fca6e7c','陽朔碧蓮峰','沈彬','唐','唐诗','tang','','[]','陶潛彭澤五株柳，潘岳河陽一縣花。',32,'全唐诗/poet.tang.41000.json','["陶潛彭澤五株柳，潘岳河陽一縣花。", "兩處爭如陽朔好，碧蓮峰裏住人家。"]'),
('aabb49fb-8b7b-4e18-94a6-432cef88809e','再過金陵','沈彬','唐','唐诗','tang','','[]','玉樹歌終王氣收，鴈行高送石城秋。',32,'全唐诗/poet.tang.41000.json','["玉樹歌終王氣收，鴈行高送石城秋。", "江山不管興亡事，一任斜陽伴客愁。"]'),
('cd457b7c-c294-4584-aeb5-0a9f6a9d0abc','都門送別','沈彬','唐','唐诗','tang','','[]','岸柳蕭疎野荻秋，都門行客莫回頭。',32,'全唐诗/poet.tang.41000.json','["岸柳蕭疎野荻秋，都門行客莫回頭。", "一條灞水清如劒，不爲離人割斷愁。"]'),
('b70654da-93ab-49be-a55c-e6e1a448bc2f','弔邊人','沈彬','唐','唐诗','tang','','[]','殺聲沈後野風悲，漢月高時望不歸。',32,'全唐诗/poet.tang.41000.json','["殺聲沈後野風悲，漢月高時望不歸。", "白骨已枯沙上草，家人猶自寄寒衣。"]'),
('6f6bfc7d-4dba-4362-92ae-3f8b75f47e6a','句','沈彬','唐','唐诗','tang','','[]','尺素隱清輝，一毫分險阻。',172,'全唐诗/poet.tang.41000.json','["尺素隱清輝，一毫分險阻。", "金翅動身摩日月，銀河轉浪洗乾坤。", "須知手筆安排定，不怕山河整頓難。", "九衢冠蓋暗爭路，四海干戈多異心。", "地隈一水巡城轉，天約羣山附郭來。", "數家魚網疎雲外，一岸殘陽細雨中。", "松欹晚影離壇草，鍾撼秋聲入殿風。", "壓低吳楚遙涵水，約破雲霞獨倚天。", "半身落日離秦樹，一路平蕪入楚煙。", "清占月中三峽水，麗偷雲外十洲春。", "幽鳥喚人穿竹去，野猨尋果出雲來。"]'),
('4f152091-a91d-48b6-bd6c-cbee22b0a6e1','僻居謝何明府見訪','伍喬','唐','唐诗','tang','','[]','公退琴堂動逸懷，閑披煙靄訪微才。',64,'全唐诗/poet.tang.41000.json','["公退琴堂動逸懷，閑披煙靄訪微才。", "馬嘶窮巷蛙聲息，轍到衡門草色開。", "風引柳花當坐起，日將林影入庭來。", "滿齋塵土一牀蘚，多謝從容水飯回。"]'),
('7494a841-ad4c-4b1b-8f73-2ebd1e72c678','冬日道中','伍喬','唐','唐诗','tang','','[]','去去天涯無定期，瘦童羸馬共依依。',64,'全唐诗/poet.tang.41000.json','["去去天涯無定期，瘦童羸馬共依依。", "暮煙江口客來絕，寒葉嶺頭人住稀。", "帶雪野風吹旅思，入雲山火照行衣。", "釣臺吟閣滄洲在，應爲初心未得歸。"]'),
('c20f1cf3-7397-4688-bc15-69a3568e6a32','僻居酬友人','伍喬','唐','唐诗','tang','','[]','僻居雖愛近林泉，幽徑閑居碧蘚連。',64,'全唐诗/poet.tang.41000.json','["僻居雖愛近林泉，幽徑閑居碧蘚連。", "向竹掩扉隨鶴息，就溪安石學僧禪。", "古琴帶月音聲亮，山果經霜氣味全。", "多謝故交憐朴野，隔雲時復寄佳篇。"]'),
('d6f29aa5-cd84-4277-888f-aecc2564f287','遊西山龍泉禪寺','伍喬','唐','唐诗','tang','','[]','疊巘層峰坐可觀，枕門流水更潺湲。',64,'全唐诗/poet.tang.41000.json','["疊巘層峰坐可觀，枕門流水更潺湲。", "曉鐘聲徹洞溪遠，夏木影籠軒檻寒。", "幽徑乍尋衣屨潤，古堂頻宿夢魂安。", "因嗟城郭營營事，不得長遊空鬢殘。"]'),
('cc225000-4487-4cdf-a286-1712d1430359','宿灊山','伍喬','唐','唐诗','tang','','[]','一入仙山萬慮寬，夜深寧厭倚虛欄。',64,'全唐诗/poet.tang.41000.json','["一入仙山萬慮寬，夜深寧厭倚虛欄。", "鶴和雲影宿高木，人帶月光登古壇。", "芝朮露濃溪塢白，薜蘿風起殿廊寒。", "更陪羽客論真理，不覺初鐘叩曉殘。"]'),
('5dc7fef5-4f90-4815-983f-b9bcc6ec5319','遊西禪','伍喬','唐','唐诗','tang','','[]','遠岫當軒列翠光，高僧一衲萬緣忘。',64,'全唐诗/poet.tang.41000.json','["遠岫當軒列翠光，高僧一衲萬緣忘。", "碧松影裏地長潤，白藕花中水亦香。", "雲自雨前生淨石，鶴于鐘後宿長廊。", "遊人戀此吟終日，盛暑樓臺早有涼。"]'),
('63cdc527-e8e1-4e86-9bef-b588b95c6a77','寄史處士','伍喬','唐','唐诗','tang','','[]','長羨閑居一水湄，吟情高古有誰知。',64,'全唐诗/poet.tang.41000.json','["長羨閑居一水湄，吟情高古有誰知。", "石樓待月橫琴久，漁浦經風下釣遲。", "僻塢落花多掩徑，舊山殘燒幾侵籬。", "松門別後無消息，早晚重應躡屐隨。"]'),
('a4b9cdc9-2df8-4f2d-ad6e-531b9195a2a6','僻居秋思寄友人','伍喬','唐','唐诗','tang','','[]','門巷秋歸更寂寥，雨餘閑砌委蘭苗。',64,'全唐诗/poet.tang.41000.json','["門巷秋歸更寂寥，雨餘閑砌委蘭苗。", "夢迴月夜蟲吟壁，病起茅齋藥滿瓢。", "澤國舊遊關遠思，竹林前會負佳招。", "身名未立猶辛苦，何許流年晚鬢凋。"]'),
('632d07c5-6525-4196-93e4-5b24454d8f56','寄落星史虛白處士','伍喬','唐','唐诗','tang','','[]','白雲峰下古溪頭，曾與提壺爛熳遊。',64,'全唐诗/poet.tang.41000.json','["白雲峰下古溪頭，曾與提壺爛熳遊。", "登閣共看彭蠡水，圍爐相憶杜陵秋。", "棊玄不厭通高品，句妙多容隔歲酬。", "別後相思時一望，暮山空碧水空流。"]'),
('fd7dc655-f2b7-4d55-a22d-644d948029c2','九江旅夜寄山中故人','伍喬','唐','唐诗','tang','','[]','弱柳風高遠漏沈，坐來難便息愁吟。',64,'全唐诗/poet.tang.41000.json','["弱柳風高遠漏沈，坐來難便息愁吟。", "江城雪盡寒猶在，客舍燈孤夜正深。", "塵土積年粘旅服，關山無處寄歸心。", "此時遙羨閑眠侶，靜掩雲扉臥一林。"]'),
('62155306-fe70-407d-ac08-2899a415c685','聞杜牧赴闕','伍喬','唐','唐诗','tang','','["\u5e90\u5c71"]','舊隱匡廬一草堂，今聞攜策謁吾皇。',64,'全唐诗/poet.tang.41000.json','["舊隱匡廬一草堂，今聞攜策謁吾皇。", "峽雲難卷從龍勢，古劒終騰出土光。", "開翅定期歸碧落，濯纓寧肯問滄浪。", "他時得意交知仰，莫忘裁詩寄釣鄉。"]'),
('9d9752ea-5b07-4abe-b122-9c9eec79018f','題西林寺水閣','伍喬','唐','唐诗','tang','','[]','竹翠苔花遶檻濃，此亭幽致詎曾逢。',64,'全唐诗/poet.tang.41000.json','["竹翠苔花遶檻濃，此亭幽致詎曾逢。", "水分林下清泠派，山峙雲間峭峻峰。", "怪石夜光寒射燭，老杉秋韻冷和鐘。", "不知來往留題客，誰約重尋蓮社蹤。"]'),
('767bfcd3-38a2-4389-9d28-1a2e7130c556','林居喜崔三博遠至','伍喬','唐','唐诗','tang','','[]','幾日區區在遠程，晚煙林徑喜相迎。',64,'全唐诗/poet.tang.41000.json','["幾日區區在遠程，晚煙林徑喜相迎。", "姿容雖有塵中色，巾屨猶多嶽上清。", "野石靜排爲坐榻，溪茶深煮當飛觥。", "留連話與方經宿，又欲攜書別我行。"]'),
('4b5384ea-655c-42e8-8c10-8c23b1052adb','觀華夷圖','伍喬','唐','唐诗','tang','','[]','別手應難及此精，須知攢簇自心靈。',64,'全唐诗/poet.tang.41000.json','["別手應難及此精，須知攢簇自心靈。", "始於毫末分諸國，漸見圖中列四溟。", "關路欲伸通楚勢，蜀山俄聳入秦青。", "筆端盡現寰區事，堪把長懸在戶庭。"]'),
('e11e8ffc-4319-444f-82a5-2c25278313b0','廬山書堂送祝秀才還鄉','伍喬','唐','唐诗','tang','','["\u5e90\u5c71"]','束書辭我下重巔，相送同臨楚岸邊。',64,'全唐诗/poet.tang.41000.json','["束書辭我下重巔，相送同臨楚岸邊。", "歸思幾隨千里水，離情空寄一枝蟬。", "園林到日酒初熟，庭戶開時月正圓。", "莫使蹉跎戀疎野，男兒酬志在當年。"]'),
('d41bbb2a-034f-49f4-ac90-8d28ee950dff','暮冬送何秀才毘陵','伍喬','唐','唐诗','tang','','[]','匹馬嘶風去思長，素琴孤劒稱戎裝。',64,'全唐诗/poet.tang.41000.json','["匹馬嘶風去思長，素琴孤劒稱戎裝。", "路塗多是過殘歲，杯酒無辭到醉鄉。", "雲傍水村凝冷片，雪連山驛積寒光。", "毘陵城下饒嘉景，回日新詩應滿堂。"]'),
('7e0f6a68-3de1-43d9-9082-5b22105d6ce4','龍潭張道者','伍喬','唐','唐诗','tang','','[]','碧洞幽巖獨息心，時人何路得相尋。',64,'全唐诗/poet.tang.41000.json','["碧洞幽巖獨息心，時人何路得相尋。", "養生不說憑諸藥，適意惟聞在一琴。", "石徑掃稀山蘚合，竹軒開晚野雲深。", "他年功就期飛去，應笑吾徒多苦吟。"]'),
('5bf81790-cdb7-4594-80e0-6c44f5b207a6','晚秋同何秀才溪上','伍喬','唐','唐诗','tang','','[]','閑步秋光思杳然，荷藜因共過林煙。',64,'全唐诗/poet.tang.41000.json','["閑步秋光思杳然，荷藜因共過林煙。", "期收野藥尋幽路，欲採溪菱上小船。", "雲吐晚陰藏霽岫，柳含餘靄咽殘蟬。", "倒尊盡日忘歸處，山磬數聲敲暝天。"]'),
('7c844e4d-97d3-46e3-897a-602b2563f7cb','送江少府授延陵後寄','伍喬','唐','唐诗','tang','','[]','五老雲中勤學者，遇時能不困風塵。',64,'全唐诗/poet.tang.41000.json','["五老雲中勤學者，遇時能不困風塵。", "束書西上謁明主，捧檄南歸慰老親。", "別館友朋留醉久，去程煙月入吟新。", "莫因官小慵之任，自古鸞棲有異人。"]'),
('db3c7284-fb92-4162-b328-c52150776aff','觀山水障子','伍喬','唐','唐诗','tang','','[]','功績精妍世少倫，圖時應倍用心神。',64,'全唐诗/poet.tang.41000.json','["功績精妍世少倫，圖時應倍用心神。", "不知草木承何異，但見江山長帶春。", "雲勢似離巖底石，浪花如動岸邊蘋。", "更疑獨泛漁舟者，便是其中舊隱人。"]'),
('22250f74-1f08-4851-8b93-f51fb76ff0c6','寄張學士洎','伍喬','唐','唐诗','tang','','["\u9ec4\u5c71"]','不知何處好消憂，公退攜壺即上樓。',64,'全唐诗/poet.tang.41000.json','["不知何處好消憂，公退攜壺即上樓。", "職事久參侯伯幕，夢魂長遶帝王州。", "黃山向晚盈軒翠，黟水含春繞檻流。", "遙想玉堂多暇日，花時誰伴出城遊。"]'),
('95aa7d67-4586-43af-ae6c-939e063eb174','句','伍喬','唐','唐诗','tang','','[]','積靄沈諸壑，微陽在半峰。',12,'全唐诗/poet.tang.41000.json','["積靄沈諸壑，微陽在半峰。"]'),
('7998713e-9c69-45f3-8ff0-4f71075ec528','塞下曲 一','陳陶','唐','唐诗','tang','','[]','邊頭能走馬，猨臂李將軍。',48,'全唐诗/poet.tang.41000.json','["邊頭能走馬，猨臂李將軍。", "射虎羣胡伏，開弓絕塞聞。", "海山諳向背，攻守別風雲。", "只爲坑降罪，輕車未轉勳。"]'),
('d4f9ad57-baa9-46d9-b5b4-afd8387fe3f2','塞下曲 二','陳陶','唐','唐诗','tang','','[]','望湖關下戰，雜虜喪全師。',48,'全唐诗/poet.tang.41000.json','["望湖關下戰，雜虜喪全師。", "鳥啄豺狼將，沙埋日月旗。", "牛羊奔赤狄，部落散燕耆。", "都護凌晨出，銘功瘞死屍。"]'),
('583c83e5-adde-43cf-b506-cf121cab2702','胡無人行','陳陶','唐','唐诗','tang','','[]','十萬羽林兒，臨洮破郅支。',48,'全唐诗/poet.tang.41000.json','["十萬羽林兒，臨洮破郅支。", "殺添胡地骨，降足漢營旗。", "塞闊牛羊散，兵休帳幕移。", "空流隴頭水，嗚咽向人悲。"]'),
('6dc3008f-956b-4769-987a-6eea6c4a5772','悲哉行','陳陶','唐','唐诗','tang','','[]','中嶽仇先生，遺余餌松方。',72,'全唐诗/poet.tang.41000.json','["中嶽仇先生，遺余餌松方。", "服之一千日，肢體生異香。", "步履如風旋，天涯不齎糧。", "仍云爲地仙，不得朝虛皇。", "狡兔有三穴，人生又何常。", "悲哉二廉士，餓死於首陽。"]'),
('04e71ad9-545c-4fc2-916c-452c9a7c9044','塗山懷古','陳陶','唐','唐诗','tang','','[]','落拓書劍晚，清秋鷹正籠。',288,'全唐诗/poet.tang.41000.json','["落拓書劍晚，清秋鷹正籠。", "塗山間來上，敬愛如登龍。", "覽古覺神王，翛然天地空。", "東南更何有，一醉先王風。", "惟昔放勳世，陰晦徹成洪。", "皇圖化魚鱉，天道漂無蹤。", "帝乃命舟檝，掇芳儒素中。", "高陳九州力，百道驅歸東。", "舊物復光明，洪爐再埏鎔。", "經門不私子，足知天下公。", "亮曰那並生，唐虞禪華蟲。", "茲山朝萬國，一賦寰海同。", "十載有區宇，秋豪皆帝功。", "垂衣不驕德，子桀如何聾。", "握髮聞禮賢，葺茅見卑宮。", "凡夫色難事，神聖安能恭。", "道隱三千年，遺芳播笙鏞。", "當時執圭處，佳氣仍童童。", "海嶼儼清廟，天人盛祇供。", "玄恩及花木，丹讖名崆峒。", "異代草澤臣，何由樹勳庸。", "堯階未曾識，誰信平生忠。", "恨不當際會，預爲執鞭僮。", "勞歌下山去，懷德心無窮。"]'),
('b9eb4794-629c-4a16-bf0a-df0a2fe122cc','遊子吟','陳陶','唐','唐诗','tang','','[]','栖烏喜林曙，驚蓬傷歲闌。',132,'全唐诗/poet.tang.41000.json','["栖烏喜林曙，驚蓬傷歲闌。", "關河三尺雪，何處是天山？", "朔風無重衣，僕馬飢且寒。", "慘慼別妻子，遲回出門難。", "男兒值休明，豈是長泥蟠。", "何者爲木偶，何人侍金鑾。", "鬱鬱守貧賤，悠悠亦無端。", "進不圖功名，退不處巖巒。", "窮通在何日，光景如跳丸。", "富貴苦不早，令人摧心肝。", "誓期春之陽，一振摩霄翰。"]'),
('4bd11e3a-cbd2-4a8f-a783-14b1235efce9','懷仙吟二首 一','陳陶','唐','唐诗','tang','','[]','丹陵五牙客，昨日羅浮歸。',72,'全唐诗/poet.tang.41000.json','["丹陵五牙客，昨日羅浮歸。", "赤斧尋不得，煙霞空滿衣。", "試於華陽問，果遇三茅知。", "採藥向十洲，同行牧羊兒。", "十洲隔八海，浩渺不可期。", "留空雙白鶴，巢在長松枝。"]'),
('93942fe1-3ef2-4b0b-ab0d-37321c495221','懷仙吟二首 二','陳陶','唐','唐诗','tang','','[]','雲溪古流水，春晚桃花香。',84,'全唐诗/poet.tang.41000.json','["雲溪古流水，春晚桃花香。", "憶與我師別，片帆歸滄浪。", "滄浪在何許，相思淚如雨。", "黃鶴不復來，雲深難別處。", "石渠泉泠泠，三見菖蒲生。", "日夜勞夢魂，隨波注東溟。", "空懷別時惠，長讀消魔經。"]'),
('d086f658-6b6c-47c3-bbb7-52e0423bd1fb','海昌望月','陳陶','唐','唐诗','tang','','[]','何處無今夕，豈期在海頭。',288,'全唐诗/poet.tang.41000.json','["何處無今夕，豈期在海頭。", "賈客不愛月，嬋娟閑滄洲。", "浩然傷歲華，獨望湖邊樓。", "煙島青歷歷，藍田白悠悠。", "誰無破鏡期，繄我信虛舟。", "誰無桂枝念，繄我方摧輈。", "始見彎環春，又逢團圓秋。", "莫厭綾扇夕，百年多銀鉤。", "今盤誰雕鐫，玉窟難冥搜。", "重輪運時節，三五不自由。", "疑拋雲上鍋，欲摟天邊毬。", "孀居應寒冷，擣藥青冥愁。", "兔子樹下蹲，蝦𢋙池中遊。", "如何名金波，不共水東流。", "天花辟膻腥，野雲無邊陬。", "蚌蛤乘大運，含珠相對醻。", "夜鵲思南鄉，露華清東甌。", "百寶安可覰，老龍鎖深湫。", "究究如情人，盜者即仇讎。", "海涯上皎潔，九門更清幽。", "亭亭勸金尊，夜久喘吳牛。", "夷俗皆輕擲，北山思今遊。", "鴈聲故鄉來，客淚墮南洲。", "平生煙霞志，讀書覓封侯。"]'),
('019b5d9c-e3f9-4677-bb1a-4b3fe4fd566f','蒲門戍觀海作','陳陶','唐','唐诗','tang','','[]','廓落溟漲曉，蒲門鬱蒼蒼。',120,'全唐诗/poet.tang.41000.json','["廓落溟漲曉，蒲門鬱蒼蒼。", "登樓禮東君，旭日生扶桑。", "毫釐見蓬瀛，含吐金銀光。", "草木露未晞，蜃樓氣若藏。", "欲遊蟠桃國，慮涉魑魅鄉。", "徐市惑秦朝，何人在巖廊。", "惜哉千童子，葬骨於眇茫。", "恭聞槎客言，東池接天潢。", "即此聘牛女，曰祈長壽方。", "靈津水清淺，余亦慕脩航。"]'),
('99a5a849-e231-4a45-bbf2-7c9a0f2fb800','番禺道中作','陳陶','唐','唐诗','tang','','[]','博羅程遠近，海塞愁先入。',96,'全唐诗/poet.tang.41000.json','["博羅程遠近，海塞愁先入。", "瘴雨出虹蝀，蠻江渡山急。", "常聞島夷俗，犀象滿城邑。", "鴈至草猶春，潮迴檣半濕。", "丹丘鳳皇隱，水廟蛟龍集。", "何處樹能言，幾鄉珠是泣。", "千年趙佗國，霸氣委原隰。", "齷齪笑終軍，長纓禍先及。"]'),
('648892e4-0445-43b7-875c-2a74ac94f4fe','贈江西周大夫','陳陶','唐','唐诗','tang','','[]','否極生大賢，九元降靈氣。',228,'全唐诗/poet.tang.41000.json','["否極生大賢，九元降靈氣。", "獨立正始風，蔚然中興瑞。", "淵倫照三古，磊落涵涇渭。", "真貌月懸秋，雄詞雷出地。", "具瞻先皇寵，欲踐東華貴。", "咫尺時不來，千秋鼎湖淚。", "因分三輔職，進領南平位。", "報政黃霸慙，提兵呂蒙醉。", "歲星臨斗牛，水國嘉祥至。", "不獨蒼生蘇，仍兼六騶喜。", "恭聞廟堂畧，欲斷匈奴臂。", "剗釋自宸衷，平戍在連帥。", "時康簪笏宂，世梗忠良議。", "丘壑非無人，松香有私志。", "三朝倚天劍，十萬浮雲騎。", "可使河曲清，羣公信兒戲。", "滄溟用謙德，百谷走童稚。", "禦衆付深人，參籌須偉器。", "他年蓬蓽賤，願附鵷鸞翅。"]'),
('dbed85c7-6651-4656-9717-439f3e143008','旅次銅山途中先寄溫州韓使君','陳陶','唐','唐诗','tang','','[]','亂山滄海曲，中有橫陽道。',120,'全唐诗/poet.tang.41000.json','["亂山滄海曲，中有橫陽道。", "束馬過銅梁，苕華坐堪老。", "鳩鳴高崖裂，熊鬬深樹倒。", "絕壑無坤維，重林失蒼昊。", "躋攀寡儔侶，扶接念輿皁。", "俛仰慄嵌空，無因掇靈草。", "梯窮聞戍鼓，魂續賴丘禱。", "敞豁天地歸，縈紆村落好。", "悠悠思蔣徑，擾擾愧商皓。", "馳想永嘉侯，應傷此懷抱。"]'),
('048c5e95-a0ed-4bd8-a606-22b5583063eb','種蘭','陳陶','唐','唐诗','tang','','[]','種蘭幽谷底，四遠聞馨香。',228,'全唐诗/poet.tang.41000.json','["種蘭幽谷底，四遠聞馨香。", "春風長養深，枝葉趁人長。", "智水潤其根，仁鋤護其芳。", "蒿藜不生地，惡鳥弓已藏。", "椒桂夾四隅，茅茨居中央。", "左鄰桃花塢，右接蓮子塘。", "一月薰手足，兩月薰衣裳。", "三月薰肌骨，四月薰心腸。", "幽人飢如何，採蘭充餱糧。", "幽人渴如何，醞蘭爲酒漿。", "地無青苗租，白日如散王。", "不嘗仙人藥，端坐紅霞房。", "日夕望美人，佩花正煌煌。", "美人久不來，佩花徒生光。", "刈穫及葳蕤，無令見雪霜。", "清芬信神鬼，一葉豈可忘。", "舉頭愧青天，鼓腹詠時康。", "下有賢公卿，上有聖明王。", "無階荅風雨，願獻蘭一筐。"]'),
('c97e5b6d-627f-437a-8306-fb8fdb5daa00','草木言','陳陶','唐','唐诗','tang','','[]','何生我蒼蒼，何育我黃黃。',216,'全唐诗/poet.tang.41000.json','["何生我蒼蒼，何育我黃黃。", "草木無知識，幸君同三光。", "始自受姓名，葳蕤立衣裳。", "山河既分麗，齊首乳青陽。", "甘辛各有榮，好醜不相防。", "常憂刀斧劫，竊慕仁壽鄉。", "願天雨無暴，怨地風無狂。", "雨足因衰憊，風多因夭傷。", "在山不爲桂，徒辱君高岡。", "在水不爲蓮，徒占君深塘。", "勿輕培塿阜，或有奇棟梁。", "勿輕蒙朧澤，或有奇馨香。", "涓毫可蔍差，朝菌壽爲長。", "擁腫若無取，大椿命爲傷。", "婆娑不材生，苒苒向秋荒。", "幸遭薰風日，有得皆簸揚。", "所愧雨露恩，願效幽微芳。", "希君頻採擇，勿使枯雪霜。"]'),
('476c46a7-0017-4e5e-8fb0-f181122b0a85','題僧院紫竹','陳陶','唐','唐诗','tang','','[]','喜遊蛟井寺，復見炎州竹。',288,'全唐诗/poet.tang.41000.json','["喜遊蛟井寺，復見炎州竹。", "杳靄萬丈間，嘯風清獨速。", "江南正霜霰，吐秀弄顓頊。", "似瑞驚堅貞，如魔試金粟。", "笋非孝子泣，文異湘靈哭。", "金碧誰與鄰，蕭森自成族。", "新聞赤帝種，子落毛人谷。", "遠祖賜鷦鵬，遺芳遍南陸。", "對煙蘇麻醜，夾澗篔簹伏。", "美譽動丹青，瓌姿豔秦蜀。", "因緣鹿苑識，想像虵丘斸。", "幾葉別黃茅，何年依白足。", "龍樹蟄一花，砌瑤掃雲屋。", "色靜曼仙花，名高給孤獨。", "青蔥太子樹，灑落觀音目。", "法雨每霑濡，玉毫時照燭。", "離居鸞節變，住冷金顏縮。", "豈念葛陂榮，幸無祖父辱。", "光搖水精串，影送蓮花軸。", "江鶩日相尋，野鶚時寄宿。", "幽香入茶竈，靜翠直碁局。", "肯羨垣上蒿，自多籬下菊。", "從來道生一，況伴龜藏六。", "棲託詎星迴，檀欒已雲矗。"]'),
('9a167b83-dfad-444e-aa45-5bf87970c26f','早發始興','陳陶','唐','唐诗','tang','','[]','雲裏山已曙，舟中火初爇。',49,'全唐诗/poet.tang.41000.json','["雲裏山已曙，舟中火初爇。", "綠浦待行橈，玄猨催落月。", "沿流信多美，況復秋風發。", "挂席借前期，晨雞莫嘲异常。"]'),
('09cdbdb6-a239-4e77-ad7a-32ae4e670d71','寄元孚道人','陳陶','唐','唐诗','tang','','[]','梵宇章句客，佩蘭三十年。',120,'全唐诗/poet.tang.41000.json','["梵宇章句客，佩蘭三十年。", "長乘碧雲馬，時策翰林鞭。", "曩事五岳遊，金衣曳祥煙。", "高攀桐君手，左倚鸑鷟肩。", "哭玉秋雨中，摘星春風前。", "橫輈截洪偃，憑几見廣宣。", "爾來寤華胥，石壁孤雲眠。", "龍降始得偈，龜老方巢蓮。", "內殿無文僧，驅虞誰能牽。", "因之問楚水，弔屈幾潺湲。"]'),
('f0d24ebf-a86c-4b4a-b7df-064d65a758d3','和西江李助副使早登開元寺閣','陳陶','唐','唐诗','tang','','[]','虛豁登寶閣，三休極層構。',192,'全唐诗/poet.tang.41000.json','["虛豁登寶閣，三休極層構。", "獨立天地間，煙雲滿襟袖。", "鰲荒初落日，劍野呈綺繡。", "秋檻祝融微，陰軒九江湊。", "拂簷皇姑舍，錯落白榆秀。", "倚砌天竺祠，蛟龍蟠古甃。", "翛然觀六合，一指齊宇宙。", "書劍忽若□，青雲日方晝。", "南朝空蒼莽，楚澤稀耕耨。", "萬事溺頹波，一航安可涭。", "徒云寄麟泣，六五終難就。", "資斧念餘生，湖光隱圭竇。", "早聞羣黃鶴，飄舉此江岫。", "陵谷空靄然，人樵已雛𪆪。", "燕宮豸冠客，憑覽發清奏。", "珠玉難嗣音，摐轅愧孤陋。"]'),
('f862ecfb-744f-4c1b-bc6b-6205f0abf0d0','將歸鍾陵留贈南海李尚書','陳陶','唐','唐诗','tang','','["\u957f\u6c5f"]','楚國有田舍，炎州長夢歸。',120,'全唐诗/poet.tang.41000.json','["楚國有田舍，炎州長夢歸。", "懷恩似秋燕，屢遶玉堂飛。", "越酒豈不甘，海魚寧無肥。", "山裘醉歌舞，事與初心違。", "曄曄文昌公，英靈世間稀。", "長江浩無際，龍蜃皆歸依。", "賤子感一言，草茅發光輝。", "從來雞鳧質，得假鳳皇威。", "常欲討玄珠，青雲報巍巍。", "龍門竟多故，雙淚別旍旂。"]'),
('330789f9-0bba-41a8-b252-b393eb087e30','宿島徑夷山舍','陳陶','唐','唐诗','tang','','[]','百里遵鳥徑，蓬征信邅迴。',120,'全唐诗/poet.tang.41000.json','["百里遵鳥徑，蓬征信邅迴。", "暝依漁樵宿，似過黃金臺。", "缺齧心未理，寥寥夜猨哀。", "山深石牀冷，海近腥氣來。", "主人意不淺，屢獻流霞杯。", "對月撫長劍，愁襟紛莫開。", "九衢平如水，胡爲涉崔崽。", "一飯未遑飽，鵬圖信悠哉。", "山濤謔細君，吾豈厭蓬萊。", "明發又驅馬，客思一裴回。"]'),
('e7cbadbd-992a-4775-8904-704dbce0472c','避世翁','陳陶','唐','唐诗','tang','','[]','海上一蓑笠，終年垂釣絲。',132,'全唐诗/poet.tang.41000.json','["海上一蓑笠，終年垂釣絲。", "滄洲有深意，冠盡何由知。", "直鉤不營魚，蝸室無妻兒。", "渴飲寒泉水，飢飡紫朮芝。", "鶴髮披兩肩，高懷如澄陂。", "曾聞仙老言，云是古鴟夷。", "石竇閟雷雨，金潭養蛟螭。", "乘槎上玉津，騎鹿遊峨嵋。", "以人爲語默，與世爲雄雌。", "茲焉乃磻溪，豹變應須時。", "自古隱淪客，無非王者師。"]'),
('f4536fdf-0f9c-4143-a815-799ddbea5616','冬夜吟','陳陶','唐','唐诗','tang','','[]','黑夜天寒愁散玉，東皇海上張仙燭。',112,'全唐诗/poet.tang.41000.json','["黑夜天寒愁散玉，東皇海上張仙燭。", "侯家歌舞按梨園，石氏賓寮醉金谷。", "魯家襜褕闇披水，雪花燈下甘垂翅。", "散帙高編折桂枝，披紗密甃青雲地。", "霜白溪松轉斜盡，銅龍喚曙咽聲細。", "八埏螻蟻厭寒栖，早晚青旗引春帝。", "展轉城烏啼紫天，曈曚千騎衙樓前。"]'),
('8bcf0682-f605-4338-aeb8-8a7b8fbb3ea7','西川座上聽金五雲唱歌','陳陶','唐','唐诗','tang','','[]','蜀王殿上華筵開，五雲歌從天上來。',320,'全唐诗/poet.tang.41000.json','["蜀王殿上華筵開，五雲歌從天上來。", "滿堂羅綺悄無語，喉音止駐雲裴回。", "管弦金石還依轉，不隨歌出靈和殿。", "白雲飄颻席上聞，貫珠歷歷聲中見。", "舊樣釵箆淺澹衣，元和梳洗青黛眉。", "低叢小鬢膩䰀鬌，碧牙鏤掌山參差。", "曲終暫起更衣過，還向南行座頭坐。", "低眉欲語謝貴侯，檀臉雙雙淚穿破。", "自言本是宮中嬪，武皇改號承恩新。", "中丞御史不足比，水殿一聲愁殺人。", "武皇鑄鼎登真籙，嬪御蒙恩免幽辱。", "茂陵弓劍不得親，嫁與卑官到西蜀。", "卑官到官年未周，堂衡祿罷東西遊。", "蜀江水急駐不得，復此萍蓬二十秋。", "今朝得侍王侯宴，不覺途中妾身賤。", "願持巵酒更唱歌，歌是伊州第三遍。", "唱著右丞征戍詞，更聞閨月添相思。", "如今聲韻尚如在，何況宮中年少時。", "五雲處處可憐許，明朝道向襃中去。", "須臾宴罷各東西，雨散雲飛莫知處。"]'),
('974f6f40-7fe3-443d-afde-d7bc58518c4d','飛龍引','陳陶','唐','唐诗','tang','','[]','有熊之君好神仙，飡霞鍊石三千年。',240,'全唐诗/poet.tang.41000.json','["有熊之君好神仙，飡霞鍊石三千年。", "一旦黃龍下九天，騎龍枿枿昇紫煙。", "萬姓攀髯髯墮地，啼呼弓劍飄寒水。", "紫鸞八九墮玉笙，金鏡空留照魑魅。", "羽幢䙰褷銀漢秋，六宮望斷芙蓉愁。", "應龍下揮中園笑，泓泓水遶青苔洲。", "瑞風颯遝天光淺，瑤闕峨峨橫露苑。", "沆瀣樓頭紫鳳歌，三株樹下青牛飯。", "鴻朧九闕相玉皇，鈞天樂引金華郎。", "散花童子鶴衣短，投壺姹女蛾眉長。", "彤庭侍宴瑤池席，老兔春高桂宮白。", "蓬萊下國賜分珪，阿母金桃容小摘。", "仙流萬緘蟲篆春，三十六洞交風雲。", "千年小兆一蟬蛻，丹臺職亞扶桑君。", "金烏試浴青門水，下界蜉蝣幾迴死。"]'),
('4206d8e7-8082-4dbf-81bd-f2a24ee5ff65','謫仙詞','陳陶','唐','唐诗','tang','','[]','牧龍丈人病高秋，羣童擊節星漢愁。',96,'全唐诗/poet.tang.41000.json','["牧龍丈人病高秋，羣童擊節星漢愁。", "瑤臺鳳輦不勝恨，太古一聲龍白頭。", "玉氣蘭光久摧折，上清雞犬音書絕。", "蜺旌失手遠於天，三島空雲對秋月。", "人間磊磊浮漚客，鸑鷟蜻蜓飛自隔。", "不應冠蓋逐黃埃，長夢真君舊恩澤。"]'),
('0c96eac3-db45-4401-b970-5a705cd7ccf1','步虛引','陳陶','唐','唐诗','tang','','[]','小隱山人十洲客，莓苔爲衣雙耳白。',64,'全唐诗/poet.tang.41000.json','["小隱山人十洲客，莓苔爲衣雙耳白。", "青編爲我忽降書，暮雨虹蜺一千尺。", "赤城門閉六丁直，曉日已燒東海色。", "朝天半夜聞玉雞，星斗離離礙龍翼。"]'),
('0fbb78a0-756c-4dc0-9737-0e7ca0b3b23b','獨搖手','陳陶','唐','唐诗','tang','','[]','漢宮新燕矜蛾眉，春臺豔妝蓮一枝。',112,'全唐诗/poet.tang.41000.json','["漢宮新燕矜蛾眉，春臺豔妝蓮一枝。", "迎春侍宴瑤華池，游龍七盤嬌欲飛。", "冶袖鶯鸞拂朝曦，摩煙褭雪金碧遺。", "愁鴻連翾蠶曳絲，颯遝明珠掌中移。", "仙人龍鳳雲雨吹，朝哀暮愁引啞吚。", "鴛鴦翡翠承宴私，南山一笑君無辭。", "仙蛾泣月清露垂，六宮燒燭愁風欷。"]'),
('d8b0950e-f1b5-4df6-8bb5-f85d3b225ba9','空城雀','陳陶','唐','唐诗','tang','','[]','古城濛濛花覆水，昔日住人今住鬼。',96,'全唐诗/poet.tang.41000.json','["古城濛濛花覆水，昔日住人今住鬼。", "野雀荒臺遺子孫，千年飲啄枯桑根。", "不隨海燕栢梁去，應無玉環銜報恩。", "近村紅栗香壓枝，嗷嗷黃口訴朝飢。", "生來未見鳳皇語，欲飛常怕蜘蛛絲。", "斷腸四隅天四絕，清泉綠蒿無恐疑。"]'),
('14b13d2d-52e5-4bd5-81b8-bfbc66d473c1','雞鳴曲','陳陶','唐','唐诗','tang','','[]','雞聲春曉上林中，一聲驚落蝦蟆宮。',64,'全唐诗/poet.tang.41000.json','["雞聲春曉上林中，一聲驚落蝦蟆宮。", "二聲喚破枕邊夢，三聲行人煙海紅。", "平旦慵將百雛語，蓬鬆錦繡當陽處。", "媿君飲食長相呼，爲君晝鳴下高樹。"]'),
('3ebe2384-902c-4ca0-8b57-9be9810a3ee8','小笛弄','陳陶','唐','唐诗','tang','','[]','一尺玲瓏握中翠，僊娥月浦呼龍子。',96,'全唐诗/poet.tang.41000.json','["一尺玲瓏握中翠，僊娥月浦呼龍子。", "五夜流珠粲夢卿，九青鸞倚洪崖醉。", "丹穴飢兒笑風雨，媧皇碧玉星星語。", "蛇蝎愁聞骨髓寒，江山恨老眠秋霧。", "綺席鴛鴦冷朱翠，星流露泫誰驅使。", "江南一曲罷伶倫，芙蓉水殿春風起。"]'),
('b5e8694b-fcaa-405b-9aee-7f349acb85ba','將進酒','陳陶','唐','唐诗','tang','','[]','金尊莫倚青春健，齷齪浮生如走電。',208,'全唐诗/poet.tang.41000.json','["金尊莫倚青春健，齷齪浮生如走電。", "琴瑟盤傾從世珠，黃泥局瀉流年箭。", "麻姑爪禿瞳子昏，東皇肉角生魚鱗。", "靈鼇柱骨半枯朽，驪龍德悔愁耕人。", "周孔蓍龜久淪沒，黃蒿誰認賢愚骨。", "兔苑詞才去不還，蘭亭水石空明月。", "姮娥弄簫香雨收，江濱迸瑟魚龍愁。", "靈芝九折楚蓮醉，翾風一歎梁庭秋。", "醁亞蠻觥奉君壽，玉山三獻春紅透。", "銀鴨金鵝言待誰，隋家嶽瀆皇家有。", "珊瑚座上凌香雲，鳳𦢙龍炙猩猩脣。", "芝蘭此日不傾倒，南山白石皆賢人。", "文康調笑麒麟起，一曲飛龍壽天地。"]'),
('27fbe408-088e-4920-9d5f-f2299cf6e406','錢塘對酒曲','陳陶','唐','唐诗','tang','','[]','風天鴈悲西陵愁，使君紅旗弄濤頭。',128,'全唐诗/poet.tang.41000.json','["風天鴈悲西陵愁，使君紅旗弄濤頭。", "東海神魚騎未得，江天大笑閑悠悠。", "嵯峨吳山莫誇碧，河陽經年一宵白。", "南州彩鳳爲君生，古獄愁蛇待恩澤。", "三清羽童來何遲，十二玉樓胡蝶飛。", "炎荒翡翠九門去，遼東白鶴無歸期。", "鴟夷公子休悲悄，六鼇如鏡天始老。", "尊前事去月團圓，琥珀無情憶蘇小。"]'),
('70033607-8695-4ddf-8415-95e397a912a1','巫山高','陳陶','唐','唐诗','tang','','[]','玉峰青雲十二枝，金母和雲賜瑤姬。',96,'全唐诗/poet.tang.41000.json','["玉峰青雲十二枝，金母和雲賜瑤姬。", "花宮磊砢楚宮外，列仙八面星斗垂。", "秀色無雙怨三峽，春風幾夢襄王獵。", "青鸞不在嬾吹簫，斑竹題詩寄江妾。", "飄颻絲散巴子天，苔裳玉轡紅霞幡。", "歸時白帝掩青瑣，瓊枝草草遺湘煙。"]'),
('8f81e2fb-0bcb-4365-9d36-999534046f0c','贈別離','陳陶','唐','唐诗','tang','','[]','碧玉飛天星墜地，玉劍分風交合水。',128,'全唐诗/poet.tang.41000.json','["碧玉飛天星墜地，玉劍分風交合水。", "楊柳聽歌莫向隅，雞鳴一石留髠醉。", "蹄輪送客溝水東，月娥揮手崦嵫峰。", "蠻天列嶂儼相待，風官掃道迎遊龍。", "天姥翦霞鋪曉空，漴漴大帝開明宮。", "文鯨掉尾四海通，分明瀑布收靈桐。", "山妖水魅騎旋風，魘夢齧魂黃瘴中。", "借君郎鑒入崆峒，靈光草照閑花紅。"]'),
('fe49f210-ed7f-439c-a8df-756ba2227f9d','關山月','陳陶','唐','唐诗','tang','','[]','昔年嫖姚護羌月，今照嫖姚雙鬢雪。',96,'全唐诗/poet.tang.41000.json','["昔年嫖姚護羌月，今照嫖姚雙鬢雪。", "青塚曾無尺寸歸，錦書多記窮荒骨。", "百戰金瘡體沙磧，鄉心一片懸秋碧。", "漢城應期破鏡時，胡塵萬里嬋娟隔。", "度磧衝雲朔風起，邊笳欲晚生青珥。", "隴上橫吹霜色刀，何年斷得匈奴臂。"]'),
('6feada2f-0a48-43fd-a7d9-7fb596c168ac','殿前生桂樹','陳陶','唐','唐诗','tang','','[]','僊娥玉宮秋夜明，桂枝拂檻參差瓊。',87,'全唐诗/poet.tang.41000.json','["僊娥玉宮秋夜明，桂枝拂檻參差瓊。", "香風下天漏丁丁，牛渚翠梁橫淺清羽帳不眠恨吹笙。", "棲烏暗驚僊子落，步月鬃雲墮金雀。", "蕙樓涼簟翠波空，銀縷香寒鳳皇薄。", "東海即爲郎斟酌，綺疏長懸七星杓。"]'),
('cc9f6be9-9e5a-4d3d-ad56-c238bfadf182','古鏡篇','陳陶','唐','唐诗','tang','','[]','紫皇玉鏡蟾蜍字，墮地千年光不死。',96,'全唐诗/poet.tang.41000.json','["紫皇玉鏡蟾蜍字，墮地千年光不死。", "發匣身沈古井寒，懸臺日照愁成水。", "海戶山窗幾梳綰，菱花開落何人見。", "野老曾耕太白星，神狐夜哭秋天片。", "下國青銅旋磨滅，迴鸞萬影成枯骨。", "會待搏風雨泬寥，長恐莓苔蝕明月。"]'),
('8ea14f72-3f11-4539-b96e-29d929795c5c','自歸山','陳陶','唐','唐诗','tang','','[]','海嶽南歸遠，天門北望深。',48,'全唐诗/poet.tang.41000.json','["海嶽南歸遠，天門北望深。", "暫爲青瑣客，難換白雲心。", "富貴老閑事，猨猱思舊林。", "清平無樂志，尊酒有瑤琴。"]'),
('ed947551-41bc-4ba5-8f98-6af180c94e30','渡浙江','陳陶','唐','唐诗','tang','','[]','適越一輕艘，凌兢截鷺濤。',48,'全唐诗/poet.tang.41000.json','["適越一輕艘，凌兢截鷺濤。", "曙光金海近，晴雪玉峰高。", "靜寇思投筆，傷時欲釣鼇。", "壯心殊未展，登涉漫勞勞。"]'),
('ac47d94a-9419-47aa-8c99-8f2576f26014','清源途中旅思','陳陶','唐','唐诗','tang','','[]','古木閩州道，驅羸落照間。',48,'全唐诗/poet.tang.41000.json','["古木閩州道，驅羸落照間。", "投村礙野水，問店隔荒山。", "身事幾時了，蓬飄何日閑。", "看花滯南國，鄉月十灣環。"]'),
('be10b6ed-de06-41a1-9b2c-d1ac2d0cf030','南海送韋七使君赴象州任','陳陶','唐','唐诗','tang','','[]','一鶚韋公子，新恩頒郡符。',48,'全唐诗/poet.tang.41000.json','["一鶚韋公子，新恩頒郡符。", "島夷通荔浦，龍節過蒼梧。", "地理金城近，天涯玉樹孤。", "聖朝朱紱貴，從此展雄圖。"]'),
('308ad3c5-3e00-486c-977a-3d4d8856a491','送沈次魯南遊','陳陶','唐','唐诗','tang','','[]','高臺贈君別，滿握軒轅風。',48,'全唐诗/poet.tang.41000.json','["高臺贈君別，滿握軒轅風。", "落日一揮手，金鵝雲雨空。", "鼇洲石梁外，劍浦羅浮東。", "茲興不可接，翛翛煙際鴻。"]'),
('6d7867e8-e871-47cb-ac71-74353002129b','南海石門戍懷古','陳陶','唐','唐诗','tang','','["\u957f\u6c5f"]','漢家征百越，落地喪貔貅。',48,'全唐诗/poet.tang.41000.json','["漢家征百越，落地喪貔貅。", "大野朱旗沒，長江赤血流。", "鬼神尋覆族，宮廟變荒丘。", "唯有朝臺月，千年照戍樓。"]'),
('9be23822-1874-4fe2-9cce-1c6c3b575e78','賦得池塘生春草','陳陶','唐','唐诗','tang','','[]','謝公遺詠處，池水夾通津。',48,'全唐诗/poet.tang.41000.json','["謝公遺詠處，池水夾通津。", "古往人何在，年來草自春。", "色宜波際綠，香異雨中新。", "今日青青意，空悲行路人。"]'),
('a3744ebb-4ad3-4d3b-a14d-2ee08c8a64c6','題居上人法華新院','陳陶','唐','唐诗','tang','','[]','浮名深般若，方寺設蓮華。',48,'全唐诗/poet.tang.41000.json','["浮名深般若，方寺設蓮華。", "鐘唄成僧國，湖山稱法家。", "一塵多寶塔，千佛大牛車。", "能誘泥犂客，超然識聚沙。"]'),
('0202807d-de46-42fb-8ad2-c96e39c68cf1','送秦鍊師','陳陶','唐','唐诗','tang','','[]','紫府靜沈沈，松軒思別吟。',48,'全唐诗/poet.tang.41000.json','["紫府靜沈沈，松軒思別吟。", "水流寧有意，雲泛本無心。", "錦洞桃花遠，青山竹葉深。", "不因時賣藥，何路更相尋。"]'),
('bad27ccb-c4fd-42f9-aa46-32af21b13e67','哭寶月三藏大禪師','陳陶','唐','唐诗','tang','','[]','五峰習聖罷，乾竺化身歸。',48,'全唐诗/poet.tang.41000.json','["五峰習聖罷，乾竺化身歸。", "帝子傳真印，門人哭寶衣。", "一囊窮海沒，三藏故園稀。", "無復天花落，悲風滿鐵圍。"]'),
('c303e3cb-470e-47b7-8655-dffbbed2344a','湓城贈別','陳陶','唐','唐诗','tang','','[]','楚岸青楓樹，長隨送遠心。',48,'全唐诗/poet.tang.41000.json','["楚岸青楓樹，長隨送遠心。", "九江春水闊，三峽暮雲深。", "氣調桓伊笛，才華蔡琰琴。", "迢迢嫁湘漢，誰不重黃金。"]'),
('76117075-1764-4768-a954-869643d0add0','贈別','陳陶','唐','唐诗','tang','','[]','海國一尺綺，冰壺萬縷絲。',48,'全唐诗/poet.tang.41000.json','["海國一尺綺，冰壺萬縷絲。", "以君西攀桂，贈此金蓮枝。", "高鳥思茂林，窮魚樂洿池。", "平生握中寶，無使歲寒移。"]'),
('d679efa3-fd35-4eca-b0a9-a3e00a012f3d','贈溫州韓使君','陳陶','唐','唐诗','tang','','[]','康樂風流五百年，永嘉鈴閣又登賢。',64,'全唐诗/poet.tang.41000.json','["康樂風流五百年，永嘉鈴閣又登賢。", "嚴城鼓動魚驚海，華屋尊開月下天。", "內使筆鋒光案牘，鄢陵詩句滿山川。", "今來誰似韓家貴，越絕髦幢鴈影連。"]'),
('909587dd-d2cc-462f-a880-a95a0247ca46','閑居寄太學盧景博士','陳陶','唐','唐诗','tang','','[]','無路青冥奪錦袍，恥隨黃雀住蓬蒿。',64,'全唐诗/poet.tang.41000.json','["無路青冥奪錦袍，恥隨黃雀住蓬蒿。", "碧雲夢後山風起，珠樹詩成海月高。", "久滯鼎書求羽翼，未忘龍闕致波濤。", "閑來長得留侯癖，羅列樝梨校六韜。"]'),
('6bf6d2fe-ad76-4adb-a3c7-864af3ecca48','贈漳州張怡使君','陳陶','唐','唐诗','tang','','[]','舊德徐方天下聞，當年熊軾繼清芬。',64,'全唐诗/poet.tang.41000.json','["舊德徐方天下聞，當年熊軾繼清芬。", "井田異政光蠻竹，符節深恩隔瘴雲。", "已見嘉祥生北戶，嘗嫌夷貊蠹南薰。", "幾時徴拜征西越，學著縵胡從使君。"]'),
('4869ee5f-5e0b-4655-a719-a6fc23c3e51a','贈容南韋中丞','陳陶','唐','唐诗','tang','','[]','普寧都護軍威重，九驛梯航壓要津。',64,'全唐诗/poet.tang.41000.json','["普寧都護軍威重，九驛梯航壓要津。", "十二銅魚尊畫戟，三千犀甲擁朱輪。", "風雲已靜西山寇，閭井全移上國春。", "不獨來蘇發歌詠，天涯半是泣珠人。"]'),
('1a69282d-59c4-4f42-9e3e-b10f9eddfded','投贈福建路羅中丞','陳陶','唐','唐诗','tang','','[]','越豔聽謠不厭聽，樓船高臥靜南溟。',64,'全唐诗/poet.tang.41000.json','["越豔聽謠不厭聽，樓船高臥靜南溟。", "未聞建水窺龍劍，應喜家山接女星。", "三捷楷模光典策，一生封爵笑丹青。", "皇恩幾日西歸去，玉樹扶疎正滿庭。"]'),
('37ec0ef0-0965-40a5-803c-ab1df0cdf3e1','贈江南李偕副使','陳陶','唐','唐诗','tang','','[]','世祿三朝壓鳳池，杜陵公子漢庭知。',64,'全唐诗/poet.tang.41000.json','["世祿三朝壓鳳池，杜陵公子漢庭知。", "雷封始賀堂溪劍，花府尋邀玉樹枝。", "幾日坐談誅叛逆，列城歸美見歌詩。", "從軍莫厭千場醉，即是金鑾寵命時。"]'),
('bb20e9e2-d9b8-4e4c-a395-9196d6445b5e','賀容府韋中丞大府賢兄新除黔南經略','陳陶','唐','唐诗','tang','','[]','蓬瀛簪笏舊聯行，紫極差池降寵章。',64,'全唐诗/poet.tang.41000.json','["蓬瀛簪笏舊聯行，紫極差池降寵章。", "列國山河分鴈字，一門金玉盡龍驤。", "耿家符節朝中美，袁氏芝蘭閫外香。", "烽戍悠悠限巴越，佇聽歌詠兩甘棠。"]'),
('9a1020f0-280a-4b1d-a130-38f6fea786e4','和容南韋中丞題瑞亭白燕白鼠六眸龜嘉蓮','陳陶','唐','唐诗','tang','','[]','伏波恩行動南夷，交趾喧傳四瑞詩。',64,'全唐诗/poet.tang.41000.json','["伏波恩行動南夷，交趾喧傳四瑞詩。", "燕鼠孕靈褒上德，龜蓮增耀荅無私。", "迴翔雪侶窺簷處，照映紅巢出水時。", "盡寫流傳在軒檻，嘉祥從此百年知。"]'),
('c9c851de-5244-47ea-a802-4ed7a00b1373','題豫章西山香城寺','陳陶','唐','唐诗','tang','','[]','十地嚴宮禮竺皇，栴檀樓閣半天香。',64,'全唐诗/poet.tang.41000.json','["十地嚴宮禮竺皇，栴檀樓閣半天香。", "祇園樹老梵聲小，雪嶺花香燈影長。", "霄漢落泉供月界，蓬壺靈鳥侍雲房。", "何年七七金人降，金錫珠壇滿上方。"]'),
('f877d66f-07d9-47ba-b345-28a0562320bf','送江西周尚書赴滑臺','陳陶','唐','唐诗','tang','','[]','楚謠襦袴整三千，喉舌新恩下九天。',64,'全唐诗/poet.tang.41000.json','["楚謠襦袴整三千，喉舌新恩下九天。", "天角雄都分節鉞，蛟龍舊國罷樓船。", "崑河已在兵鈐內，棠樹空留鶴嶺前。", "多病無因酬一顧，鄢陵千騎去翩翩。"]'),
('b763fd08-f084-4e54-814b-f5f553efa039','閩中送任畹端公還京','陳陶','唐','唐诗','tang','','[]','燕臺下榻玉爲人，月桂曾輸次第春。',64,'全唐诗/poet.tang.41000.json','["燕臺下榻玉爲人，月桂曾輸次第春。", "幾日酬恩坐炎瘴，九秋高駕拂星辰。", "漢庭鳳進鵷行喜，隋國珠還水府貧。", "多少嘉謨奏風俗，斗牛孤劍在平津。"]'),
('fa551a8f-8244-4f17-baee-6a36e92debd7','豫章江樓望西山有懷','陳陶','唐','唐诗','tang','','[]','水護星壇列太虛，煙霓十八上仙居。',64,'全唐诗/poet.tang.41000.json','["水護星壇列太虛，煙霓十八上仙居。", "時人未識遼東鶴，吾祖曾傳寶鼎書。", "終日章江催白鬢，何年丹竈見紅蕖。", "桃花谷口春深淺，欲訪仙生赤鯉魚。"]'),
('e224b97a-15a6-4e61-9877-c49ec52b017d','經徐穉墓','陳陶','唐','唐诗','tang','','[]','郟鄏妖興炎漢衰，先生南國臥明夷。',64,'全唐诗/poet.tang.41000.json','["郟鄏妖興炎漢衰，先生南國臥明夷。", "鳳皇屢降玄纁禮，瓊石終藏烈火詩。", "禁掖衣冠加宋鵲，湖山耕釣沒堯時。", "千年壠樹何人哭，寂寞蒼苔內史碑。"]'),
('63e8c19b-9c04-4505-be11-3f6aff8d5dab','鍾陵道中作','陳陶','唐','唐诗','tang','','[]','原隰經霜蕙草黃，塞鴻消息怨流芳。',64,'全唐诗/poet.tang.41000.json','["原隰經霜蕙草黃，塞鴻消息怨流芳。", "秋山落照見麋鹿，南國異花開雪霜。", "煙火近通槃瓠俗，水雲深入武陵鄉。", "曾逢齧缺話東海，長憶蕭家青玉牀。"]'),
('b133f02f-3ce8-4101-9fc6-1fa2ab75cb8e','旅泊塗江','陳陶','唐','唐诗','tang','','[]','煙雨南江一葉微，松潭漁父夜相依。',64,'全唐诗/poet.tang.41000.json','["煙雨南江一葉微，松潭漁父夜相依。", "斷沙鴈起金精出，孤嶺猨愁木客歸。", "楚國柑橙勞夢想，丹陵霞鶴間音徽。", "無因得似滄溟叟，始憶離巢已倦飛。"]'),
('3349da10-4e46-4f99-bbdd-d1da751c4885','上建溪','陳陶','唐','唐诗','tang','','[]','崆垌一派瀉蒼煙，長揖丹丘逐水仙。',64,'全唐诗/poet.tang.41000.json','["崆垌一派瀉蒼煙，長揖丹丘逐水仙。", "雲樹杳冥通上界，峰巒迴合下閩川。", "侵星愁過蛟龍國，採碧時逢婺女船。", "已判猨催鬢先白，幾重灘瀨在秋天。"]'),
('57ef90df-c659-45db-b20d-f5f6d83b8d88','冬日暮旅泊廬陵','陳陶','唐','唐诗','tang','','[]','螺亭倚棹哭飄蓬，白浪欺船自向東。',64,'全唐诗/poet.tang.41000.json','["螺亭倚棹哭飄蓬，白浪欺船自向東。", "楚國蕙蘭增悵望，番禺筐篚旅虛空。", "江城雪落千家夢，汀渚冰生一夕風。", "棄置侯鯖任羇束，不勞龜瓦問窮通。"]'),
('bade2217-9882-453c-82a6-6c3990f29c07','登寶曆寺閣','陳陶','唐','唐诗','tang','','[]','金碧高層世界空，憑蜺長嘯八鑾風。',64,'全唐诗/poet.tang.41000.json','["金碧高層世界空，憑蜺長嘯八鑾風。", "橫軒水壯蛟龍府，倚棟星開牛斗宮。", "三楚故墟殘景北，六朝荒苑斷山東。", "不堪懷古勞悲笑，安得鵬摶顥氣中。"]'),
('8192d135-ab8a-4c70-94c3-c7c2c91e6a04','寄兵部任畹郎中','陳陶','唐','唐诗','tang','','[]','常思劍浦越清塵，荳蔻花紅十二春。',64,'全唐诗/poet.tang.41000.json','["常思劍浦越清塵，荳蔻花紅十二春。", "崑玉已成廊廟器，澗松猶是薜蘿身。", "雖同橘柚依南土，終媿魁罡近北辰。", "好向昌時薦遺逸，莫教千古弔靈均。"]'),
('deb61665-75ea-4fdb-83b8-230e99a1a337','贈江南從事張侍郎','陳陶','唐','唐诗','tang','','[]','平南門館鳳皇毛，二十華軒立最高。',64,'全唐诗/poet.tang.41000.json','["平南門館鳳皇毛，二十華軒立最高。", "幾處談天致雲雨，早時文海得鯨鼇。", "姻聯紫府蕭窗貴，職稱青錢繡服豪。", "江徼無虞才不展，銜杯終日詠離騷。"]'),
('e472f7a2-a62b-4dbd-9ea2-61a1e2e6796e','劍池','陳陶','唐','唐诗','tang','','[]','秦帝南巡厭火精，蒼黃埋劍故豐城。',64,'全唐诗/poet.tang.41000.json','["秦帝南巡厭火精，蒼黃埋劍故豐城。", "霸圖繚戾金龍螫，坤道扶搖紫氣生。", "星斗臥來閑窟穴，雌雄飛去變澄泓。", "永懷惆悵中宵作，不見春雷發匣聲。"]'),
('b6bfe501-f496-4ddb-a5a5-798774a3b308','洛城見賀自真飛昇','陳陶','唐','唐诗','tang','','[]','子晉鸞飛古洛川，金桃再熟賀郎仙。',64,'全唐诗/poet.tang.41000.json','["子晉鸞飛古洛川，金桃再熟賀郎仙。", "三清樂奏嵩丘下，五色雲屯御苑前。", "朱頂舞低迎絳節，青鬟歌對駐香軿。", "誰能白晝相悲泣，太極光陰億萬年。"]'),
('c3069b13-ab5c-4804-a913-2effef02da1c','謫仙吟贈趙道士','陳陶','唐','唐诗','tang','','[]','汗漫東遊黃鶴雛，縉雲仙子住清都。',64,'全唐诗/poet.tang.41000.json','["汗漫東遊黃鶴雛，縉雲仙子住清都。", "三元麟鳳推高座，六甲風雷閟小壺。", "日月暗資靈壽藥，山河擬作化生符。", "若爲失意居蓬島，鼇足塵飛桑樹枯。"]'),
('b8e18db0-a45a-4b71-8049-4bdcd39f3ebb','夜別溫商梓州','陳陶','唐','唐诗','tang','','[]','鳳皇城裏花時別，玄武江邊月下逢。',64,'全唐诗/poet.tang.41000.json','["鳳皇城裏花時別，玄武江邊月下逢。", "客舍莫辭先買酒，相門曾忝舊登龍。", "迎風騷屑千家竹，隔水悠揚午夜鐘。", "明日又行西蜀去，不堪天際遠山重。"]'),
('2b4ff908-f093-4ae2-9b02-281c0a276aba','題贈高閑上人','陳陶','唐','唐诗','tang','','[]','簷蔔花間客，軒轅席上珍。',192,'全唐诗/poet.tang.41000.json','["簷蔔花間客，軒轅席上珍。", "筆江秋菡萏，僧國瑞麒麟。", "內殿初招隱，曹溪得後塵。", "龍蛇驚粉署，花雨對金輪。", "白馬方依漢，朱星又入秦。", "劇談凌鑿齒，清論倒波旬。", "拂石先天古，降龍舊國春。", "珠還合浦老，龍去玉州貧。", "鴛鷺輸黃絹，場壇遶白萍。", "鼎湖閑入夢，金閣靜通神。", "海氣成方丈，山泉落淨巾。", "獼猴深愛月，鷗鳥不猜人。", "拂岳蕭蕭竹，垂空澹澹津。", "漢珠難覓對，荆璞本來真。", "伊傅多聯壁，劉雷競買鄰。", "江邊有國寶，時爲劚星辰。"]'),
('397074bf-946f-46a2-9fde-29f95206e3a4','哭王贊府','陳陶','唐','唐诗','tang','','[]','白水流今古，青山送死生。',144,'全唐诗/poet.tang.41000.json','["白水流今古，青山送死生。", "驅馳三楚掾，倏忽一空名。", "金玉埋臯壤，芝蘭哭弟兄。", "龍頭孤後進，鵬翅失前程。", "愁變風雲色，悲連鼓角聲。", "落星辭聖代，寒夢閉佳城。", "伊昔來江邑，從容副國英。", "德踰棲棘美，公亞飲冰清。", "大廈亡孤直，羣儒憶老成。", "白駒悲里巷，梁木慟簪纓。", "隴遂添新草，珠還滿舊籝。", "蒼蒼難可問，原上晚煙橫。"]'),
('df825dfe-e82c-475c-b6eb-56a5e9b4d22c','聖帝撃壤歌四十聲','陳陶','唐','唐诗','tang','','[]','百六承堯緒，艱難土運昌。',288,'全唐诗/poet.tang.41000.json','["百六承堯緒，艱難土運昌。", "太虛橫彗孛，中野鬬豺狼。", "帝曰更吾嗣，時哉憶聖唐。", "英星垂將校，神嶽誕忠良。", "鍊石醫元氣，屠鼇正昊蒼。", "掃原鋪一德，驅祲立三光。", "大道重蘇息，真風再發揚。", "芟夷踰舊跡，神聖掩前王。", "郊酒酣寥廓，鴻恩受渺茫。", "地圖龜負出，天誥鳳銜將。", "雜貢來山峙，羣夷入鴈行。", "紫泥搜海岱，鴻筆富巖廊。", "鷹象敷宸極，寰瀛作瑞坊。", "泥丸封八表，金鏡照中央。", "構殿基麟趾，開藩表鳳翔。", "鑾輿親稼穡，朱幌務蠶桑。", "戎羯輸天馬，靈仙侍玉房。", "宮儀水蒐甲，門衛綠沈槍。", "陶鑄超三古，車書混萬方。", "時巡望虞舜，蒐狩法殷湯。", "化合謳謠滿，年豐鬼蜮藏。", "政源歸牧馬，宮法付神羊。", "寶鼎無靈應，金甌肯破傷。", "封山昭茂績，祠執荅嘉祥。"]'),
('58108e36-179c-458c-a56c-5eac25ca1361','續古二十九首 一','陳陶','唐','唐诗','tang','','[]','大堯登寶位，麟鳳煥宸居。',24,'全唐诗/poet.tang.41000.json','["大堯登寶位，麟鳳煥宸居。", "海曲霑恩澤，還生比目魚。"]'),
('d3dab92e-971c-4b58-aa57-8a9056565911','續古二十九首 二','陳陶','唐','唐诗','tang','','[]','生值揖遜曆，長歌東南春。',24,'全唐诗/poet.tang.41000.json','["生值揖遜曆，長歌東南春。", "釣鼇年三十，未見天子巡。"]'),
('1221ddba-00e2-481b-96cc-2b4a4c3ee725','續古二十九首 三','陳陶','唐','唐诗','tang','','[]','軒轅承化日，羣鳳戲池臺。',24,'全唐诗/poet.tang.41000.json','["軒轅承化日，羣鳳戲池臺。", "大樸衰喪後，仲尼生不來。"]'),
('5646c461-6390-4cd9-9336-a7f85075989b','續古二十九首 四','陳陶','唐','唐诗','tang','','[]','大道歸孟門，蕭蘭日爭長。',24,'全唐诗/poet.tang.41000.json','["大道歸孟門，蕭蘭日爭長。", "想得巢居時，碧江應無浪。"]'),
('1401ae10-7e8f-4628-b28f-d0e7340a7aa5','續古二十九首 五','陳陶','唐','唐诗','tang','','[]','矻矻蓬舍下，慕君麒麟閣。',24,'全唐诗/poet.tang.41000.json','["矻矻蓬舍下，慕君麒麟閣。", "笑殺王子喬，寥天乘白鶴。"]'),
('81c7ece0-7291-41e7-b35b-42f4836b2a61','續古二十九首 六','陳陶','唐','唐诗','tang','','[]','杳杳巫峽雲，悠悠漢江水。',24,'全唐诗/poet.tang.41000.json','["杳杳巫峽雲，悠悠漢江水。", "愁殺幾少年，春風相憶地。"]'),
('aa29b562-619a-4fe1-9cfa-9bf42a9e67b0','續古二十九首 七','陳陶','唐','唐诗','tang','','[]','吳洲采芳客，桂棹木蘭船。',24,'全唐诗/poet.tang.41000.json','["吳洲采芳客，桂棹木蘭船。", "日晚欲有寄，裴回春風前。"]'),
('accf07a9-0972-44a2-9564-bb805856dd7e','續古二十九首 八','陳陶','唐','唐诗','tang','','[]','仙家風景晏，浮世年華速。',24,'全唐诗/poet.tang.41000.json','["仙家風景晏，浮世年華速。", "邂逅漢武時，蟠桃海東熟。"]'),
('2954cdd9-cfc5-42e9-92b8-7cb2415c795b','續古二十九首 九','陳陶','唐','唐诗','tang','','[]','南國珊瑚樹，好裁天馬鞭。',24,'全唐诗/poet.tang.41000.json','["南國珊瑚樹，好裁天馬鞭。", "魚龍不解語，海曲空嬋娟。"]'),
('c0616c55-b4a7-45f5-a73c-76e59fe5c4d7','續古二十九首 十','陳陶','唐','唐诗','tang','','["\u6cf0\u5c71"]','周穆恣遊幸，橫天驅八龍。',24,'全唐诗/poet.tang.41000.json','["周穆恣遊幸，橫天驅八龍。", "寧知泰山下，日日望登封。"]'),
('645dd081-d41b-432a-a627-45725c4d729f','續古二十九首 十一','陳陶','唐','唐诗','tang','','[]','秦國饒羅網，中原絕麟鳳。',24,'全唐诗/poet.tang.41000.json','["秦國饒羅網，中原絕麟鳳。", "萬乘巡海回，鮑魚空相送。"]'),
('426ea595-2b9d-4c26-809b-146610c5cfd7','續古二十九首 十二','陳陶','唐','唐诗','tang','','[]','秦家無廟略，遮虜續長城。',24,'全唐诗/poet.tang.41000.json','["秦家無廟略，遮虜續長城。", "萬姓隴頭死，中原荆棘生。"]'),
('d9dea70c-4fde-4b0d-a572-f6796f57be54','續古二十九首 十三','陳陶','唐','唐诗','tang','','[]','秦作東海橋，中州鬼辛苦。',24,'全唐诗/poet.tang.41000.json','["秦作東海橋，中州鬼辛苦。", "縱得跨蓬萊，羣仙亦飛去。"]'),
('15f30552-4756-465e-ae1f-af59e8806ee2','續古二十九首 十四','陳陶','唐','唐诗','tang','','[]','隋煬棄中國，龍舟巡海涯。',24,'全唐诗/poet.tang.41000.json','["隋煬棄中國，龍舟巡海涯。", "春風廣陵苑，不見秦宮花。"]'),
('7b253f96-c7c7-4e64-9fba-f19c81ad80c3','續古二十九首 十五','陳陶','唐','唐诗','tang','','[]','范子相句踐，滅吳成大勳。',24,'全唐诗/poet.tang.41000.json','["范子相句踐，滅吳成大勳。", "雖然五湖去，終媿磻溪雲。"]'),
('281304ee-bf77-4835-a772-ba2638d8d69c','續古二十九首 十六','陳陶','唐','唐诗','tang','','[]','麟鳳識翔蟄，聖賢明卷舒。',24,'全唐诗/poet.tang.41000.json','["麟鳳識翔蟄，聖賢明卷舒。", "哀哉嵇叔夜，智不及鶢鶋。"]'),
('98a2b495-c371-4c42-a225-e509ff278523','續古二十九首 十七','陳陶','唐','唐诗','tang','','[]','戰地三尺骨，將軍一身貴。',24,'全唐诗/poet.tang.41000.json','["戰地三尺骨，將軍一身貴。", "自古若弔冤，落花少於淚。"]'),
('77a5f5c4-3f13-4ce3-a183-eec1807e7e54','續古二十九首 十八','陳陶','唐','唐诗','tang','','[]','楚國千里旱，土龍日已多。',24,'全唐诗/poet.tang.41000.json','["楚國千里旱，土龍日已多。", "九穀竟枯死，好雲閑嵯峨。"]'),
('a83d732c-5483-4734-b9ca-7facba20ba77','續古二十九首 十九','陳陶','唐','唐诗','tang','','[]','漢家三殿色，恩澤若飄風。',24,'全唐诗/poet.tang.41000.json','["漢家三殿色，恩澤若飄風。", "今日黃金屋，明朝長信宮。"]'),
