('8e5d1996-d54d-4fcb-b51e-692fa820d440','水調詞十首 二','陳陶','唐','唐诗','tang','','[]','羽管慵調怨別離，西園新月伴愁眉。',32,'全唐诗/poet.tang.41000.json','["羽管慵調怨別離，西園新月伴愁眉。", "容華不分隨年去，獨有妝樓明鏡知。"]'),
('150cd2bb-38e1-4fc9-8765-8e827c91b2d4','水調詞十首 三','陳陶','唐','唐诗','tang','','[]','憶餞良人玉塞行，棃花三見換啼鶯。',32,'全唐诗/poet.tang.41000.json','["憶餞良人玉塞行，棃花三見換啼鶯。", "邊場豈得勝閨閣，莫逞琱弓過一生。"]'),
('a17933df-0000-4e1b-a251-b78a6a50abf3','水調詞十首 四','陳陶','唐','唐诗','tang','','[]','惆悵江南早鴈飛，年年辛苦寄寒衣。',32,'全唐诗/poet.tang.41000.json','["惆悵江南早鴈飛，年年辛苦寄寒衣。", "征人豈不思鄉國，只是皇恩未放歸。"]'),
('4de1daef-ff04-456d-a58b-da43312bc732','水調詞十首 五','陳陶','唐','唐诗','tang','','[]','水閣蓮開燕引雛，朝朝攀折望金吾。',32,'全唐诗/poet.tang.41000.json','["水閣蓮開燕引雛，朝朝攀折望金吾。", "聞道磧西春不到，花時還憶故園無。"]'),
('421de69e-52ea-4335-803a-3759b0820d2d','水調詞十首 六','陳陶','唐','唐诗','tang','','[]','自從清野戍遼東，舞袖香銷羅幌空。',32,'全唐诗/poet.tang.41000.json','["自從清野戍遼東，舞袖香銷羅幌空。", "幾度長安發梅柳，節旄零落不成功。"]'),
('0329df7f-c528-49dc-b4e9-bd43c0c7c0c5','水調詞十首 七','陳陶','唐','唐诗','tang','','[]','長夜孤眠倦錦衾，秦樓霜月苦邊心。',32,'全唐诗/poet.tang.41000.json','["長夜孤眠倦錦衾，秦樓霜月苦邊心。", "征衣一倍裝綿厚，猶慮交河雪凍深。"]'),
('43277fa3-544d-4234-99f2-2ffbcba58f7f','水調詞十首 八','陳陶','唐','唐诗','tang','','[]','瀚海長征古別離，華山歸馬是何時。',32,'全唐诗/poet.tang.41000.json','["瀚海長征古別離，華山歸馬是何時。", "仍聞萬乘尊猶屈，裝束千嬌嫁郅支。"]'),
('8570e2f3-f42b-4f4d-80dc-650465140ffd','水調詞十首 九','陳陶','唐','唐诗','tang','','[]','沙塞依稀落日邊，寒宵魂夢怯山川。',32,'全唐诗/poet.tang.41000.json','["沙塞依稀落日邊，寒宵魂夢怯山川。", "離居漸覺笙歌懶，君逐嫖姚已十年。"]'),
('f9cbb5b2-6cbf-4f5d-8cac-afe5dba70822','水調詞十首 十','陳陶','唐','唐诗','tang','','[]','萬里輪臺音信稀，傳聞移帳護金微。',32,'全唐诗/poet.tang.41000.json','["萬里輪臺音信稀，傳聞移帳護金微。", "會須麟閣留蹤跡，不斬天驕莫議歸。"]'),
('3c300c91-a5d4-46d4-9e9f-003cb400dabd','送謝山人歸江夏','陳陶','唐','唐诗','tang','','[]','黃鶴春風二千里，山人佳期碧江水。',32,'全唐诗/poet.tang.41000.json','["黃鶴春風二千里，山人佳期碧江水。", "攜琴一醉楊柳堤，日暮龍沙白雲起。"]'),
('eb79f715-948c-4287-a8c0-9d0b285e3b98','閑居雜興五首 一','陳陶','唐','唐诗','tang','','[]','虞韶九奏音猶在，只是巴童自棄遺。',32,'全唐诗/poet.tang.41000.json','["虞韶九奏音猶在，只是巴童自棄遺。", "閑臥清秋憶師曠，好風搖動古松枝。"]'),
('caee9b1e-6397-458f-93a8-3069581324c1','閑居雜興五首 二','陳陶','唐','唐诗','tang','','[]','一顧成周力有餘，白雲閑釣五溪魚。',32,'全唐诗/poet.tang.41000.json','["一顧成周力有餘，白雲閑釣五溪魚。", "中原莫道無麟鳳，自是皇家結網疎。"]'),
('45c7e6c8-287a-420c-904d-fef200fc159a','閑居雜興五首 三','陳陶','唐','唐诗','tang','','[]','長愛真人王子喬，五松山月伴吹簫。',32,'全唐诗/poet.tang.41000.json','["長愛真人王子喬，五松山月伴吹簫。", "從他浮世悲生死，獨駕蒼鱗入九霄。"]'),
('e4004a19-5622-4570-bd82-216ae67df6e4','閑居雜興五首 四','陳陶','唐','唐诗','tang','','[]','越里娃童錦作襦，豔歌聲壓郢中姝。',32,'全唐诗/poet.tang.41000.json','["越里娃童錦作襦，豔歌聲壓郢中姝。", "無人說向張京兆，一曲江南十斛珠。"]'),
('58c484bb-6592-4df4-91e1-42450ab1fc65','閑居雜興五首 五','陳陶','唐','唐诗','tang','','[]','雲堆西望賊連營，分閫何當舉義兵。',32,'全唐诗/poet.tang.41000.json','["雲堆西望賊連營，分閫何當舉義兵。", "莫道羔裘無壯節，古來成事盡書生。"]'),
('0aebbfd4-cff2-48fe-8d1c-8ceaaddae5b9','泉州刺桐花詠兼呈趙使君 一','陳陶','唐','唐诗','tang','','[]','髣髴三株植世間，風光滿地赤城閑。',32,'全唐诗/poet.tang.41000.json','["髣髴三株植世間，風光滿地赤城閑。", "無因秉燭看奇樹，長伴劉公醉玉山。"]'),
('1b30e1b3-7424-4c07-a036-8f01074a80a5','泉州刺桐花詠兼呈趙使君 二','陳陶','唐','唐诗','tang','','[]','海曲春深滿郡霞，越人多種刺桐花。',32,'全唐诗/poet.tang.41000.json','["海曲春深滿郡霞，越人多種刺桐花。", "可憐虎竹西樓色，錦帳三千阿母家。"]'),
('07bc9d85-5fd4-419e-a716-ee6e48fc0aa6','泉州刺桐花詠兼呈趙使君 三','陳陶','唐','唐诗','tang','','[]','石氏金園無此豔，南都舊賦乏靈材。',32,'全唐诗/poet.tang.41000.json','["石氏金園無此豔，南都舊賦乏靈材。", "只因赤帝宮中樹，丹鳳新銜出世來。"]'),
('ea8c55bb-8c45-44f5-b3de-0e91c79921bd','泉州刺桐花詠兼呈趙使君 四','陳陶','唐','唐诗','tang','','[]','猗猗小豔夾通衢，晴日熏風笑越姝。',32,'全唐诗/poet.tang.41000.json','["猗猗小豔夾通衢，晴日熏風笑越姝。", "只是紅芳移不得，刺桐屏幛滿中都。"]'),
('69ad96df-3617-41e7-abf2-d40d59178208','泉州刺桐花詠兼呈趙使君 五','陳陶','唐','唐诗','tang','','[]','不勝攀折悵年華，紅樹南看見海涯。',32,'全唐诗/poet.tang.41000.json','["不勝攀折悵年華，紅樹南看見海涯。", "故國春風歸去盡，何人堪寄一枝花。"]'),
('06905273-6acf-47e0-b981-b79cbc74375d','泉州刺桐花詠兼呈趙使君 六','陳陶','唐','唐诗','tang','','[]','赤帝常聞海上遊，三千幢蓋擁炎州。',32,'全唐诗/poet.tang.41000.json','["赤帝常聞海上遊，三千幢蓋擁炎州。", "今來樹似離宮色，紅翠斜欹十二樓。"]'),
('d6a4e3c6-191f-4b0c-bc70-b759cec9b899','投贈福建桂常侍二首 一','陳陶','唐','唐诗','tang','','[]','後來台席更何人，都護朝天拜近臣。',32,'全唐诗/poet.tang.41000.json','["後來台席更何人，都護朝天拜近臣。", "長笑當時漢卿士，等閑恩澤畫麒麟。"]'),
('0d1507c5-38f2-4197-a267-450bc7fbc3ee','投贈福建桂常侍二首 二','陳陶','唐','唐诗','tang','','[]','匝地歌鐘鎮海隅，城池鞅掌舊名都。',32,'全唐诗/poet.tang.41000.json','["匝地歌鐘鎮海隅，城池鞅掌舊名都。", "不知珠履三千外，更許侯嬴寄食無。"]'),
('2bd6333b-4da3-4c12-ac0e-e8496e3ce941','隴西行四首 一','陳陶','唐','唐诗','tang','','[]','漢主東封報太平，無人金闕議邊兵。',32,'全唐诗/poet.tang.41000.json','["漢主東封報太平，無人金闕議邊兵。", "縱饒奪得林胡塞，磧地桑麻種不生。"]'),
('fde30eaa-9b2c-47ce-ba49-c1356353ac9a','隴西行四首 二','陳陶','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u6218\u4e89", "\u5987\u5973", "\u8fb9\u585e", "\u4e03\u8a00\u7edd\u53e5"]','誓掃匈奴不顧身，五千貂錦喪胡塵。',32,'全唐诗/poet.tang.41000.json','["誓掃匈奴不顧身，五千貂錦喪胡塵。", "可憐無定河邊骨，猶是春閨夢裏人。"]'),
('47a6add6-70a4-48bd-be0c-cef3c025b291','隴西行四首 三','陳陶','唐','唐诗','tang','','[]','隴戍三看塞草青，樓煩新替護羌兵。',32,'全唐诗/poet.tang.41000.json','["隴戍三看塞草青，樓煩新替護羌兵。", "同來死者傷離別，一夜孤魂哭舊營。"]'),
('6c37f2a0-d347-4267-abaf-2a5d610f9f9e','隴西行四首 四','陳陶','唐','唐诗','tang','','[]','黠虜生擒未有涯，黑山營陣識龍蛇。',32,'全唐诗/poet.tang.41000.json','["黠虜生擒未有涯，黑山營陣識龍蛇。", "自從貴主和親後，一半胡風似漢家。"]'),
('33f4e294-e059-4970-b148-ca3f8b6d6061','荅蓮花妓','陳陶','唐','唐诗','tang','','[]','近來詩思清於水，老去風情薄似雲。',32,'全唐诗/poet.tang.41000.json','["近來詩思清於水，老去風情薄似雲。", "已向昇天得門戶，錦衾深愧卓文君。"]'),
('0d5b8455-3306-40d6-8161-3dd415642daa','鏡道中吹簫','陳陶','唐','唐诗','tang','','[]','金欄白的善篸𥰭，雙鳳夜伴江南棲。',32,'全唐诗/poet.tang.41000.json','["金欄白的善篸𥰭，雙鳳夜伴江南棲。", "十洲人聽玉樓曉，空向千山桃杏枝。"]'),
('4728edda-ba59-4e42-ba55-f9ab9d51fa15','贈野老','陳陶','唐','唐诗','tang','','[]','何年種芝白雲裏，人傳先生老萊子。',32,'全唐诗/poet.tang.41000.json','["何年種芝白雲裏，人傳先生老萊子。", "消磨世上名利心，澹若巖間一流水。"]'),
('ab5d9b00-4c62-412c-a07e-6e0ddb741c9d','酬元亨上人','陳陶','唐','唐诗','tang','','[]','一衲淨居雲夢合，秋來詩思祝融高。',32,'全唐诗/poet.tang.41000.json','["一衲淨居雲夢合，秋來詩思祝融高。", "何因知我津涯闊，遠寄東溟六巨鼇。"]'),
('f9295c20-e37c-4167-b2b9-d522b44f799c','題徐穉湖亭','陳陶','唐','唐诗','tang','','[]','伏龍山橫洲渚地，人如白蘋自生死。',32,'全唐诗/poet.tang.41000.json','["伏龍山橫洲渚地，人如白蘋自生死。", "洪崖成道二千年，唯有徐君播青史。"]'),
('8831f675-bb4e-4181-ba52-cfa5f0fa39c4','鄱陽秋夕','陳陶','唐','唐诗','tang','','[]','憶昔鄱陽旅遊日，曾聽南家爭擣衣。',32,'全唐诗/poet.tang.41000.json','["憶昔鄱陽旅遊日，曾聽南家爭擣衣。", "今夜重開舊砧杵，當時還見鴈南飛。"]'),
('c219ff22-9a89-487c-bf10-7c2ecf7695f6','飛龍引','陳陶','唐','唐诗','tang','','[]','長洲茂苑朝夕池，映日含風結細漪。',64,'全唐诗/poet.tang.41000.json','["長洲茂苑朝夕池，映日含風結細漪。", "坐當伏檻紅蓮披，雕軒洞戶青蘋吹。", "輕幌芳煙鬱金馥，綺簷花簟桃李枝。", "苕苕翡翠但相逐，桂樹鴛鴦恆並宿。"]'),
('7a73950b-e10d-4f0e-a6d2-e8b2a560e746','句','陳陶','唐','唐诗','tang','','[]','蟬聲將月短，草色與秋長。',124,'全唐诗/poet.tang.41000.json','["蟬聲將月短，草色與秋長。", "比屋歌黃竹，何人撼白榆。", "好看如鏡夜，莫笑似弓時。", "江湖水清淺，不足掉鯨尾。", "飲水狼子瘦，思日鷓鴣寒。", "一鼎雄雌金液火，十年寒暑鹿麑裘。", "寄語東流任斑鬢，向隅終守鐵梭飛。", "乾坤見了文章懶，龍虎成來印綬疎。", "近來世上無徐庶，誰向桑麻識臥龍。"]'),
('2d9d6022-cc59-4c99-a140-9718a3564111','春日作','李中','唐','唐诗','tang','','[]','和氣來無象，物情還暗新。',48,'全唐诗/poet.tang.41000.json','["和氣來無象，物情還暗新。", "乾坤一夕雨，草木萬方春。", "染水煙光媚，催花鳥語頻。", "高臺曠望處，歌詠屬詩人。"]'),
('5f122a99-c36f-482c-b858-736b0b379986','寒江暮泊寄左偃','李中','唐','唐诗','tang','','[]','維舟蘆荻岸，離恨若爲寬。',48,'全唐诗/poet.tang.41000.json','["維舟蘆荻岸，離恨若爲寬。", "煙火人家遠，汀洲暮雨寒。", "天涯孤夢去，篷底一燈殘。", "不是憑騷雅，相思寫亦難。"]'),
('b221764c-043a-4751-be60-edc77edcb54a','喜春雨有寄','李中','唐','唐诗','tang','','[]','青春終日雨，公子莫思晴。',48,'全唐诗/poet.tang.41000.json','["青春終日雨，公子莫思晴。", "任阻西園會，且觀南畝耕。", "最憐滋壠麥，不恨濕林鶯。", "父老應相賀，豐年兆已成。"]'),
('4ccd7362-c8c9-42bb-9cda-f245b7889f9d','魏夫人壇','李中','唐','唐诗','tang','','[]','仙壇遺跡在，苔合落花明。',48,'全唐诗/poet.tang.41000.json','["仙壇遺跡在，苔合落花明。", "絳節何年返，白雲終日生。", "旋新芳草色，依舊偃松聲。", "欲問希夷事，音塵隔上清。"]'),
('a4415254-a2b8-4414-80da-61128681f056','訪洞神宮邵道者不遇','李中','唐','唐诗','tang','','[]','閑來仙觀問希夷，雲滿星壇水滿池。',32,'全唐诗/poet.tang.41000.json','["閑來仙觀問希夷，雲滿星壇水滿池。", "羽客不知何處去，洞前花落立多時。"]'),
('8a390e28-35a6-488a-9106-1ec0943f2f49','寄贈致仕沈彬郎中','李中','唐','唐诗','tang','','[]','鶴氅換朝服，逍遙雲水鄉。',48,'全唐诗/poet.tang.41000.json','["鶴氅換朝服，逍遙雲水鄉。", "有時乘一葉，載酒入三湘。", "塵夢年來息，詩魔老亦狂。", "蓴羮與鱸鱠，秋興最宜長。"]'),
('b5ede339-e728-4295-9601-0eb9133afabd','贈別','李中','唐','唐诗','tang','','[]','行杯酌罷歌聲歇，不覺前汀月又生。',32,'全唐诗/poet.tang.41000.json','["行杯酌罷歌聲歇，不覺前汀月又生。", "自是離人魂易斷，落花芳草本無情。"]'),
('326951cb-3876-48e1-9c58-fca644dbd242','送劉恭遊廬山兼寄令上人','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','松桂煙霞蔽梵宮，詩流閑去訪支公。',32,'全唐诗/poet.tang.41000.json','["松桂煙霞蔽梵宮，詩流閑去訪支公。", "石堂磬斷相逢夜，五老月生谿影空。"]'),
('8e0909ff-7722-4fee-a06b-6f22a0737b10','宿廬山白雲峰重道者院','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','絕頂松堂喜暫遊，一宵玄論接浮丘。',64,'全唐诗/poet.tang.41000.json','["絕頂松堂喜暫遊，一宵玄論接浮丘。", "雲開碧落星河近，月出滄溟世界秋。", "塵裏年光何急急，夢中強弱自悠悠。", "他時書劒酬恩了，願逐鸞車看十洲。"]'),
('57201b7e-a19b-4000-b0ce-35caf1a24e36','海上從事秋日書懷','李中','唐','唐诗','tang','','[]','悠悠旅宦役塵埃，舊業那堪信未迴。',64,'全唐诗/poet.tang.41000.json','["悠悠旅宦役塵埃，舊業那堪信未迴。", "千里夢隨殘月斷，一聲蟬送早秋來。", "壺傾濁酒終難醉，匣鎖青萍久不開。", "唯有搜吟遣懷抱，涼風時復上高臺。"]'),
('d3f71391-62a3-4109-838a-1a2929903cfd','訪蔡文慶處士留題','李中','唐','唐诗','tang','','[]','幽人棲息處，一到滌塵心。',48,'全唐诗/poet.tang.41000.json','["幽人棲息處，一到滌塵心。", "蘚色花陰闊，棊聲竹徑深。", "籬根眠野鹿，池面戲江禽。", "多謝相留宿，開樽拂素琴。"]'),
('66ca0b05-ec92-4d99-b55e-eec235cfa8c2','寄廬岳鑒上人','李中','唐','唐诗','tang','','[]','岳寺棲缾錫，常人親亦難。',48,'全唐诗/poet.tang.41000.json','["岳寺棲缾錫，常人親亦難。", "病披青衲重，晚剃白髭寒。", "烘壁茶煙暗，填溝木葉乾。", "昔年皆禮謁，頻到碧雲端。"]');
